#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> result_x(n);
        std::vector<int> result_y(n);

        for (int i = 0; i < n; ++i) {
            result_x[a[i].original_index] = a[i].value;
            result_y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << result_x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << result_y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_operations = 0;
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Cannot copy a pile to itself
        }
        // For each other pile a[i], we can add min_val to it as many times as possible
        // without exceeding k.
        // The number of times min_val can be added to a[i] is (k - a[i]) / min_val.
        // Integer division naturally handles this.
        total_operations += (k - a[i]) / min_val;
    }

    std::cout << total_operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

