int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use 5s
        ans += diff / 5;
        diff %= 5;

        // Use 2s and 1s for the remaining diff (0, 1, 2, 3, 4)
        // If diff is 0, 1, 2, 3, 4:
        // 0 -> 0 presses
        // 1 -> 1 press (+1 or -1)
        // 2 -> 1 press (+2 or -2)
        // 3 -> 2 presses (+2, +1 or -2, -1)
        // 4 -> 2 presses (+2, +2 or -2, -2)

        if (diff == 1 || diff == 2) {
            ans += 1;
        } else if (diff == 3 || diff == 4) {
            ans += 2;
        }
        // If diff is 0, ans remains unchanged.

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // The simplest way to find a different permutation with the same fingerprint
    // is to reverse the given permutation.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // If p' = [p_n, p_{n-1}, ..., p_1], then
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // This set of sums is identical to the set of sums for p, just in reverse order.
    // Therefore, F(p') will be equal to F(p).
    //
    // We need p' to be different from p.
    // A permutation p is equal to its reverse p' if and only if p is a palindrome.
    // For example, [1,2,1] is not a permutation. [1,2,3,2,1] is not a permutation.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // For n >= 2, if p is a permutation, it cannot be a palindrome.
    // Proof: If p is a palindrome, then p_i = p_{n-i+1}.
    // If n is odd, say n=2k+1, then p_{k+1} = p_{n-(k+1)+1} = p_{2k+1-k-1+1} = p_{k+1}. This element is unique.
    // For all other i != k+1, p_i = p_{n-i+1}.
    // If p_i = p_{n-i+1} for all i, and all elements are distinct, then this implies that
    // the set of elements {p_1, ..., p_k} must be distinct from {p_{n-k+1}, ..., p_n}
    // and also p_i must be distinct from p_j for i,j in {1, ..., k}.
    // This is only possible if n=1.
    // For n >= 2, a permutation cannot be a palindrome.
    // Example: n=2, p=[1,2]. p_rev=[2,1]. Different.
    // Example: n=3, p=[1,2,3]. p_rev=[3,2,1]. Different.
    // Example: n=4, p=[1,2,3,4]. p_rev=[4,3,2,1]. Different.
    //
    // Thus, reversing any permutation p of length n >= 2 will always yield a different permutation p'
    // with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

