void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n > 1, we can construct a number that satisfies the conditions.
        // The strategy is to use '2' as the first digit and '3' for the rest (n-1 digits).
        // This number will be 233...3 (n-1 times '3').
        // Let's check divisibility:
        // 1. Not divisible by 2: The number ends in 3, so it's odd.
        // 2. Not divisible by 3: The sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    Since 3n - 1 is not divisible by 3 (it leaves a remainder of 2 when divided by 3),
        //    the number itself is not divisible by 3.
        // 3. No digit is 0. All digits are 2 or 3.
        // 4. s > 0 and has n digits. This is satisfied.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

