#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);
    int color_for_half_T = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Using floating point for comparison with T/2.0 is safe here because T/2.0 is exact for integers.
                              // Alternatively, a[i] * 2 < T for integer comparison.
            p[i] = 0; // White
        } else if (a[i] > T / 2.0) { // a[i] * 2 > T
            p[i] = 1; // Black
        } else { // a[i] == T / 2.0, i.e., a[i] * 2 == T
            // These elements must be split.
            // Assign them alternating colors.
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Flip color for the next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

