}

#include <iostream>
#include <vector>
#include <algorithm> // For std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            int val;
            std::cin >> val;
            if (i != j) { // Only consider a_i,j where i != j
                max_val_for_i = std::max(max_val_for_i, val);
            }
        }
        // If max_val_for_i is n-1, then p[i] must be n.
        // Otherwise, p[i] must be max_val_for_i.
        // This logic is derived from the problem constraints and properties.
        // Specifically, if p[i] = n, then min(p[i], p[j]) = p[j] for all j != i.
        // The maximum of these p[j] values (for j != i) would be n-1.
        // If p[i] < n, then there must be some p[k] > p[i].
        // For such p[k], min(p[i], p[k]) = p[i].
        // For any p[j] < p[i], min(p[i], p[j]) = p[j].
        // So, max_{j != i} min(p[i], p[j]) will be p[i].
        // The only exception is if p[i] is n, in which case the max is n-1.
        // So, if max_val_for_i == n-1, p[i] = n.
        // Otherwise, p[i] = max_val_for_i.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases
    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Handle edge case for n=0, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last element, as it's the minimum in the suffix ending at n-1
        int min_suffix = a[n - 1]; 

        // Iterate from the second to last element backwards
        // For each element a[i], we compare it with the minimum price found so far in the suffix a[i+1...n-1]
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                bad_prices_count++; // If a[i] is greater than min_suffix, it's a bad price
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is either
                // equal to or smaller than min_suffix. In this case, a[i] becomes
                // the new minimum for the suffix a[i...n-1].
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize |median1 - median2|.
        // After sorting the entire array, the optimal strategy is to
        // assign the first n elements to one class and the next n elements
        // to the other class.
        // The first class will consist of elements a[0], ..., a[n-1].
        // The second class will consist of elements a[n], ..., a[2n-1].
        // Both classes will have n elements.
        // If n is odd, then both classes have odd sizes, and their medians
        // are a[n/2] and a[n + n/2] respectively.
        // If n is even, then both classes have even sizes, which is not allowed.
        //
        // However, the problem statement implies that we can choose any odd sizes
        // S1 and S2 such that S1 + S2 = 2n.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // If we pick the elements a_{n-1} and a_n as the medians of the two classes,
        // we can always construct such a partition.
        //
        // To make a_{n-1} the median of the first class:
        // We need to pick an odd number of elements for this class, say 2k+1.
        // a_{n-1} must be the k-th element (0-indexed) in its sorted class.
        // This means we need k elements smaller than or equal to a_{n-1}
        // and k elements greater than or equal to a_{n-1}.
        // We can pick a_0, ..., a_{n-1-k} for the smaller elements,
        // and a_{n-1}, ..., a_{n-1+k} for the larger elements.
        //
        // The key insight for this type of problem is that if you sort the entire array,
        // the optimal medians will be adjacent elements in the sorted array.
        // Specifically, for $2n$ students, the two medians will be $a_{n-1}$ and $a_n$
        // from the globally sorted array.
        //
        // Let's prove this. Suppose we have two classes $C_1$ and $C_2$ with medians $m_1$ and $m_2$.
        // Let $m_1 = a_i$ and $m_2 = a_j$ for some $i, j$ in the globally sorted array.
        // Without loss of generality, assume $m_1 \le m_2$.
        // To make $a_i$ the median of $C_1$, $C_1$ must contain $a_i$, and an equal number of elements
        // smaller than or equal to $a_i$ and greater than or equal to $a_i$.
        // Similarly for $a_j$ and $C_2$.
        //
        // The total number of elements is $2n$.
        // The elements $a_0, \dots, a_{n-1}$ are the "lower half" and $a_n, \dots, a_{2n-1}$ are the "upper half".
        //
        // If we choose $a_{n-1}$ and $a_n$ as the medians, we can form two classes:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. Its median is $a_{n-1}$ if $n$ is odd.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. Its median is $a_n$ if $n$ is odd.
        // If $n$ is odd, this is a valid partition and the difference is $a_n - a_{n-1}$.
        //
        // What if $n$ is even? Then $n$ elements is an even number.
        // We need odd-sized classes.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$. $S_1+S_2 = 2n$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can always make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        // For example, form Class 1 with $a_0, \dots, a_{n-1}, \dots, a_{n-1+k_1}$
        // and Class 2 with $a_{n-1+k_1+1}, \dots, a_n, \dots, a_{2n-1}$.
        // This is not quite right.
        //
        // The crucial observation is that to minimize $|m_1 - m_2|$, we want $m_1$ and $m_2$ to be as close as possible.
        // If we sort the entire array $a_0, \dots, a_{2n-1}$, then the smallest possible difference between any two medians
        // will be achieved when these medians are $a_{n-1}$ and $a_n$.
        //
        // To make $a_{n-1}$ the median of a class $C_1$:
        // We need to pick $k$ elements from $a_0, \dots, a_{n-2}$ and $k$ elements from $a_n, \dots, a_{2n-1}$.
        // The total size of $C_1$ would be $2k+1$.
        // We can pick $k$ elements from $a_0, \dots, a_{n-2}$ (e.g., $a_0, \dots, a_{k-1}$)
        // and $k$ elements from $a_n, \dots, a_{2n-1}$ (e.g., $a_n, \dots, a_{n+k-1}$).
        // This forms a class $C_1 = \{a_0, \dots, a_{k-1}, a_{n-1}, a_n, \dots, a_{n+k-1}\}$.
        // The remaining elements are $a_k, \dots, a_{n-2}$ and $a_{n+k}, \dots, a_{2n-1}$.
        // This is not a simple construction.
        //
        // The simplest construction that always works and yields $a_n - a_{n-1}$ is:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. (size $n$)
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. (size $n$)
        // If $n$ is odd, this is a valid partition. The medians are $a_{(n-1)/2}$ and $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // Let's re-read the problem carefully. "each class has odd number of students".
        // The example for $n=3$ (total $2n=6$ students): $[6, 5, 4, 1, 2, 3]$. Sorted: $[1, 2, 3, 4, 5, 6]$.
        // $n=3$. $a_{n-1} = a_2 = 3$, $a_n = a_3 = 4$. Difference is $4-3=1$.
        // The example output is 1.
