#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_idx = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_idx is -1, it means the frog is at cell 0.
                             // If last_R_idx is i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The distance from the previous 'R' (or 0) to the current 'R' is (i - last_R_idx).
                // This is the maximum jump needed to cover the segment of 'L's between them.
                max_dist = std::max(max_dist, i - last_R_idx);
                last_R_idx = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or 0 if no 'R's) to the target cell n+1.
        // The distance is (n + 1 - last_R_idx).
        max_dist = std::max(max_dist, n + 1 - last_R_idx);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The total number of coders available: k <= c
        // 2. The total number of mathematicians available: k <= m
        // 3. The total number of students available: 3 * k <= c + m + x
        //    which implies k <= (c + m + x) / 3

        // So, k must be less than or equal to the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});

        std::cout << ans << "\n";
    }
    return 0;
}

