int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long k = 1;            // Represents the 'n' in 2^n - 1 for the cost formula
                                    // For k=1, n=1, cost = 2^1-1 = 1
                                    // For k=2, n=3, cost = 2^2-1 = 3
                                    // For k=3, n=7, cost = 2^3-1 = 7
                                    // The cost for a staircase with (2^k - 1) stairs is (2^k - 1) * (2^k) / 2
                                    // This is actually (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^(k-1)
                                    // No, the cost is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^(k-1)
                                    // Let's re-derive the cost for a staircase with N stairs.
                                    // N = 2^k - 1.
                                    // Cost = N * (N+1) / 2 = (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
                                    // Let's check:
                                    // k=1: N=1. Cost = (2^1-1)*2^0 = 1*1 = 1.
                                    // k=2: N=3. Cost = (2^2-1)*2^1 = 3*2 = 6.
                                    // k=3: N=7. Cost = (2^3-1)*2^2 = 7*4 = 28.
                                    // The problem statement says the cost for a staircase with N stairs is N*(N+1)/2.
                                    // The example for 7 stairs shows 28 cells.
                                    // The example for 3 stairs shows 6 cells.
                                    // The example for 1 stair shows 1 cell.
                                    // These are the costs for nice staircases.
                                    // The sequence of costs for nice staircases is:
                                    // N=1: cost = 1*(1+1)/2 = 1
                                    // N=3: cost = 3*(3+1)/2 = 6
                                    // N=7: cost = 7*(7+1)/2 = 28
                                    // N=15: cost = 15*(15+1)/2 = 15*8 = 120
                                    // N=2^k-1: cost = (2^k-1)*(2^k)/2 = (2^k-1)*2^(k-1)
                                    // This is the sequence of costs we need to use.
                                    // Let's use `n_stairs` for N and `cost_val` for the cost.
        long long n_stairs = 1;
        long long cost_val = 1;

        while (x >= cost_val) {
            x -= cost_val;
            count++;

            // Calculate next n_stairs and next cost_val
            // n_stairs for the next nice staircase is 2 * current_n_stairs + 1
            n_stairs = 2 * n_stairs + 1;
            // cost_val for the next nice staircase is n_stairs * (n_stairs + 1) / 2
            // This can also be derived from the previous cost_val:
            // If current cost_val = (2^k-1)*2^(k-1)
            // Next cost_val = (2^(k+1)-1)*2^k
            // This is (2 * (2^k-1) + 1) * 2^k / 2
            // This is (2 * current_n_stairs + 1) * (current_n_stairs + 1)
            // No, this is not right.
            // The formula is (2^k-1) * 2^(k-1).
            // If k increases by 1, the new cost is (2^(k+1)-1) * 2^k.
            // This is (2 * (2^k-1) + 1) * 2 * 2^(k-1)
            // This is (2 * current_n_stairs + 1) * 2 * (current_cost_val / current_n_stairs)
            // This is (2 * current_n_stairs + 1) * (current_n_stairs + 1)
            // Let's just use the direct formula: n_stairs * (n_stairs + 1) / 2
            cost_val = n_stairs * (n_stairs + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == target_open && close_count == target_close) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

