#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // The sequence will be: left, right, left+1, right-1, left+2, right-2, ...
    // For example, if k=4, left=1, right=5:
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1. These are 4 distinct differences.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left++;
        } else { // Odd index, take from right
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k+1 numbers, we have used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // To avoid introducing new distinct differences, we can append these remaining numbers
    // in increasing order. This will only introduce a difference of 1.
    // Since we already generated 1 as a difference (from the alternating part, e.g., |4-3|=1 in the example above),
    // this will not add any new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix
    int j = i; // Start searching from `i`
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" array.
    // The prefix to remove has length `j`.

    std::cout << j << std::endl;
}

