    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) { // Should not happen based on constraints 1 <= m
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of pages divisible by m

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of multiples of m repeat with a cycle of length 10.
        // For example, for m=3: 3, 6, 9, 2, 5, 8, 1, 4, 7, 0, then 3, 6, ...
        // The sum of last digits for one full cycle (10 multiples)
        // is (1*m)%10 + (2*m)%10 + ... + (10*m)%10.

        std::vector<long long> cycle_last_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_last_digits[i - 1];
        }

        long long num_full_cycles = count / 10;
        long long remaining_multiples = count % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');
    ans[0] = '1'; // m=1 is always beautiful (subsegment [1])

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // For m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update the range [current_min_idx, current_max_idx] to include 'm'
        // 'm' must be at pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // contains all numbers from 1 to m and has length m.
        // The length of the current range is (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then all numbers from 1 to m must be present
        // and no other numbers (greater than m) can be present in this range.
        // This is because we are expanding the range to include 1, 2, ..., m one by one.
        // If the length is m, it means the elements 1, ..., m occupy exactly m positions
        // without any gaps or extra elements.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

