int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        double discriminant = d * d - 4 * d;

        if (discriminant < 0) {
            std::cout << "N\n";
        } else {
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 0, and sqrt_discriminant >= 0,
            // a1 = (d + sqrt_discriminant) / 2.0 will always be >= 0.
            // We only need to check b1.
            // b1 = (d - sqrt_discriminant) / 2.0
            // For b1 to be non-negative, d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (since both are non-negative): d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, if discriminant >= 0, then both a1 and b1 will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For odd n, this is the 0-indexed middle element

    // 1. Make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // These are elements a[0] to a[mid_idx-1]
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These are elements a[mid_idx+1] to a[n-1]
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Final toy in Box 1 (value <= -1)
    // This requires an odd number of negative factors, and the magnitude must be >= 1.
    // Negative factors come from Box 1 and Box 2.
    // Let N_neg be the count of toys from Box 1 and Box 2.
    // Let N_mag_gt1 be the count of toys from Box 1 and Box 4.
    // If N_neg is odd, the sign is negative.
    // If N_mag_gt1 >= 1, it's possible to get magnitude >= 1.
    // If N_mag_gt1 == 0, then all toys are from Box 2 and Box 3.
    //    If all toys are from Box 2 and Box 3, the product will be in (-1, 1).
    //    So, if N_mag_gt1 == 0, Box 1 is impossible.

    // To get a negative result, we need an odd number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is odd:
    //   If A + D >= 1 (at least one toy with magnitude >= 1), then it's possible to get a value <= -1.
    //   Example: (-2) * (0.5) = -1. (-2) * (0.6) = -1.2.
    //   If A + D == 0, then all toys are from B and C.
    //     If B is odd, the product is negative.
    //     But all toys are in (-1, 1), so the product will be in (-1, 1).
    //     So, if A+D == 0, Box 1 is impossible.
    //   Thus, if (A + B) % 2 == 1 and (A + D >= 1), Box 1 is possible.

    // What if A+B is even?
    // We can make it odd by pairing up two negative numbers to make a positive one,
    // or pairing a negative and a positive to make a negative.
    // The key is that we can control the parity of negative numbers.
    // Each multiplication reduces the total number of toys by 1.
    // The parity of negative numbers changes if we multiply a negative by a positive.
    // The parity of negative numbers stays the same if we multiply two negatives (result positive)
    // or two positives (result positive).
    // This means the final sign depends on the parity of the initial count of negative numbers (A+B).
    // If (A+B) is odd, the final product is negative.
    // If (A+B) is even, the final product is positive.

    // So, for Box 1 (negative): (A + B) must be odd.
    // For Box 2 (negative): (A + B) must be odd.
    // For Box 3 (positive): (A + B) must be even.
    // For Box 4 (positive): (A + B) must be even.

    // Let's re-evaluate the conditions for each box.

    // Box 1: $(-\infty, -1]$
    // 1. Final sign must be negative: (A + B) must be odd.
    // 2. Final magnitude must be >= 1.
    //    This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4).
    //    So, A + D >= 1.
    //    If A + D == 0, all toys are from Box 2 and Box 3. Their product will always be in (-1, 1).
    //    So, if (A + B) % 2 == 1 and (A + D >= 1), Box 1 is possible.
    if ((a + b) % 2 == 1 && (a + d >= 1)) {
        ans1 = "Ya";
    }

    // Box 2: $(-1, 0)$
    // 1. Final sign must be negative: (A + B) must be odd.
    // 2. Final magnitude must be < 1.
    //    This is always possible if there's at least one toy from Box 2 or Box 3 (B+C >= 1).
    //    If A+D >= 1, we can pick a toy from Box 1 or Box 4, and a toy from Box 2 or Box 3,
    //    e.g., (-2) * (0.1) = -0.2 (Box 2).
    //    If A+D == 0, then all toys are from Box 2 and Box 3.
    //    If (A+B) is odd, and all toys are from B and C, the product will be negative and in (-1, 1).
    //    So, if (A + B) % 2 == 1, Box 2 is possible.
    //    The only edge case is if A+B is odd, but A+D >= 1, and we are forced to make a magnitude >= 1.
    //    But we can always choose values such that the magnitude is < 1.
    //    Example: A=1, B=0, C=0, D=1. Toys: {-2, 3}. Product -6 (Box 1).
    //    But we can choose {-2, 0.1} and {3, 0.1}.
    //    The problem states "you only know the number of toys... do not know their fun values".
    //    This means we can pick specific fun values within the ranges.
    //    If (A+B) is odd, we can always make the final product negative.
    //    To make it in (-1, 0), we need to ensure the magnitude is < 1.
    //    If A+D >= 1, we can pick a toy from Box 1 or Box 4, say $X$.
    //    We can pick a toy from Box 2 or Box 3, say $Y$.
    //    We can choose $Y$ to be very close to 0, e.g., $0.001$. Then $X \cdot Y$ will be close to 0.
    //    So, if (A + B) % 2 == 1, Box 2 is possible.
    if ((a + b) % 2 == 1) {
        ans2 = "Ya";
    }

    // Box 3: $(0, 1)$
    // 1. Final sign must be positive: (A + B) must be even.
    // 2. Final magnitude must be < 1.
    //    Similar to Box 2, if (A+B) is even, we can always make the final product positive.
    //    To make it in (0, 1), we need to ensure the magnitude is < 1.
    //    If A+D >= 1, we can pick a toy from Box 1 or Box 4, say $X$.
    //    We can pick a toy from Box 2 or Box 3, say $Y$.
    //    We can choose $Y$ to be very close to 0, e.g., $0.001$. Then $X \cdot Y$ will be close to 0.
    //    So, if (A + B) % 2 == 0, Box 3 is possible.
    if ((a + b) % 2 == 0) {
        ans3 = "Ya";
    }

    // Box 4: $[1, \infty)$
    // 1. Final sign must be positive: (A + B) must be even.
    // 2. Final magnitude must be >= 1.
    //    This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4).
    //    So, A + D >= 1.
    //    If A + D == 0, all toys are from Box 2 and Box 3. Their product will always be in (-1, 1).
    //    So, if (A + B) % 2 == 0 and (A + D >= 1), Box 4 is possible.
    if ((a + b) % 2 == 0 && (a + d >= 1)) {
        ans4 = "Ya";
    }

    // Special case: total_toys == 1
    // If there's only one toy, it is the super toy.
    // Its box is the special box.
    if (total_toys == 1) {
        ans1 = "Tidak"; ans2 = "Tidak"; ans3 = "Tidak"; ans4 = "Tidak";
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the "larger" elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (the "smaller" elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i]
        // To maximize the count, we should use the smallest possible a[j] that satisfies the condition
        // and is not yet used.
        // The two-pointer approach naturally handles this:
        // 'i' iterates through the sorted original array (representing the values at original positions).
        // 'j' iterates through the sorted array (representing the values we can place).
        // If a[j] > a[i], we found a match: a[j] can be placed at position 'i'.
        // We increment both 'i' and 'j' and count this as a successful placement.
        // If a[j] <= a[i], then a[j] cannot be placed at position 'i' to satisfy the condition.
        // We need a larger element for position 'i', so we try the next available element by incrementing 'j'.
        // 'i' stays put, waiting for a suitable 'j'.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element for placement
        } else {
            // If j reaches n, it means all remaining elements in 'a' are <= a[i]
            // or have already been used. No more matches possible for current or subsequent 'i'.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // Assign A_i' to B_i based on sorted order
    // The i-th smallest A value should be paired with the i-th largest B value
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max_val_prefix will handle a[i] > i+1
            distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_prefix && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i; // Length of suffix a[i...n-1]
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max_val_suffix will handle a[i] > current_len
            distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_suffix && max_val_suffix == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char move : s) {
            if (move == 'R') {
                countR++;
            } else if (move == 'S') {
                countS++;
            } else if (move == 'P') {
                countP++;
            }
        }

        char dominant_bot_move;
        if (countR >= countS && countR >= countP) {
            dominant_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            dominant_bot_move = 'S';
        } else {
            dominant_bot_move = 'P';
        }

        char my_winning_move = get_winning_move(dominant_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << my_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (chanek_turn) {
                if (N % 2 == 1) { // N is odd
                    chanek_coins += 1;
                    N -= 1;
                } else { // N is even
                    if (N == 2) { // Special case for N=2, taking 1 is optimal
                        chanek_coins += 1;
                        N -= 1;
                    } else if ((N / 2) % 2 == 1) { // N/2 is odd
                        // If N/2 is odd, taking N/2 leaves an odd number of coins for opponent.
                        // Opponent will take 1, leaving an even number for Chanek.
                        // Taking 1 leaves an odd number for opponent.
                        // Example: N=6. N/2=3 (odd).
                        //   Chanek takes 3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        //   Chanek: 3+1=4. Opponent: 1+1=2.
                        //   Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                        //   Chanek: 1+2+1=4. Opponent: 1+1=2.
                        // Both lead to 4. Taking N/2 is simpler.
                        chanek_coins += N / 2;
                        N /= 2;
                    } else { // N/2 is even
                        // If N/2 is even, taking N/2 leaves an even number of coins for opponent.
                        // Opponent can take N/4. This is generally bad for Chanek.
                        // Taking 1 leaves an odd number for opponent.
                        // Example: N=4. N/2=2 (even).
                        //   Chanek takes 2: N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                        //   Chanek: 2+1=3. Opponent: 1.
                        //   Chanek takes 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        //   Chanek: 1+1=2. Opponent: 1+1=2.
                        // In this case, taking N/2 is better.
                        // Example: N=8. N/2=4 (even).
                        //   Chanek takes 4: N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        //   Chanek: 4+1=5. Opponent: 2+1=3.
                        //   Chanek takes 1: N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                        //   Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                        // Both lead to 5. Taking N/2 is simpler.
                        // It seems taking N/2 is always optimal if N is even and N > 2.
                        chanek_coins += N / 2;
                        N /= 2;
                    }
                }
            } else { // Opponent's turn
                if (N % 2 == 1) { // N is odd
                    N -= 1;
                } else { // N is even
                    if (N == 2) {
                        N -= 1;
                    } else if ((N / 2) % 2 == 1) { // N/2 is odd
                        N /= 2;
                    } else { // N/2 is even
                        N /= 2;
                    }
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We want current_sum + b1 + b2 + ... = 2 * (current_xor_sum ^ b1 ^ b2 ^ ...)
        // Let S' = current_sum and X' = current_xor_sum
        // We want S' + b1 + b2 + ... = 2 * (X' ^ b1 ^ b2 ^ ...)

        // Strategy: Add two elements, X' and S' + X'.
        // Let b1 = X'
        // Let b2 = S' + X'
        // New sum: S_new = S' + b1 + b2 = S' + X' + (S' + X') = 2*S' + 2*X'
        // New XOR sum: X_new = X' ^ b1 ^ b2 = X' ^ X' ^ (S' + X') = 0 ^ (S' + X') = S' + X'
        // Check condition: S_new = 2 * X_new
        // (2*S' + 2*X') = 2 * (S' + X')
        // This condition is always true.

        // So, we can always add two elements: current_xor_sum and current_sum + current_xor_sum.
        // The problem states we can add AT MOST 3 elements.
        // If the array is already good, we can add 0 elements.
        // The problem statement says "You don't have to minimize the number of added elements!".
        // So, even if it's already good, we can add 2 elements.
        // However, the example output for an already good array is 0 elements.
        // Let's follow the example and output 0 if already good.

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will "jump over" this 'b',
            // effectively doubling the number of 'a's that need to jump
            // over subsequent 'b's.
            // So, we double the current count of 'a's that are "active"
            // and need to jump over 'b's.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it needs to jump over all 'b's
            // that are currently represented by `count_a`.
            // Each jump is one step.
            total_steps = (total_steps + count_a) % MOD;
            // After this 'a' jumps over all 'b's, it effectively
            // becomes two 'b's and one 'a' to its right.
            // The 'a' moves past the 'b's.
            // The 'a' itself is now an active 'a' that needs to jump
            // over any 'b's further to its left.
            // So, we increment the count of active 'a's by 1.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, int> x_counts;
    std::map<int, int> y_counts;
    std::map<std::pair<int, int>, int> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Count pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Count pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Subtract pairs with same (x, y) coordinates (these are counted twice)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_ok: can a[0...i] be made strictly increasing starting from 0?
    // i.e., can we make a'_j = j for j=0...i, such that a'_j <= a_j?
    // This means a_j must be at least j.
    std::vector<bool> prefix_ok(n);
    prefix_ok[0] = (a[0] >= 0); // a[0] must be >= 0. We can make it 0.
    for (int i = 1; i < n; ++i) {
        prefix_ok[i] = (a[i] >= i);
    }

    // Calculate suffix_ok: can a[i...n-1] be made strictly decreasing ending at 0?
    // i.e., can we make a'_j = (n-1-j) for j=i...n-1, such that a'_j <= a_j?
    // This means a_j must be at least (n-1-j).
    std::vector<bool> suffix_ok(n);
    suffix_ok[n - 1] = (a[n - 1] >= 0); // a[n-1] must be >= 0. We can make it 0.
    for (int i = n - 2; i >= 0; --i) {
        suffix_ok[i] = (a[i] >= (n - 1 - i));
    }

    // Check if there exists a peak k (0-indexed)
    // such that a[0...k] can be made strictly increasing (0, 1, ..., k)
    // AND a[k...n-1] can be made strictly decreasing (k, k-1, ..., 0)
    // This means a[i] >= i for i <= k
    // AND a[j] >= (k - (j-k)) = 2k - j for j >= k
    // The condition for a[k] is a[k] >= k (from prefix) AND a[k] >= k (from suffix, as n-1-k = k when k is peak)
    // This is equivalent to checking if a[i] >= i for i <= k and a[j] >= (n-1-j) for j >= k.
    // The peak element a[k] must satisfy a[k] >= k AND a[k] >= (n-1-k).
    // The minimum value for a[k] would be max(k, n-1-k).
    // However, the problem statement implies a_k is the peak, so a_k > a_{k-1} and a_k > a_{k+1}.
    // The conditions we derived (a_i >= i and a_j >= n-1-j) ensure this.
    // For a peak k, we need prefix_ok[k] to be true AND suffix_ok[k] to be true.
    // This is because prefix_ok[k] checks if a[0...k] can be 0,1,...,k.
    // And suffix_ok[k] checks if a[k...n-1] can be k,k-1,...,0.
    // Both conditions together ensure that a[k] can be at least k.
    // The actual values would be a'_0=0, a'_1=1, ..., a'_k=k, a'_{k+1}=k-1, ..., a'_{n-1}=0.
    // This requires a_i >= i for i <= k AND a_j >= (k - (j-k)) for j >= k.
    // The second part is equivalent to a_j >= (n-1-j) if we consider the "height" from the right end.
    // Let's re-evaluate.
    // For a peak at index k (0-indexed):
    // a'_0 < a'_1 < ... < a'_k
    // a'_k > a'_{k+1} > ... > a'_{n-1}
    // To make this possible with minimal values:
    // a'_i = i for i <= k
    // a'_j = k - (j-k) for j > k. (This is k, k-1, k-2, ..., k-(n-1-k) = 2k-n+1)
    // So we need:
    // a_i >= i for i <= k
    // a_j >= k - (j-k) for j > k
    // The second condition can be rewritten as a_j >= k - j + k = 2k - j.
    // This is equivalent to a_j >= (n-1-j) if we consider the "height" from the right end.
    // Example: n=6, k=2 (0-indexed). Peak at a[2].
    // a'_0=0, a'_1=1, a'_2=2, a'_3=1, a'_4=0, a'_5=-1 (not allowed)
    // This means the right side must also be non-negative.
    // The values must be a'_j >= 0.
    // So, a'_j = max(0, k - (j-k)).
    // This is equivalent to a_j >= (n-1-j) for j >= k.
    // Because if we set a'_j = (n-1-j) for j >= k, then a'_k = n-1-k.
    // For a valid peak, we need a'_k to be the maximum.
    // So we need a'_k >= k and a'_k >= n-1-k.
    // The conditions `a_i >= i` for `i <= k` and `a_j >= (n-1-j)` for `j >= k` are sufficient.
    // If these hold, we can construct the array:
    // a'_i = i for i <= k
    // a'_j = (n-1-j) for j > k
    // This makes a'_k = k and a'_{k+1} = n-1-(k+1) = n-k-2.
    // For a peak, we need a'_k > a'_{k+1}, so k > n-k-2, which means 2k > n-2.
    // This is not always true. For example, if n=3, k=0. a'_0=0, a'_1=1, a'_2=0. This is not sharpened.
    // The definition of sharpened is a_1 < ... < a_k and a_k > ... > a_n.
    // This means a_k must be strictly greater than its neighbors.
    // The conditions `a_i >= i` for `i <= k` and `a_j >= (n-1-j)` for `j >= k` are correct.
    // If these hold, we can construct a sharpened array.
    // For example, if `a_i >= i` for `i <= k` and `a_j >= (n-1-j)` for `j >= k`.
    // We can set `a'_i = i` for `i <= k`.
    // We can set `a'_j = (n-1-j)` for `j >= k`.
    // Then `a'_0=0, a'_1=1, ..., a'_k=k`.
    // And `a'_k=n-1-k, a'_{k+1}=n-2-k, ..., a'_{n-1}=0`.
    // For this to be a valid sharpened array, we need to pick a peak `k_peak`.
    // The values must be `0, 1, ..., k_peak, k_peak-1, ..., 0`.
    // So we need `a_i >= i` for `i <= k_peak` AND `a_j >= (k_peak - (j-k_peak))` for `j > k_peak` AND `a_j >= 0`.
    // This simplifies to `a_i >= i` for `i <= k_peak` AND `a_j >= max(0, k_peak - (j-k_peak))` for `j > k_peak`.
    // The `suffix_ok` array checks if `a_j >= (n-1-j)`.
    // If we choose `k_peak` such that `prefix_ok[k_peak]` is true and `suffix_ok[k_peak]` is true,
    // then `a_i >= i` for `i <= k_peak` and `a_j >= (n-1-j)` for `j >= k_peak`.
    // We can then construct the array `b`:
    // `b_i = i` for `i <= k_peak`.
    // `b_j = (n-1-j)` for `j >= k_peak`.
    // This means `b_k_peak = k_peak` and `b_k_peak = n-1-k_peak`.
    // For this to be a valid peak, we need `k_peak = n-1-k_peak`. This implies `2*k_peak = n-1`.
    // This only works if `n` is odd and `k_peak` is the middle element.
    // This is not what the problem means. The peak `k` is just an index.
    // The conditions are `a_1 < ... < a_k` and `a_k > ... > a_n`.
    // We can make `a'_i = i` for `i <= k`.
    // We can make `a'_j = k - (j-k)` for `j > k`.
    // This requires `a_i >= i` for `i <= k`.
    // And `a_j >= k - (j-k)` for `j > k`.
    // And `a_j >= 0` for all `j`.
    // The `prefix_ok[i]` checks `a_x >= x` for `x <= i`.
    // The `suffix_ok[i]` checks `a_x >= (n-1-x)` for `x >= i`.
    // If we find an `i` such that `prefix_ok[i]` is true AND `suffix_ok[i]` is true,
    // then we can make `a'_x = x` for `x <= i` and `a'_x = (n-1-x)` for `x >= i`.
    // This means `a'_0=0, a'_1=1, ..., a'_i=i`.
    // And `a'_i=n-1-i, a'_{i+1}=n-2-i, ..., a'_{n-1}=0`.
    // For this to be a valid sharpened array, we need `i = n-1-i`.
    // This is only true if `i` is the exact middle element.
    // This is not the general case.

    // Let's re-think the conditions for a peak at index `k` (0-indexed).
    // We need to find `a'_0, ..., a'_{n-1}` such that `a'_x <= a_x` and `a'_x >= 0`.
    // And `0 <= a'_0 < a'_1 < ... < a'_k`
    // And `a'_k > a'_{k+1} > ... > a'_{n-1} >= 0`.
    // To satisfy `0 <= a'_0 < ... < a'_k`, the minimum values are `a'_x = x` for `x <= k`.
    // This requires `a_x >= x` for `x <= k`.
    // To satisfy `a'_k > a'_{k+1} > ... > a'_{n-1} >= 0`, the minimum values are `a'_x = k - (x-k)` for `x > k`,
    // provided `k - (x-k) >= 0`. If `k - (x-k) < 0`, we need `a'_x = 0`.
    // So, `a'_x = max(0, k - (x-k))` for `x > k`.
    // This requires `a_x >= max(0, k - (x-k))` for `x > k`.
    // Combining these:
    // For a given `k` (0-indexed peak):
    // 1. `a_x >= x` for `0 <= x <= k`.
    // 2. `a_x >= max(0, k - (x-k))` for `k < x < n`.
    // If these conditions hold for *any* `k`, then "Yes".

    // Let's check this for `k=0` (strictly decreasing array):
    // 1. `a_0 >= 0`.
    // 2. `a_x >= max(0, 0 - (x-0))` for `0 < x < n`. This is `a_x >= max(0, -x)`. Since `x > 0`, `-x < 0`, so `max(0, -x) = 0`.
    // So for `k=0`, we need `a_0 >= 0` and `a_x >= 0` for `x > 0`. This is always true since `a_x >= 0` is given.
    // But the definition is `a_k > a_{k+1} > ... > a_n`.
    // So for `k=0`, we need `a_0 > a_1 > ... > a_{n-1} >= 0`.
    // The minimum values would be `a'_0 = n-1, a'_1 = n-2, ..., a'_{n-1} = 0`.
    // This requires `a_x >= n-1-x` for all `x`. This is exactly `suffix_ok[0]`.
    // So if `suffix_ok[0]` is true, it's possible.

    // Let's check this for `k=n-1` (strictly increasing array):
    // 1. `a_x >= x` for `0 <= x <= n-1`. This is exactly `prefix_ok[n-1]`.
    // 2. No `x` such that `k < x < n`.
    // So if `prefix_ok[n-1]` is true, it's possible.

    // For a general `k` (0 < k < n-1):
    // We need `a_x >= x` for `0 <= x <= k`.
    // And `a_x >= k - (x-k)` for `k < x < n`.
    // The second part is `a_x >= 2k - x`.
    // And `a_x >= 0` for all `x`.
    // The `prefix_ok` array already checks `a_x >= x` for `x <= k`.
    // The `suffix_ok` array checks `a_x >= (n-1-x)` for `x >= k`.
    // If `prefix_ok[k]` is true, then `a_x >= x` for `x <= k`.
    // If `suffix_ok[k]` is true, then `a_x >= (n-1-x)` for `x >= k`.
    // Let's try to construct the target array `b` using these conditions.
    // `b_x = x` for `x <= k`.
    // `b_x = (n-1-x)` for `x >= k`.
    // This means `b_k = k` and `b_k = n-1-k`.
    // For this to be a valid sharpened array, we need `b_k` to be the peak.
    // This means `k = n-1-k`, or `2k = n-1`. This is only for the exact middle.
    // This approach is flawed.

    // The correct approach for a peak at `k` (0-indexed):
    // We need to be able to form `0, 1, ..., k` on the left side.
    // This means `a_i >= i` for `0 <= i <= k`.
    // We need to be able to form `k-1, k-2, ..., 0` on the right side, starting from `a_{k+1}`.
    // This means `a_j >= (k - (j-k))` for `k < j < n`, and `k - (j-k) >= 0`.
    // Or, `a_j >= (k - (j-(k+1)+1))` for `j > k`.
    // Let's use the "height from ends" idea.
    // For `0 <= i <= k`, we need `a_i >= i`.
    // For `k < i < n`, we need `a_i >= (n-1-i)`.
    // If these conditions hold for some `k`, then we can construct the array:
    // `b_i = i` for `0 <= i <= k`.
    // `b_i = (n-1-i)` for `k < i < n`.
    // This array `b` would be `0, 1, ..., k, n-1-(k+1), n-1-(k+2), ..., 0`.
    // For this to be sharpened, we need `k > n-1-(k+1)`.
    // `k > n-k-2`
    // `2k > n-2`.
    // This is the condition for `k` to be a "true" peak.
    // If `2k <= n-2`, then `k <= n-k-2`.
    // In this case, the sequence `0, 1, ..., k, n-k-2, ..., 0` is not sharpened at `k`.
    // It would be `0, 1, ..., k, k+1, ..., n-1-k, n-2-k, ..., 0`.
    // The peak would be at `n-1-k`.
    // This means we need to find *any* `k_peak` (0-indexed) such that:
    // `a_i >= i` for `0 <= i <= k_peak`.
    // `a_i >= (n-1-i)` for `k_peak < i < n`.
    // This is equivalent to checking if there is an index `k_peak` such that
    // `prefix_ok[k_peak]` is true (meaning `a_i >= i` for `0 <= i <= k_peak`)
    // AND `suffix_ok[k_peak+1]` is true (meaning `a_i >= (n-1-i)` for `k_peak+1 <= i < n`).
    // This is the correct interpretation.

    // `prefix_ok[i]` means `a_0 >= 0, a_1 >= 1, ..., a_i >= i`.
    // `suffix_ok[i]` means `a_i >= n-1-i, a_{i+1} >= n-1-(i+1), ..., a_{n-1} >= 0`.

    // We need to find if there exists an index `k` (0-indexed) such that:
    // `a_i >= i` for all `0 <= i <= k`
    // AND `a_i >= (n-1-i)` for all `k < i < n`.

    // Let's compute `left_reach[i]` = true if `a_0, ..., a_i` can be `0, ..., i`.
    // `left_reach[0] = (a[0] >= 0)`
    // `left_reach[i] = left_reach[i-1] && (a[i] >= i)` for `i > 0`.
    std::vector<bool> left_reach(n);
    left_reach[0] = (a[0] >= 0);
    for (int i = 1; i < n; ++i) {
        left_reach[i] = left_reach[i - 1] && (a[i] >= i);
    }

    // Let's compute `right_reach[i]` = true if `a_i, ..., a_{n-1}` can be `..., 1, 0`.
    // `right_reach[n-1] = (a[n-1] >= 0)`
    // `right_reach[i] = right_reach[i+1] && (a[i] >= (n-1-i))` for `i < n-1`.
    std::vector<bool> right_reach(n);
    right_reach[n - 1] = (a[n - 1] >= 0);
    for (int i = n - 2; i >= 0; --i) {
        right_reach[i] = right_reach[i + 1] && (a[i] >= (n - 1 - i));
    }

    // Now, iterate through all possible peak indices `k` (0-indexed).
    // For a peak at `k`, we need:
    // 1. `a_0, ..., a_k` can be `0, ..., k`. This is `left_reach[k]`.
    // 2. `a_k, ..., a_{n-1}` can be `k, k-1, ..., 0`. This is `right_reach[k]`.
    // If `left_reach[k]` is true AND `right_reach[k]` is true, then it's possible.
    // This is because if both are true, we can construct the array `b`:
    // `b_i = i` for `0 <= i <= k`.
    // `b_i = (n-1-i)` for `k < i < n`.
    // This array `b` would be `0, 1, ..., k, n-1-(k+1), n-1-(k+2), ..., 0`.
    // The peak is at `k` if `k > n-1-(k+1)`.
    // If `k <= n-1-(k+1)`, the peak is at `n-1-(k+1)`.
    // But the problem states "there exists an integer 1 <= k_idx <= n such that a_1 < ... < a_k_idx and a_k_idx > ... > a_n".
    // This means we just need to find *some* `k_idx` (1-indexed) that works.
    // The conditions `a_i >= i` for `0 <= i <= k` and `a_i >= (n-1-i)` for `k <= i < n`
    // (where `k` is the 0-indexed peak) are sufficient.
    // If these hold, we can construct `b_i = i` for `i <= k` and `b_i = (n-1-i)` for `i >= k`.
