    // This array `b` would be `0, 1, ..., k-1, max(k, n-1-k), n-1-(k+1), ..., 0`.
    // This array is always sharpened.
    // Example: n=3, a=[0,1,0].
    // left_reach: [T, T, F] (a[2]=0 < 2)
    // right_reach: [F, T, T] (a[0]=0 < 2)
    // No k such that left_reach[k] && right_reach[k]. Output: No. Correct.

    // Example: n=3, a=[1,0,1].
    // left_reach: [T, F, F] (a[1]=0 < 1)
    // right_reach: [F, F, T] (a[1]=0 < 1)
    // No k such that left_reach[k] && right_reach[k]. Output: No. Correct.

    // Example: n=2, a=[0,1].
    // left_reach: [T, T]
    // right_reach: [F, T] (a[0]=0 < 1)
    // k=1: left_reach[1] && right_reach[1] is T && T. Yes. Correct.
    // Array becomes [0,1]. Peak at 1.

    // Example: n=2, a=[1,0].
    // left_reach: [T, F] (a[1]=0 < 1)
    // right_reach: [T, T]
    // k=0: left_reach[0] && right_reach[0] is T && T. Yes. Correct.
    // Array becomes [1,0]. Peak at 0.

    // Example: n=6, a=[100, 11, 15, 9, 7, 8]
    // n-1 = 5
    // i:     0   1   2   3   4   5
    // a[i]: 100 11  15  9   7   8
    // i:     0   1   2   3   4   5
    // left_reach:
    // a[0]>=0 (100>=0) -> T
    // a[1]>=1 (11>=1) && T -> T
    // a[2]>=2 (15>=2) && T -> T
    // a[3]>=3 (9>=3) && T -> T
    // a[4]>=4 (7>=4) && T -> T
    // a[5]>=5 (8>=5) && T -> T
    // left_reach: [T, T, T, T, T, T]

    // n-1-i: 5   4   3   2   1   0
    // right_reach:
    // a[5]>=0 (8>=0) -> T
    // a[4]>=1 (7>=1) && T -> T
    // a[3]>=2 (9>=2) && T -> T
    // a[2]>=3 (15>=3) && T -> T
    // a[1]>=4 (11>=4) && T -> T
    // a[0]>=5 (100>=5) && T -> T
    // right_reach: [T, T, T, T, T, T]

    // All k from 0 to n-1 satisfy left_reach[k] && right_reach[k].
    // So output Yes. Correct.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (left_reach[k] && right_reach[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

