// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // This effectively means padding from the right of the reversed string
    // or padding from the left of the original number's digits.
    // Example: 92 -> "10" (reversed) -> "000...0010" (padded to 18)
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

