        if (i + x < n && w[i + x] == '1') {
            s_i_is_one = true;
        }

        // If s[i] is '1' but our constructed w cannot make it '1',
        // then no such w exists.
        if (s[i] == '1' && !s_i_is_one) {
            std::cout << -1 << std::endl;
