int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // These are w[i]...w[n-1]
        // The count of items taken from the right is (n-i)
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left.
            // The difference is (left_count - right_count).
            // If left_count == right_count + 1, one extra item from left.
            // This means the last item taken was from the left, and the previous one was from the right.
            // The number of "extra" left items that incur Ql penalty is (left_count - right_count - 1).
            // Example: LLLRR. left=3, right=2. diff=1. No penalty.
            // Example: LLLLRR. left=4, right=2. diff=2. One penalty.
            // The number of times we take an item from the left consecutively after the right items are exhausted
            // is (left_count - right_count - 1).
            // This is equivalent to (left_count - (n - left_count) - 1) = (2*left_count - n - 1)
            if (left_count > right_count + 1) { // If left_count >= right_count + 2
                current_energy += (left_count - right_count - 1) * Ql;
            }
        } else if (right_count > left_count) {
            // More items taken from right.
            // The number of "extra" right items that incur Qr penalty is (right_count - left_count - 1).
            // This is equivalent to ((n - left_count) - left_count - 1) = (n - 2*left_count - 1)
            if (right_count > left_count + 1) { // If right_count >= left_count + 2
                current_energy += (right_count - left_count - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

