    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string colors(n, ' ');
        char last_color1_digit = '0' - 1; // Represents a value smaller than any digit
        char last_color2_digit = '0' - 1; // Represents a value smaller than any digit
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < '0' + pivot_digit) {
                // Must be color 1
                if (current_digit < last_color1_digit) {
                    possible_with_pivot = false;
                    break;
                }
                colors[i] = '1';
                last_color1_digit = current_digit;
            } else if (current_digit > '0' + pivot_digit) {
                // Must be color 2
                if (current_digit < last_color2_digit) {
                    possible_with_pivot = false;
                    break;
                }
                colors[i] = '2';
                last_color2_digit = current_digit;
            } else { // current_digit == '0' + pivot_digit
                // Can be color 1 or color 2
                if (current_digit >= last_color2_digit) {
                    // Prefer color 2 if possible, as it allows more flexibility for future digits
                    // (future digits equal to pivot can also be color 2)
                    colors[i] = '2';
                    last_color2_digit = current_digit;
                } else if (current_digit >= last_color1_digit) {
                    // If not possible for color 2, try color 1
                    colors[i] = '1';
                    last_color1_digit = current_digit;
                } else {
                    // Not possible for either color
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            // Final check: ensure all digits are assigned a color
            // and the sequence is valid.
            // The logic above ensures local non-decreasing property for color 1 and color 2.
            // We also need to ensure last_color1_digit <= first_color2_digit.
            // The way we assign colors for digits equal to pivot_digit handles this.
            // If a digit d_i == pivot_digit is assigned color 1, it means d_i < last_color2_digit.
            // If a digit d_i == pivot_digit is assigned color 2, it means d_i >= last_color2_digit.
            // This implies that all digits assigned color 1 will be <= pivot_digit,
            // and all digits assigned color 2 will be >= pivot_digit.
            // The only edge case is if last_color1_digit > first_color2_digit.
            // But our greedy choice for pivot_digit ensures this:
            // For d_i < pivot_digit, it's color 1.
            // For d_i > pivot_digit, it's color 2.
            // For d_i == pivot_digit:
            //   If d_i >= last_color2_digit (which is >= pivot_digit), assign color 2.
            //   Else (d_i < last_color2_digit, so last_color2_digit must be > pivot_digit), assign color 1.
            // This ensures that any digit assigned color 1 is <= pivot_digit,
            // and any digit assigned color 2 is >= pivot_digit.
            // Thus, the last digit of color 1 will be <= pivot_digit,
            // and the first digit of color 2 will be >= pivot_digit.
            // So last_color1_digit <= first_color2_digit is implicitly satisfied.

            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

