#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_val = (b - 1);
    if (sum_r_val < 0) sum_r_val = 0; // If b=1, b-1=0, sum is 0.
    sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_k_b_term = (b % MOD * sum_k_val) % MOD;
    long long sum_k_term = (sum_k_b_term + (a % MOD)) % MOD;

    // Total sum = sum_r_val * sum_k_term
    long long total_sum = (sum_r_val * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <iomanip>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute character occurrences
    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible first characters t[0]
    for (char c0_char = 'a'; c0_char <= 'z'; ++c0_char) {
        int c0_idx = c0_char - 'a';
        if (char_indices[c0_idx].empty()) {
            continue; // This character does not appear in s, so it cannot be t[0]
        }

        // Possible values for k given t[0] = c0_char
        const std::vector<int>& possible_k_values = char_indices[c0_idx];
        int num_possible_k = possible_k_values.size();

        if (num_possible_k == 1) {
            // If only one k is possible, Vasya wins for sure for this c0_char.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to L-1)
        double max_win_prob_for_c0 = 0.0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, we need to count how many k values are uniquely determined.
            // We use a map to group k values by the pair (t[0], t[p]).
            // t[0] is fixed as c0_char.
            // t[p] = s[(p + k) % L].
            std::map<char, int> counts_for_p; // Map: t[p] character -> count of k's that produce it
            for (int k_val : possible_k_values) {
                char tp_char = s[(p + k_val) % L];
                counts_for_p[tp_char]++;
            }

            double win_prob_for_p = 0.0;
            for (auto const& [tp_char, count] : counts_for_p) {
                if (count == 1) {
                    // If only one k produces this (c0_char, tp_char) pair, Vasya wins.
                    win_prob_for_p += 1.0;
                }
            }
            // The probability of winning for this specific p is (number of uniquely determined k's) / (total number of possible k's)
            win_prob_for_p /= num_possible_k;
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, win_prob_for_p);
        }
        total_win_prob += max_win_prob_for_c0;
    }

    // The final probability is the sum of (P(win | t[0]=c) * P(t[0]=c)) over all c.
    // Since P(t[0]=c) = (number of k's such that s[k]=c) / L,
    // and we've already summed P(win | t[0]=c) * (number of k's such that s[k]=c),
    // we just need to divide by L.
    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

