#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> seen_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        seen_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::set<char> visited_in_layout;

    // Find a starting point: a character with only one neighbor (an end of a chain)
    // Or if all characters have two neighbors, pick any unvisited character.
    char start_char = '\0';
    for (char c : seen_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in s have 2 neighbors (a cycle or a single char)
    // Or s has only one character.
    if (start_char == '\0' && !seen_in_s.empty()) {
        // If s has only one character, it will be the start_char.
        // If s has multiple characters and all have 2 neighbors, it implies a cycle.
        // A cycle is not possible on a linear keyboard.
        // Exception: if s has only one character, it has 0 neighbors.
        // If s has only one character, adj[s[0]] is empty, size is 0.
        // If s has multiple characters and all have 2 neighbors, it's a cycle.
        // Example: "abacaba" -> a: {b,c}, b: {a}, c: {a} -> a has 2, b has 1, c has 1.
        // Example: "abcde" -> a:b, b:ac, c:bd, d:ce, e:d. a and e have 1, others 2.
        // Example: "abacaba" -> a-b, a-c. This forms a 'Y' shape, which is fine.
        // The only case where all characters in `seen_in_s` have 2 neighbors is if they form a cycle.
        // E.g., "abcb" -> a:b, b:ac, c:b. Here a and c have 1 neighbor.
        // E.g., "abac" -> a:bc, b:a, c:a. Here b and c have 1 neighbor.
        // The only way all characters in `seen_in_s` have 2 neighbors is if `s` itself forms a cycle.
        // E.g., "abcda" -> a:bd, b:ac, c:bd, d:ac. This is not a simple path.
        // The problem states "adjacent characters in s, they should be adjacent on the keyboard".
        // This means the graph formed by `adj` must be a collection of disjoint paths.
        // If `start_char` is still null, it means all characters in `seen_in_s` have 0 or 2 neighbors.
        // If any character has 2 neighbors, and no character has 1 neighbor, it implies a cycle.
        // A cycle cannot be represented on a linear keyboard.
        // The only exception is if `seen_in_s` is empty (s is empty, but |s| >= 1) or contains only one character.
        // If `seen_in_s` contains only one character, say 'a', then `adj['a']` is empty, size 0.
        // In this case, `start_char` would still be null. We should pick this single char.
        if (!seen_in_s.empty()) {
            start_char = *seen_in_s.begin(); // Pick any char from s
            // If this char has 2 neighbors, it means it's part of a cycle.
            // If it has 0 neighbors, it's a single char.
            // If it has 1 neighbor, it would have been picked above.
            if (adj[start_char].size() == 2) { // This means it's part of a cycle
                std::cout << "NO\n";
                return;
            }
        }
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first step

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            keyboard_layout += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from 's' have been included in the layout.
    // This implicitly checks for disjoint paths/cycles.
    for (char c : seen_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means there's a disconnected component in the graph formed by `s`
            // that wasn't a single character and wasn't part of the main path.
            // This would happen if `s` implies multiple disjoint paths,
            // or a cycle that wasn't caught by the `adj[char].size() == 2` check for `start_char`.
            // The logic for `start_char` should cover cycles.
            // If `start_char` was null and `seen_in_s` was not empty, and we picked a char with 2 neighbors,
            // we already printed NO.
            // If `start_char` was null and `seen_in_s` was not empty, and we picked a char with 0 neighbors,
            // it means `s` had only one unique character. This is handled.
            // The only remaining case for `visited_in_layout.find(c) == visited_in_layout.end()`
            // is if there are multiple disjoint paths implied by `s`.
            // E.g., s = "ab" and then later "cd". This is fine, we just append them.
            // The current logic only builds one path. We need to build all paths.
            // Let's restart the path building for any unvisited character from `seen_in_s`.

            // This indicates a problem in the path construction logic if it didn't cover all `seen_in_s`
            // or if it implies a cycle.
            // The `adj[char].size() > 2` check handles forks.
            // The `adj[char].size() == 2` for all chars in `seen_in_s` implies a cycle.
            // If `start_char` was picked as a 1-neighbor char, it builds one path.
            // If `start_char` was picked as a 0-neighbor char (single char in `s`), it builds that char.
            // If `start_char` was picked as a 2-neighbor char (implies cycle), it prints NO.
            // So, if we reach here, it means there's a character `c` in `seen_in_s` that wasn't visited.
            // This `c` must be part of a new disjoint path.
            // We need to find a new `start_char` for this new path.

            // This implies that the graph formed by `s` is disconnected.
            // We need to find another starting point for a new chain.
            // This is handled by iterating through all `seen_in_s` and trying to extend.
            // The current loop structure is not robust for multiple disjoint paths.
            // Let's refactor the path building.
            std::cout << "NO\n"; // This should not be reached if the logic is correct.
            return;
        }
    }

    // Collect all remaining characters not in `s`
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

