    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Store balances for prefixes of the left half (jars 1 to n)
    // and suffixes of the right half (jars n+1 to 2n)
    // The balance is (count of 1s - count of 2s)

    // Balances for jars 1 to n (left side)
    // map: balance_diff -> minimum jars eaten from left to achieve this diff
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars eaten, balance diff 0

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) { // Iterate from jar n down to 1
        if (a[i] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // The number of jars eaten from the left is (n - i)
        // This is equivalent to eating jars 1, ..., n-i
        // The jars remaining on the left are i+1, ..., n
        // The balance of jars *eaten* from the left is current_balance_left
        // The number of jars eaten is n-i
        left_balances[current_balance_left] = n - i;
    }

    // Balances for jars n+1 to 2n (right side)
    // map: balance_diff -> minimum jars eaten from right to achieve this diff
    std::map<int, int> right_balances;
    right_balances[0] = 0; // 0 jars eaten, balance diff 0

    int current_balance_right = 0;
    for (int i = n; i < 2 * n; ++i) { // Iterate from jar n+1 up to 2n
        if (a[i] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
        // The number of jars eaten from the right is (i - n + 1)
        // This is equivalent to eating jars 2n, ..., i+1
        // The jars remaining on the right are n+1, ..., i
        // The balance of jars *eaten* from the right is current_balance_right
        // The number of jars eaten is i-n+1
        right_balances[current_balance_right] = i - n + 1;
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible balances achieved by eating from the left
    for (auto const& [left_diff, left_eaten_count] : left_balances) {
        // If we eat 'left_eaten_count' jars from the left,
        // the balance of these eaten jars is 'left_diff'.
        // The remaining jars have an initial balance of 'initial_balance'.
        // After eating 'left_eaten_count' jars with balance 'left_diff',
        // the balance of the *remaining* jars is (initial_balance - left_diff).
        // Let this be `target_remaining_balance`.
        // We need to eat some jars from the right such that the balance of
        // *those eaten jars* (from the right) is equal to `target_remaining_balance`.
        // This is because if we eat jars from left with balance `left_diff`
        // and jars from right with balance `right_diff`,
        // the total balance of eaten jars is `left_diff + right_diff`.
        // The balance of remaining jars is `initial_balance - (left_diff + right_diff)`.
        // We want this to be 0.
        // So, `initial_balance - (left_diff + right_diff) = 0`
        // `left_diff + right_diff = initial_balance`
        // `right_diff = initial_balance - left_diff`

        int required_right_diff = initial_balance - left_diff;

        if (right_balances.count(required_right_diff)) {
            int right_eaten_count = right_balances[required_right_diff];
            min_jars_eaten = std::min(min_jars_eaten, left_eaten_count + right_eaten_count);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n), R(n);

    // Calculate L[i]: length of consecutive 0s ending at i, or 1s ending at i
    // L[i] is 0 if a[i] is different from a[i-1]
    // L[i] is L[i-1] + 1 if a[i] is same as a[i-1]
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i, or 1s starting at i
    // R[i] is 0 if a[i] is different from a[i+1]
    // R[i] is R[i+1] + 1 if a[i] is same as a[i+1]
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_steps = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Found a '010' or '101' pattern
            int len_left = L[i - 1];
            int len_right = R[i + 1];
            int current_steps = (std::min(len_left, len_right) + 1) / 2;
            max_steps = std::max(max_steps, current_steps);
        }
    }

    std::cout << max_steps << std::endl;

    std::vector<int> result_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Found a '010' or '101' pattern
            int len_left = L[i - 1];
            int len_right = R[i + 1];

            // The middle element a[i] and its neighbors up to min(len_left, len_right)
            // will flip towards the dominant side.
            // If len_left < len_right, they become a[i-1].
            // If len_right < len_left, they become a[i+1].
            // If len_left == len_right, they become a[i-1] (which is also a[i+1] due to pattern).
            // The number of elements that flip is min(len_left, len_right).
            // The elements that flip are from i - min(len_left, len_right) + 1 to i + min(len_left, len_right) - 1.
            // The value they flip to is a[i-1].

            int flip_len = std::min(len_left, len_right);
            int target_val = a[i - 1]; // This is also a[i+1]

            for (int j = 0; j < flip_len; ++j) {
                result_a[i - j] = target_val;
                result_a[i + j] = target_val;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // Represents the state of a bit if initial bit is 0
    int current_val_1 = 1023; // Represents the state of a bit if initial bit is 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1 |= x;
        } else { // '^'
            current_val_0 ^= x;
            current_val_1 ^= x;
        }
    }

    // Now we have current_val_0 and current_val_1.
    // For each bit position j (0 to 9):
    // If initial bit is 0, final bit is (current_val_0 >> j) & 1.
    // If initial bit is 1, final bit is (current_val_1 >> j) & 1.

    // We need to find A, B, C such that for any input bit 'b':
    // ((b & A) | B) ^ C = final_bit
