// The state is (current_x, current_a_val_at_x_minus_1).
// The current_a_val_at_x_minus_1 is the value of a[x] from the previous step.
// This is because the problem states:
// 1. x = x + a[x], y = y + a[x]
// 2. x = x - a[x], y = y + a[x]
// The a[x] in step 2 is the *new* a[x] after step 1.
// The a[x] in step 3 is the *new* a[x] after step 2.
// This means the value of a[x] used in step 2 is A[x_old + A[x_old]].
// The value of a[x] used in step 3 is A[x_old + A[x_old] - A[x_old + A[x_old]]].
// This is confusing. Let's re-read carefully:
// "The program increases both x and y by a value equal to a_x simultaneously." (Step 2)
// "The program now increases y by a_x while decreasing x by a_x." (Step 3)
// "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates."
// This implies that a_x is evaluated *at the beginning of each step*.
// So, if current x is X:
// Step 2: let val = A[X]. X = X + val, Y = Y + val.
// Step 3: let val = A[X]. X = X - val, Y = Y + val.
// This means the value of A[X] changes based on the new X.

// Let's define a function `solve(start_x, start_y, current_a_val)`
// This is not quite right. The `current_a_val` is not a state variable.
// The state is just `x`. The `y` value accumulates.
// We need to find the final `y` for each starting `a_1`.
// The `a` array is `a_1, a_2, ..., a_n`.
// For each `i` from `1` to `n-1`, we set `a_1 = i`.
// The `a` array is effectively `i, A[2], ..., A[n]`.

// Let `dp[x][parity]` store the result for starting at `x` with `parity` step.
// `parity = 0` for the "add" step (x+a[x]), `parity = 1` for the "subtract" step (x-a[x]).
// `dp[x][parity]` will store a pair: `{final_y_change, final_x_change}`.
// This is a standard dynamic programming approach for paths on a graph.
// The graph nodes are `(x, parity)`.
// `dp[x][parity]` will store the total `y` accumulated and the final `x` reached
// if we start at `x` and perform the `parity` step, and then continue until termination.
// We need to compute this for each `a_1 = i`.
// The `a_1` value changes, so the `a` array changes.
// This means `dp` values depend on `a_1`.
// Recomputing `dp` for each `a_1` would be `O(N * N)`. `N=2e5`, so `N^2` is too slow.

// Notice that `a_1` only affects `A[1]`.
// When `x` is not `1`, `A[x]` is fixed.
// This suggests that we can precompute results for `x > 1`.
// Let `memo[x][parity]` store `{y_sum, final_x}` for `x > 1`.
// `parity = 0` means we are about to do `x = x + A[x]`, `y = y + A[x]`.
// `parity = 1` means we are about to do `x = x - A[x]`, `y = y + A[x]`.

// `memo[x][parity]` can be in three states:
// 0: not computed
// 1: currently computing (detect cycle)
// 2: computed

// `memo[x][parity]` will store `pair<long long, long long>`: `{total_y_change, final_x_value}`.
// `final_x_value` will be `0` if it terminates `x <= 0`, or `N+1` if it terminates `x > N`.
// Or `x` if it enters a cycle.

std::vector<long long> A;
std::vector<std::vector<std::pair<long long, long long>>> memo; // {y_sum, final_x}
std::vector<std::vector<int>> visited_state; // 0: unvisited, 1: visiting, 2: visited

// Function to compute {y_sum, final_x} starting from (curr_x, parity)
// parity = 0 means next step is x += A[x]
// parity = 1 means next step is x -= A[x]
std::pair<long long, long long> compute_path(long long curr_x, int parity) {
    if (curr_x <= 0 || curr_x > A.size() - 1) {
        return {0, curr_x}; // Terminated, no further y change, return current x
    }

    // If we are at x=1, its A[1] value depends on the outer loop's 'i'.
    // So we cannot use memoization for x=1.
    // We must compute it directly.
    if (curr_x == 1) {
        // This branch should not be called from memoization.
        // It will be called directly from the main loop for a_1 = i.
        // This means the `A[1]` value is already set.
        // So we can proceed with the calculation.
    } else {
        // For x > 1, A[x] is fixed. We can use memoization.
        if (visited_state[curr_x][parity] == 1) { // Cycle detected
            return {-1, -1}; // Indicate non-termination
        }
        if (visited_state[curr_x][parity] == 2) { // Already computed
            return memo[curr_x][parity];
        }
    }

    // Mark as visiting
    if (curr_x != 1) {
        visited_state[curr_x][parity] = 1;
    }

    long long current_a_val = A[curr_x];
    long long next_x;
    long long y_accum = current_a_val;

    if (parity == 0) { // x += A[x]
        next_x = curr_x + current_a_val;
    } else { // x -= A[x]
        next_x = curr_x - current_a_val;
    }

    std::pair<long long, long long> res;
    if (next_x <= 0 || next_x > A.size() - 1) {
        res = {y_accum, next_x};
    } else {
        // Next step is the other parity
        std::pair<long long, long long> next_res = compute_path(next_x, 1 - parity);
        if (next_res.first == -1) { // Non-termination from sub-path
            res = {-1, -1};
        } else {
            res = {y_accum + next_res.first, next_res.second};
        }
    }

    // Store result and mark as visited
    if (curr_x != 1) {
        memo[curr_x][parity] = res;
        visited_state[curr_x][parity] = 2;
    }
    return res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    A.resize(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> A[i];
    }

    // Initialize memoization tables for x > 1
    // Size n+1 for 1-indexing, 2 for parity (0 or 1)
    memo.resize(n + 1, std::vector<std::pair<long long, long long>>(2, {0, 0}));
    visited_state.resize(n + 1, std::vector<int>(2, 0));

    for (long long i = 1; i < n; ++i) {
        A[1] = i; // Set a_1 for the current run

        long long current_x = 1;
        long long current_y = 0;

        // First step is always x += A[x], y += A[x]
        // This is equivalent to calling compute_path(1, 0)
        // But we need to handle x=1 specially because A[1] changes.
        // So we manually do the first step, then call compute_path for the rest.

        long long val_at_1 = A[1];
        current_y += val_at_1;
        current_x += val_at_1;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // Now we are at (current_x, current_y) and the next step is x -= A[x] (parity 1)
            std::pair<long long, long long> result = compute_path(current_x, 1);
            if (result.first == -1) { // Non-termination
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + result.first << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> v(n);
    std::vector<long long> d(n);
    std::vector<long long> p(n);
    std::vector<int> original_indices(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> v[i] >> d[i] >> p[i];
        original_indices[i] = i + 1; // Store 1-based original index
    }

    std::vector<int> cured_children_indices;
    std::vector<bool> removed(n, false);

    for (int i = 0; i < n; ++i) {
        if (removed[i]) {
            continue;
        }

        cured_children_indices.push_back(original_indices[i]);
        removed[i] = true;

        long long current_v_cry = v[i];
        long long accumulated_d_cry = 0; // Sum of d_j from children removed *before* current child in line

        for (int j = i + 1; j < n; ++j) {
            if (removed[j]) {
                continue;
            }

            // Apply accumulated d_cry from children removed *before* j in the current iteration
            p[j] -= accumulated_d_cry;

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                p[j] -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (p[j] < 0) {
                removed[j] = true;
                accumulated_d_cry += d[j]; // Add d_j to accumulated cry for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

