int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;

        long long prev_b = 0; // The previous element in the non-decreasing array
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];

            // Case 1: current_a can be made equal to or greater than prev_b
            // without wrapping around m, using at most mid operations.
            // This means current_a + x >= prev_b for some x <= mid.
            // The smallest possible value for current_a + x is current_a.
            // If current_a >= prev_b, we can potentially use 0 operations on a[i]
            // and set b_i = current_a.
            // If current_a < prev_b, we need to increment current_a.
            // We need current_a + x >= prev_b, so x >= prev_b - current_a.
            // If prev_b - current_a <= mid, then we can achieve prev_b.
            // In this case, we set b_i = max(prev_b, current_a).
            // The number of operations needed is max(0LL, prev_b - current_a).
            // This is valid if max(0LL, prev_b - current_a) <= mid.

            // Case 2: current_a must wrap around m to become >= prev_b.
            // This means current_a + x >= prev_b + m for some x <= mid.
            // The smallest value current_a can take after wrapping is 0.
            // The largest value current_a can take after wrapping is (current_a + mid) % m.
            // If current_a + mid < prev_b, then it's impossible to make it >= prev_b
            // even with wrapping and max operations.
            // More precisely, if current_a + mid < prev_b and current_a < prev_b,
            // then we cannot make current_a >= prev_b.
            // The condition for wrapping is that current_a + x >= m.
            // If we increment current_a by x, it becomes (current_a + x) % m.
            // We want (current_a + x) % m >= prev_b.
            // This is possible if current_a + mid >= prev_b + m (after wrapping).
            // Or, if current_a + mid >= m and (current_a + mid) % m >= prev_b.
            // This is equivalent to saying that the range [current_a, (current_a + mid) % m]
            // (potentially wrapping around m) contains a value >= prev_b.

            // Let's simplify: we want to find b_i such that b_i >= prev_b and b_i = (current_a + x) % m for 0 <= x <= mid.
            // If current_a >= prev_b:
            // We can choose b_i = current_a. This requires 0 operations. Since 0 <= mid, this is always valid.
            // So, we can set prev_b = current_a.
            // However, we might be able to choose a smaller b_i if current_a is very large,
            // by incrementing it to wrap around. But we want to minimize operations, not b_i.
            // The goal is to make b_i as small as possible, but at least prev_b.
            // So if current_a >= prev_b, we can set b_i = current_a.
            // The only exception is if current_a is so large that we can increment it by some x <= mid
            // to make it wrap around and become a smaller value that is still >= prev_b.
            // Example: m=10, prev_b=2, current_a=8, mid=3.
            // If we don't wrap: b_i = 8.
            // If we wrap: 8+1=9, 8+2=0, 8+3=1.
            // We can choose b_i=8.
