            // If we don't wrap: 0 < 8. Not possible.
            // If we wrap: 0+1=1, 0+2=2, 0+3=3. Still < 8. Not possible.
            // What if prev_b=8, current_a=7, mid=3.
            // If we don't wrap: 7 < 8. Not possible.
            // If we wrap: 7+1=8, 7+2=9, 7+3=0.
            // We can choose b_i=8 (by 1 op). This is valid.
            // So, if current_a + mid >= prev_b + m, we can always find a b_i >= prev_b.
            // For example, we can choose b_i = prev_b.
            // The number of operations needed to make current_a become prev_b (after wrapping) is (prev_b - current_a + m) % m.
            // If (prev_b - current_a + m) % m <= mid, then we can achieve prev_b.
            // So, if current_a >= prev_b:
            //   We can set b_i = current_a. This is valid.
            //   We can also potentially set b_i = prev_b if (prev_b - current_a + m) % m <= mid.
            //   But we want to make b_i as small as possible, so we prefer prev_b if possible.
            //   If (prev_b - current_a + m) % m <= mid, then we can set b_i = prev_b.
            //   Otherwise, we must set b_i = current_a.
            // If current_a < prev_b:
            //   We must increment current_a.
            //   If current_a + mid < prev_b, then it's impossible.
            //   Otherwise, we can set b_i = prev_b. This requires (prev_b - current_a + m) % m operations.
            //   This is valid if (prev_b - current_a + m) % m <= mid.

            // Let's re-evaluate the condition for setting prev_b for the next iteration.
            // We need to find the smallest b_i >= prev_b such that b_i = (current_a + x) % m for some 0 <= x <= mid.
            // If current_a >= prev_b:
            //   We can choose b_i = current_a (0 operations). This is always valid.
            //   We can also potentially choose b_i = prev_b. This requires (prev_b - current_a + m) % m operations.
            //   If (prev_b - current_a + m) % m <= mid, then we can achieve prev_b.
            //   In this case, we prefer prev_b because it's smaller or equal to current_a.
            //   So, if (prev_b - current_a + m) % m <= mid, then next prev_b is prev_b.
            //   Else, next prev_b is current_a.
            // If current_a < prev_b:
            //   We must increment current_a.
            //   The number of operations needed to reach prev_b is (prev_b - current_a + m) % m.
            //   If this is <= mid, then we can achieve prev_b. So next prev_b is prev_b.
            //   Else, it's impossible.

            // Combining these:
            // If current_a >= prev_b:
            //   If (current_a + mid) % m >= prev_b (this means we can reach prev_b by wrapping around, or current_a is already >= prev_b)
            //   AND (current_a + mid) % m < current_a (this means we actually wrapped around)
            //   AND (current_a + mid) % m is the largest value we can reach by wrapping.
            //   This logic is getting complicated. Let's use the simpler approach.

            // We need to find the smallest b_i >= prev_b such that b_i = (a_i + x) % m for some 0 <= x <= mid.
            // Option 1: Don't wrap around m.
            // We can achieve any value in [a_i, a_i + mid].
            // If a_i + mid >= prev_b, then we can potentially set b_i = max(a_i, prev_b).
            // The number of operations needed for this is max(0LL, prev_b - a_i).
            // If max(0LL, prev_b - a_i) <= mid, then we can set b_i = prev_b.
            // This is true if a_i >= prev_b OR (a_i < prev_b AND prev_b - a_i <= mid).
            // This simplifies to: if a_i + mid >= prev_b AND a_i <= prev_b, then we can set b_i = prev_b.
            // More simply: if a_i <= prev_b AND prev_b - a_i <= mid, then we can set b_i = prev_b.
            // If a_i >= prev_b, then we can set b_i = a_i. This requires 0 operations, which is <= mid.
            // So, if a_i >= prev_b, we can set b_i = a_i.
            // If a_i < prev_b:
            //   We need to increment a_i.
            //   If a_i + mid >= prev_b, then we can set b_i = prev_b.
            //   Otherwise (a_i + mid < prev_b), we cannot reach prev_b without wrapping.
            //     In this case, we must wrap.
            //     The values we can reach are [a_i, m-1] and [0, (a_i + mid) % m].
            //     If (a_i + mid) % m < prev_b, then it's impossible.
            //     Otherwise, we can set b_i = prev_b.

            // Let's use the condition:
            // If a_i >= prev_b:
            //   We can choose b_i = a_i (0 ops). This is always valid.
            //   We can also choose b_i = prev_b if (prev_b - a_i + m) % m <= mid.
            //   If we can choose prev_b, we prefer it because it's smaller or equal.
            //   So, if (prev_b - a_i + m) % m <= mid, then next prev_b is prev_b.
            //   Else, next prev_b is a_i.
            // If a_i < prev_b:
            //   We must increment a_i.
            //   The number of operations to reach prev_b is (prev_b - a_i + m) % m.
            //   If this is <= mid, then we can achieve prev_b. So next prev_b is prev_b.
            //   Else, it's impossible.

            // This logic is correct.
            if (current_a >= prev_b) {
                // Option 1: Don't wrap. Set b_i = current_a. This is valid (0 ops).
                // Option 2: Wrap. Set b_i = prev_b. This requires (prev_b - current_a + m) % m ops.
                // If Option 2 is possible (ops <= mid), we prefer it because prev_b <= current_a.
                if ((prev_b - current_a + m) % m <= mid) {
                    // We can make current_a become prev_b by wrapping.
                    // Example: m=10, prev_b=2, current_a=8, mid=5.
                    // (2 - 8 + 10) % 10 = 4. 4 <= 5. So we can make 8 become 2.
                    // prev_b remains prev_b.
                } else {
                    // Cannot make current_a become prev_b by wrapping within mid ops.
                    // So we must use current_a as b_i.
                    prev_b = current_a;
                }
            } else { // current_a < prev_b
                // We must increment current_a to be at least prev_b.
                // This requires wrapping around m.
                // The number of operations needed to make current_a become prev_b is (prev_b - current_a + m) % m.
                // This is equivalent to (prev_b - current_a).
                // If current_a + mid < prev_b, then it's impossible.
                // Example: m=10, prev_b=8, current_a=0, mid=3.
                // 0 + 3 < 8. Impossible.
                // The number of operations needed is prev_b - current_a.
                // If prev_b - current_a <= mid, then we can achieve prev_b.
                if (prev_b - current_a <= mid) {
                    // We can make current_a become prev_b. prev_b remains prev_b.
                } else {
                    // Impossible to make current_a become prev_b.
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

