}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1, S2 is empty)
    // min_f = min_a + second_min_a
    // max_f = max_a + second_max_a
    // goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness1 = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // The minimum possible f value is min_a + second_min_a (if both are in same subseq)
    // OR min_a + elements[1].value + h (if they are in different subseqs)
    // The maximum possible f value is max_a + second_max_a + h (if they are in different subseqs)
    // OR max_a + second_max_a (if both are in same subseq)

    // Consider a specific partition strategy:
    // Put elements[0] (smallest) into S1.
    // Put elements[1] (second smallest) into S2.
    // Put elements[2] to elements[n-1] into S2.
    // S1 = {elements[0]}
    // S2 = {elements[1], elements[2], ..., elements[n-1]}

    // With this partition:
    // min_f:
    //   - If S1 has at least two elements: min_a + second_min_a
    //   - If S2 has at least two elements: elements[1].value + elements[2].value
    //   - If S1 and S2 both have elements: min_a + elements[1].value + h
    // The minimum f value will be min_a + elements[1].value + h (from S1-S2 pair)
    // OR elements[1].value + elements[2].value (from S2-S2 pair, if n >= 3)
    // The smallest possible sum of two distinct elements is min_a + second_min_a.
    // So, min_f = std::min(min_a + elements[1].value + h, elements[1].value + elements[2].value) if n >= 3.
    // If n=2, S1={elements[0]}, S2={elements[1]}. Only one f value: elements[0].value + elements[1].value + h.
    // In general, the minimum f value will be min_a + elements[1].value + h.
    // This is because min_a + elements[1].value is the smallest possible sum of two distinct elements.
    // If they are in different subsequences, it's min_a + elements[1].value + h.
    // If they are in the same subsequence, it's min_a + elements[1].value.
    // The smallest possible f value is always at least min_a + elements[1].value.
    // If elements[0] and elements[1] are in different subsequences, min_f is at least min_a + elements[1].value + h.
    // If elements[0] and elements[1] are in the same subsequence, min_f is at least min_a + elements[1].value.
    // The minimum f value is `min_a + elements[1].value`.
    // The maximum f value is `max_a + second_max_a + h` (if max_a and second_max_a are in different subsequences)
    // OR `max_a + second_max_a` (if max_a and second_max_a are in the same subsequence).
    // OR `max_a + min_a + h` (if max_a and min_a are in different subsequences).

    // Let's consider the specific partition: elements[0] in S1, all others in S2.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Possible f values:
    // 1. From S1-S2 pairs: elements[0].value + elements[j].value + h for j=1..n-1
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    // 2. From S2-S2 pairs (if n >= 3): elements[i].value + elements[j].value for 1 <= i < j <= n-1
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-1].value + elements[n-2].value
    //
    // Overall min_f for this partition:
    // If n=2: only elements[0].value + elements[1].value + h.
    // If n>=3: std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    //
    // Overall max_f for this partition:
    // If n=2: only elements[0].value + elements[1].value + h.
    // If n>=3: std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)

    long long current_min_f_val;
    long long current_max_f_val;

    if (n == 2) {
        current_min_f_val = elements[0].value + elements[1].value + h;
        current_max_f_val = elements[0].value + elements[1].value + h;
    } else {
        current_min_f_val = std::min(elements[0].value + elements[1].value + h, (long long)elements[1].value + elements[2].value);
        current_max_f_val = std::max(elements[0].value + elements[n-1].value + h, (long long)elements[n-1].value + elements[n-2].value);
    }

    long long goodness2 = current_max_f_val - current_min_f_val;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that s[l-1...r-1] contains a bad triplet.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible x and k to find bad triplets
    // x is 0-indexed, k is 1-indexed
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet is contained in any substring s[l-1...r-1] where l-1 <= x and x+2k <= r-1.
                // The smallest possible r-1 for this triplet is x+2k.
                // The largest possible l-1 for this triplet is x.

                // For any l' from 1 to x+1 (0-indexed l'-1 from 0 to x),
                // the substring s[l'-1 ... r'-1] will contain this triplet if r'-1 >= x+2k.
                // We want to find the minimum r' for each l'.
                // So, for l = x+1 (0-indexed x), the minimum r is x+2k+1.
                // For l = x (0-indexed x-1), the minimum r is x+2k+1.
                // ...
                // For l = 1 (0-indexed 0), the minimum r is x+2k+1.

                // The problem uses 1-based indexing for l, r, x, k.
                // If s_x = s_{x+k} = s_{x+2k} (0-indexed),
                // then for any l_0 (0-indexed) such that 0 <= l_0 <= x,
                // the substring starting at l_0 contains this triplet if its end index r_0 >= x+2k.
                // So, for each l_0 from 0 to x, the minimum r_0 that contains this triplet is x+2k.
                // In 1-based indexing: for each l from 1 to x+1, the minimum r is x+2k+1.

                // Update min_r_for_l[l] for l from 1 to x+1.
                // Since we are iterating x from 0 to n-1, and k from 1 upwards,
                // x+2k will be increasing.
                // For a fixed x, as k increases, x+2k increases.
                // For a fixed k, as x increases, x+2k increases.
                // This means that when we find a new triplet, its x+2k value might be larger than
                // previously found x'+2k' for the same l.
                // We need the minimum r for each l.
                // So, min_r_for_l[l] = min(min_r_for_l[l], x+2k+1).

                // The loop for l goes from 1 to x+1 (inclusive).
                // The 0-indexed equivalent is l_0 from 0 to x.
                // min_r_for_l[l_0+1] stores the minimum 1-based r.
                int current_min_r = x + 2 * k + 1; // 1-based end index of the triplet
                for (int l_idx = 0; l_idx <= x; ++l_idx) { // l_idx is 0-based start index
                    min_r_for_l[l_idx + 1] = std::min(min_r_for_l[l_idx + 1], current_min_r);
                }
            }
        }
    }

    long long total_pairs = 0;
    // Now, min_r_for_l[l] contains the minimum r (1-based) such that s[l-1...r-1] contains a bad triplet.
    // If min_r_for_l[l] is n+1, it means no bad triplet starts at or before l-1 and ends at or after l-1.
    // This is not quite right. min_r_for_l[l] means the minimum r such that a bad triplet (x,k) exists with l <= x and x+2k <= r.
    // We need to propagate the minimum r values.
    // If min_r_for_l[l] is R, then for any l' > l, if min_r_for_l[l'] is greater than R,
    // it means that the triplet found for l also covers l'.
    // So, min_r_for_l[l] should be non-increasing.
    // min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1])
    // This is wrong. It should be min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l-1])
    // because if a triplet starts at l-1, it also starts at l.
    // No, this is also wrong.
    // min_r_for_l[l] is the minimum r such that there exists a triplet (x,k) with l <= x and x+2k <= r.
    // If min_r_for_l[l] is R, then for any l' < l, min_r_for_l[l'] must be <= R.
    // This means min_r_for_l should be non-increasing.
    // So, min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l-1]) for l from 2 to n.
    for (int l = 2; l <= n; ++l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l - 1]);
    }

    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one bad triplet starting at or after l
            // For this l, any r from min_r_for_l[l] to n will form a valid pair (l, r).
            total_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case 1: k = 1 cut
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);

        // Rearrangement 1: s1 + s2 (original order)
        // This will always be s, so we don't check it.

        // Rearrangement 2: s2 + s1
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: k = 2 cuts
    // This is always possible unless all characters are the same.
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement
    // of its substrings will result in the same string "aaaa".
    // In this case, it's impossible to form a new palindrome.

    // Check if all characters are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, 2 cuts are always sufficient.
        // Example: s = "abacaba"
        // Cut into s[0...n/2-1] | s[n/2] | s[n/2+1...n-1]
        // For "abacaba", n=7, n/2=3.
        // Pieces: "aba", "c", "aba"
        // Rearrange to "aba" + "aba" + "c" = "ababaac" (not a palindrome)
        // Rearrange to "aba" + "c" + "aba" = "abacaba" (original)
        //
        // A simpler way to guarantee 2 cuts work for non-all-same palindromes:
        // Consider the string s. Since it's a palindrome and not all characters are the same,
        // there must be at least two distinct characters.
        // For example, if s = "otto", n=4.
        // Cut "ot|t|o". Pieces: "ot", "t", "o".
        // Rearrange: "o" + "t" + "ot" = "otot" (palindrome, != "otto").
        //
        // For any palindrome s that is not composed of all identical characters,
        // we can always find a way to make 2 cuts and rearrange.
        // Consider the first half of the string s[0...n/2-1].
        // If this half is not a palindrome itself, then we can cut s into
        // s[0...i-1] | s[i...n-i-1] | s[n-i...n-1] for some i.
        //
        // A general construction for 2 cuts:
        // Take s = s_1 s_2 ... s_k s_{k+1} ... s_N
        // Since s is a palindrome, s_i = s_{N-1-i}.
        // If not all characters are the same, there exists some i such that s_i != s_0.
        // Consider the string s' = s[1...N-1] + s[0].
        // This is a cyclic shift.
        // For example, "nolon", n=5.
        // s[0] = 'n', s[1...4] = "olon".
        // new_s = "olon" + "n" = "olonn". Not a palindrome.
        //
        // The problem statement implies that if a solution exists for k=2, it's 2.
        // The only case where it's impossible is if all characters are the same.
        // If s is a palindrome and not all characters are the same, then there must be
        // at least two distinct characters.
        // Example: "abacaba". n=7.
        // Cut: "aba" | "c" | "aba".
        // Rearrange: "aba" + "aba" + "c" = "ababaac" (not palindrome)
        //
        // The example "nolon" -> 2.
        // "no|l|on" -> "on|l|no" = "onlno" (palindrome, != "nolon").
        // This is achieved by cutting s into s[0...i-1], s[i...j-1], s[j...n-1].
        // Then rearranging these three pieces.
        // For "nolon", i=2, j=3. Pieces: "no", "l", "on".
        // Rearrange: s[j...n-1] + s[i...j-1] + s[0...i-1]
        // "on" + "l" + "no" = "onlno". This is a palindrome and not equal to "nolon".
        // This specific rearrangement (last piece, middle piece, first piece) works
        // if the first piece is the reverse of the last piece, and the middle piece is a palindrome.
        // This is true for any palindrome s.
        //
        // Let s = P M P_rev, where P is the first part, M is the middle part, P_rev is the reverse of P.
        // For "nolon", P="no", M="l", P_rev="on".
        // The pieces are P, M, P_rev.
        // Rearrange to P_rev M P. This is "onlno".
        // This is a palindrome because (P_rev M P)_rev = P_rev M_rev (P_rev)_rev = P_rev M P.
        // (Since M is a single character or a palindrome itself, M_rev = M).
        // This new string P_rev M P will be different from P M P_rev (original s)
        // if P is not empty and P != P_rev.
        // P != P_rev means P is not a palindrome.
        //
        // If s is a palindrome and not all characters are the same, then there must be
        // some prefix s[0...i-1] that is not a palindrome.
        // For example, "abacaba".
        // "a" is palindrome. "ab" is not.
        // Cut "a" | "bacab" | "a". Pieces: "a", "bacab", "a".
        // Rearrange: "a" + "bacab" + "a" = "abacaba" (original).
        //
        // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
        // then there exists at least one character c such that s[0] != c and c appears in s.
        // Consider the string s' formed by taking s[0...n-2] and moving s[n-1] to the front.
        // s' = s[n-1] + s[0...n-2].
        // Since s is a palindrome, s[n-1] = s[0]. So s' = s[0] + s[0...n-2].
        // This is not a useful transformation.
        //
        // The example "nolon" -> 2.
        // "no|l|on" -> "on|l|no" = "onlno".
        // This is achieved by taking the first half (excluding middle char if odd length),
        // the middle char (if odd length), and the second half.
        // Let s = P + M + P_rev (where M is empty if n is even).
        // Pieces are P, M, P_rev.
        // Rearrange to P_rev + M + P.
        // This new string is a palindrome.
        // It is different from s if P != P_rev.
        // P != P_rev means P is not a palindrome.
        //
        // If P is a palindrome, then s = P M P.
        // Example: "abacaba". P="aba", M="c". P is a palindrome.
        // P_rev M P = "aba" + "c" + "aba" = "abacaba". This is the original string.
        //
        // So, the 2-cut strategy (P, M, P_rev -> P_rev, M, P) only works if P is not a palindrome.
        // What if P is a palindrome?
        // Example: s = "abacaba". P="aba", M="c". P is a palindrome.
        // We need a different 2-cut strategy.
        //
        // The problem states "cut the paper minimum number of times k".
        // If k=1 doesn't work, and not all characters are the same, then k=2 must be the answer.
        // This is a common pattern in competitive programming: if a simple case doesn't work,
        // and a more complex case is generally true, then it's the answer.
        //
        // Let's re-verify the "Impossible" condition.
        // If all characters are the same, e.g., "qqqq".
        // Any cut will produce pieces like "q", "q", "q", "q".
        // Any rearrangement will result in "qqqq". So "Impossible".
        //
        // If not all characters are the same, then there must be at least two distinct characters.
        // Let's say s = "abacaba".
        // k=1:
        // "a"|"bacaba" -> "bacabaa" (not pal)
        // "ab"|"acaba" -> "acabaab" (not pal)
        // "aba"|"caba" -> "cabaaba" (not pal)
        // "abac"|"aba" -> "abaabac" (not pal)
        // "abaca"|"ba" -> "baabaca" (not pal)
        // "abacab"|"a" -> "aabacab" (not pal)
        // So k=1 doesn't work for "abacaba".
        //
        // The problem statement for "nolon" says "It can be shown that there is no solution with one cut."
        // And "nolon" is not all same chars. So it's 2.
        // The problem statement for "otto" -> 1.
        // "ot|to" -> "to|ot" = "toot" (palindrome, != "otto").
        //
        // The logic seems to be:
        // 1. Check for k=1. If any single cut and swap creates a new palindrome, answer is 1.
        // 2. If not, check if all characters in s are the same. If yes, answer is "Impossible".
        // 3. Otherwise (k=1 failed, but not all characters are the same), answer is 2.
        // This covers all cases and matches examples.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // dp[i] will store the minimum index j such that the first i target tracks (p[0]...p[i-1])
    // can be covered using j heads.
    // We want to find if dp[m] <= n.
    // Initialize dp with a value indicating "not possible" or "too many heads".
    // Since n is up to 10^5, n+1 is a safe "infinity".
    std::vector<int> dp(m + 1, n + 1);
    dp[0] = 0; // 0 tracks can be covered with 0 heads

    // For each target track p_i (from p[0] to p[m-1])
    for (int i = 0; i < m; ++i) {
        if (dp[i] > n) continue; // If p[0]...p[i-1] cannot be covered with <= n heads, skip

        // Try to cover p_i using an existing head (if p_i is already covered by a head's initial position)
        // This is not directly how the DP works. The DP state is about covering a prefix of p.
        // We iterate through each head h_k and see what prefix of p it can cover.

        // Find the first head h_k that can potentially cover p[i]
        // A head h_k can cover p[i] if h_k is within [p[i]-t, p[i]+t].
        // Since h and p are sorted, we can use binary search (std::lower_bound)
        // to find a suitable starting head.
        // We need to find a head h_k such that h_k - t <= p[i].
        // This means h_k <= p[i] + t.
        // We are looking for the first h_k such that h_k >= p[i] - t.
        // The heads are indexed from 0 to n-1.

        // For each head h_k, we want to find the maximum index j such that p[i...j-1] can be covered by h_k.
        // This is not quite right. The DP state is dp[i] = min_heads_for_p[0...i-1].
        // To compute dp[j], we need to find some dp[i] and then cover p[i...j-1] with one new head.

        // Let's rephrase: dp[i] is the minimum number of heads required to cover p[0...i-1].
        // To compute dp[j] (for p[0...j-1]):
        // We can take dp[j-1] heads and cover p[j-1] with one of them. This doesn't make sense.
        // The DP should be: dp[i] = minimum number of heads to cover p[0...i-1].
        // To compute dp[i]:
        //   dp[i] = min(dp[k] + 1) for all k < i, where one head can cover p[k...i-1].
        // This is O(m^2), too slow.

        // Let's use the greedy approach for `check(T)`:
        // We need to cover p[0], p[1], ..., p[m-1].
        // We use heads one by one.
        // `head_idx` is the index of the current head we are considering (from 0 to n-1).
        // `p_idx` is the index of the current target track we need to cover (from 0 to m-1).

        int current_head_idx = 0;
        int current_p_idx = 0;

        while (current_p_idx < m) {
            if (current_head_idx >= n) {
                return false; // Ran out of heads but still have tracks to cover
            }

            long long target_track = p[current_p_idx];

            // Find the first head h_k that can reach target_track.
            // A head h_k can reach target_track if h_k is in [target_track - t, target_track + t].
            // We want to find the smallest h_k such that h_k >= target_track - t.
            // This is `lower_bound(h.begin() + current_head_idx, h.end(), target_track - t)`.
            auto it_h = std::lower_bound(h.begin() + current_head_idx, h.end(), target_track - t);

            if (it_h == h.end()) {
                // No head from current_head_idx onwards can reach target_track - t.
                // This means no head can cover target_track.
                return false;
            }

            long long chosen_h = *it_h;
            int chosen_h_idx = std::distance(h.begin(), it_h);

            // If the chosen head `chosen_h` is too far to the right to cover `target_track`
            // (i.e., `chosen_h > target_track + t`), then no head from `chosen_h` onwards
            // can cover `target_track` either (since `h` is sorted).
            // In this case, we cannot cover `target_track` with any available head.
            if (chosen_h > target_track + t) {
                return false;
            }

            // We found a head `chosen_h` at `chosen_h_idx` that can cover `target_track`.
            // This head can cover the range `[chosen_h - t, chosen_h + t]`.
            // We use this head to cover as many subsequent tracks as possible.
