// Function to calculate parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

