                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - last_r_pos.
                // We need d to be at least this distance to make this jump.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current cell.
            }
        }
        // After iterating through all cells, we need to make one final jump from the last_r_pos
        // to cell n+1. The distance for this jump is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

