int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // This cut forms a smaller triangle similar to the original.
    // Let the height of this smaller triangle be x.
    // Let its base be b_x.
    // By similarity, x / b_x = h / 1, so b_x = x / h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the area from the apex to the i-th cut (at x_i) to be i * A_piece.
    // So, x_i^2 / (2h) = i * (h / (2n)).
    // x_i^2 = i * (h^2 / n).
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

