    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the minimum index of {1, ..., m} must be current_min_idx
        // and the maximum index of {1, ..., m} must be current_max_idx.
        // When we consider 'm', we update current_min_idx and current_max_idx
        // to include the position of 'm'.

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number 'm' is beautiful if there exists a subsegment [l, r]
        // such that it contains exactly {1, 2, ..., m}.
        // This implies:
        // 1. The minimum value in the subsegment is 1.
        // 2. The maximum value in the subsegment is m.
        // 3. The length of the subsegment (r - l + 1) is m.
        //
        // By maintaining current_min_idx and current_max_idx, we ensure
        // that the segment p[current_min_idx ... current_max_idx]
        // contains all numbers from 1 to m.
        //
        // If this segment's length is exactly 'm', then it must be a permutation
        // of 1 to m, because it contains 'm' distinct numbers (1 to m)
        // and its length is 'm'.
