            // Product of toys from Box 2 (odd count) and Box 3 is always > -1.
            // So, if A=0 and D=0, and B is odd, the product is > -1.
            // Otherwise, if A>0 or D>0, we can make the product <= -1.
            if (a > 0 || d > 0) {
                ans1 = true;
            }
            // Special case: if B=0 and C=0, and A is odd, then ans2 is false and ans1 is true.
            // Special case: if A=0 and D=0, and B is odd, then ans2 is true and ans1 is false.
            if (b == 0 && c == 0 && (a % 2 == 1)) {
                ans2 = false;
                ans1 = true;
            }
            if (a == 0 && d == 0 && (b % 2 == 1)) {
                ans2 = true;
                ans1 = false;
            }
        }
    }

    std::cout << (ans1 ? "Ya" : "Tidak") << " "
              << (ans2 ? "Ya" : "Tidak") << " "
              << (ans3 ? "Ya" : "Tidak") << " "
              << (ans4 ? "Ya" : "Tidak") << "\n";
}

