void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_a = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_a) {
            max_val_a = a[i];
        }
    }

    std::vector<int> prefix_max(n);
    std::vector<int> suffix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> suffix_is_perm(n + 1, false);

    // Calculate prefix_max and check prefix_is_perm
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_is_perm = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max_val_a is at most n-1
            current_is_perm = false;
        }
        seen_prefix[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        prefix_max[i] = current_max;
        if (current_is_perm && current_max == i + 1) {
            prefix_is_perm[i + 1] = true;
        }
    }

    // Calculate suffix_max and check suffix_is_perm
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    current_is_perm = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max_val_a is at most n-1
            current_is_perm = false;
        }
        seen_prefix[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;
        if (current_is_perm && current_max == (n - i)) {
            suffix_is_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

