        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append at most 3 elements.
        // Let's try to append 2 elements.
        // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2)
        // A simple strategy is to make b1 = X and b2 = S + X.
        // Let's check this:
        // New XOR sum X' = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X.
        // New sum S' = S + b1 + b2 = S + X + (S + X) = 2S + 2X.
        // Condition: S' = 2X'
        // 2S + 2X = 2 * (S + X)
        // This is always true.
        // So, we can always append X and S+X.
        // The problem states that appended elements are non-negative.
        // X is always non-negative. S is always non-negative. So S+X is non-negative.
        // This strategy works.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
}

