                n -= 1;
            } else if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent wants to maximize their coins, which means minimizing Chanek's future coins.
                // If N is even, opponent can take 1 or N/2.
                // If N=2, opponent takes 1.
                // Otherwise (N is even and N > 2), opponent takes N/2.
