int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually move past this 'b'.
            // Each such 'a' will generate a 'b' in front of it,
            // and then move past this 'b'.
            // The number of 'a's currently accumulated (a_count)
            // represents the number of 'a's that will interact with this 'b'.
            // Each of these 'a's will cause a step.
            // When an 'a' moves past a 'b', it effectively doubles the
            // number of 'a's that are "available" to move past subsequent 'b's.
            // This is because "ab" -> "bba". The 'a' moves past the 'b',
            // and effectively, the 'a' that was there is now "behind" two 'b's.
            // The 'a' that was there is now effectively "doubled" in its
            // potential to interact with future 'b's.
            // So, when an 'a' moves past a 'b', it contributes to the steps,
            // and then it effectively becomes 2 'a's for future interactions.
            // This means a_count should be doubled for the next 'b'.
            total_steps = (total_steps + a_count) % mod;
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available
            // to move past any 'b's encountered to its right (which we process next).
            // So, we increment the count of available 'a's.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

