void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // For each s[i], check if it can be '1' based on w
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        // If s[i] is '1' but our w cannot make it '1', then no solution
        if (s[i] == '1' && !can_be_one) {
            std::cout << -1 << std::endl;
            return;
        }
        // If s[i] is '0' but our w makes it '1', then no solution
        // This case is implicitly handled: if s[i] is '0', we forced w[i-x] and w[i+x] to '0'
        // so can_be_one would be false. If it's true, it means our initial assumption for w was wrong
        // or there's a contradiction. But our construction of w ensures this won't happen for s[i]=='0'.
        // Specifically, if s[i]=='0', then w[i-x] and w[i+x] are set to '0' (if they exist).
        // So can_be_one will be false. If s[i]=='0' and can_be_one is true, it means we made a mistake.
        // But the logic for setting '0's in w is correct.
        // The only case where can_be_one could be true for s[i]=='0' is if i-x or i+x is out of bounds,
        // and the other one is also out of bounds, which means s[i] should be '0' anyway.
        // Or if w[i-x] or w[i+x] was '1' but s[i] was '0', which is a contradiction.
        // The current logic correctly identifies contradictions for s[i]=='1'.
    }

    std::cout << w << std::endl;
}

