// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // The problem statement says "i-th from the right digit".
    // So, if number is 241, it's 1 (odd), 4 (even), 2 (even).
    // This means the string should be "001" (reversed from "100").
    // My current logic builds it from right to left, so "100" for 241.
    // We need to reverse it to match the "i-th from the right" interpretation
    // if we want to compare it directly with the input pattern string.
    // However, the problem also says "If the pattern is shorter than this integer,
    // it's supplemented with 0-s from the left." and vice-versa.
    // This implies that we should align from the right.
    // So, if number is 241, its parity string is "001" (2->0, 4->0, 1->1).
    // If pattern is "010", it means 3rd from right is 0, 2nd from right is 1, 1st from right is 0.
    // For 241, 1st from right is 1, 2nd is 0, 3rd is 0.
    // So 241 (001) does not match 010.
    // Example: 92, pattern 010.
    // 92 -> 10 (parity of 9 is 1, parity of 2 is 0).
    // Pattern 010.
    // 92 (10) matches 010 if we pad 92 with 0s from left: 010.
    // This means the string should be built from right to left, and then padded from left.
    // My current `pattern_str` is built from right to left, so for 241 it's "100".
    // For 92 it's "01".
    // We need to reverse this string to get the "standard" representation where index 0 is the leftmost digit.
    // No, the problem says "i-th from the right digit".
    // So, for 241, 1st from right is 1 (odd), 2nd is 4 (even), 3rd is 2 (even).
    // This gives "100" if we read from right to left.
    // If we want to store it as a string where index 0 is the rightmost digit, then "100" is correct.
    // Let's use a fixed length of 18 and pad with '0's from the left.
    // Example: 92. Parity: 01. Padded to 18: 000000000000000001.
    // This means the string should be built by taking digits from right to left,
    // and then padding the *left* of this string with '0's.
    // So, for 241: 1 (odd) -> '1', 4 (even) -> '0', 2 (even) -> '0'.
    // The string built is "100".
    // If we want to store it as a fixed-length string where the rightmost character corresponds to the rightmost digit,
    // we need to pad '0's to the left of "100" to make it 18 chars.
    // So, for 241, it would be "000000000000000100".
    // This is the correct interpretation.
    std::reverse(pattern_str.begin(), pattern_str.end());
    return std::string(18 - pattern_str.length(), '0') + pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern to 18 digits from the left with '0's
            std::string padded_s = std::string(18 - s.length(), '0') + s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

