#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n-i' items are taken from the right
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // Sum of w[n-1], w[n-2], ..., w[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalties
        if (i > j) { // More items from left than right
            // The last (i-j) items taken from the left will incur Ql penalty
            // if they are taken consecutively after another left item.
            // This happens if we take all 'j' right items, and then continue taking left items.
            // The number of 'extra' left items is i - j.
            // Each of these 'extra' left items (except the first one after the right items are exhausted)
            // will incur a Ql penalty if the previous item was also left.
            // The number of such penalties is (i - j - 1).
            // If i-j is 1, there are 0 penalties. If i-j is 2, there is 1 penalty.
            // So, (i - j - 1) * Ql.
            // This is equivalent to max(0, i - j - 1) * Ql.
            // The problem statement implies that if we take i items from left and j from right,
            // and i > j, then the (i-j) items that are 'excess' on the left side
            // will incur a penalty for each one except the first one.
            // So, if i = j+1, no penalty. If i = j+2, one penalty.
            // This means (i - j - 1) * Ql.
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // Similar logic for Qr penalty
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j, no extra penalties.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

