// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x must be a divisor of p, and x must not be a multiple of q.
        // To make x not a multiple of q, we must remove at least one prime factor from p
        // that is also a prime factor of q, such that the resulting x no longer has
        // enough of that prime factor to be divisible by q.
        // To maximize x, we should remove as little as possible.
        // This means for each prime factor f of q, we try to divide p by f until p is no longer
        // divisible by q, or until p is no divisor of the original p.
        // More precisely, for each prime factor f of q, we find the largest divisor of p
        // that is not divisible by q, by removing powers of f from p.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q
            // or until current_p is no longer divisible by q.
            // We want to find the largest divisor of p that is not divisible by q.
            // If p is divisible by q, we need to reduce p.
            // We iterate through prime factors of q. For each prime factor `f` of `q`,
            // we find the highest power of `f` that divides `q`. Let this be `f^k`.
            // We then divide `p` by `f` repeatedly until `p` is no longer divisible by `q`.
            // The resulting `p` is a candidate for `x`.

            // Example: p=12, q=6. q_prime_factors = {2, 3}
            // factor = 2:
            //   current_p = 12.
            //   12 % 6 == 0. Divide 12 by 2 -> 6.
            //   6 % 6 == 0. Divide 6 by 2 -> 3.
            //   3 % 6 != 0. Candidate x = 3. max_x = max(0, 3) = 3.
            // factor = 3:
            //   current_p = 12.
            //   12 % 6 == 0. Divide 12 by 3 -> 4.
            //   4 % 6 != 0. Candidate x = 4. max_x = max(3, 4) = 4.
            // Result: 4.

            while (current_p % q == 0) {
                current_p /= factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

