                first2 = d[i];
            } else { // d[i] == pivot_val
                // Try to assign to color 1 if it maintains non-decreasing property
                if (d[i] >= last1 && d[i] <= first2) { // Can be 1 or 2
                    // If we assign to 1, it must be <= first2.
                    // If we assign to 2, it must be >= last1.
                    // To maximize chances for future digits, assign to 2 if possible.
                    // This means if d[i] == pivot_val, and we've already seen a digit > pivot_val
                    // (i.e., first2 is not 10), then this d[i] must be assigned to 2.
                    // Otherwise, assign to 1.
                    if (d[i] < first2) { // Can still be 1
                        colors[i] = 1;
                        last1 = d[i];
                    } else { // Must be 2
                        colors[i] = 2;
                        first2 = d[i];
                    }
                } else {
                    possible_pivot = false;
                    break;
                }
            }
        }

        if (possible_pivot) {
            // Final check: last digit of color 1 <= first digit of color 2
            // This is implicitly handled by `last1` and `first2` logic.
            // If `last1` was updated, it means a digit was colored 1.
            // If `first2` was updated, it means a digit was colored 2.
            // The condition `d[i] >= last1` for color 2 and `d[i] <= first2` for color 1
            // ensures that `last1 <= first2` if both are used.

            // Re-verify the full sequence construction
            std::string s1_str = "";
            std::string s2_str = "";
            for(int i=0; i<n; ++i) {
                if (colors[i] == 1) {
                    s1_str += d_str[i];
                } else {
                    s2_str += d_str[i];
                }
            }
            std::string final_s = s1_str + s2_str;

            bool sorted = true;
            if (final_s.length() > 1) {
                for (size_t i = 0; i < final_s.length() - 1; ++i) {
                    if (final_s[i] > final_s[i+1]) {
                        sorted = false;
                        break;
                    }
                }
            }

            if (sorted) {
                for (int i = 0; i < n; ++i) {
                    std::cout << colors[i];
                }
                std::cout << "\n";
                return;
            }
        }
    }

    std::cout << "-\n";
}

