int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> pos(26);
    for (int i = 0; i < n; ++i) {
        pos[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char char0 = s[k_actual];
        int char0_idx = char0 - 'a';

        // Find all k' such that s[k'] == char0
        const std::vector<int>& possible_k_prime_indices = pos[char0_idx];

        if (possible_k_prime_indices.empty()) { // Should not happen if s is non-empty
            continue;
        }

        if (possible_k_prime_indices.size() == 1) {
            // If only one k' matches t[0], Vasya wins immediately without choosing p.
            // This k' must be k_actual.
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k' match t[0], Vasya needs to choose p optimally.
        // He wants to maximize the probability of winning for this specific char0.
        // This means choosing p such that for the given char0, the number of k'
        // that also match t[p] is minimized, ideally 1.

        double max_win_prob_for_char0 = 0.0;

        // Iterate over all possible positions p (from 1 to n-1)
        for (int p = 1; p < n; ++p) {
            std::map<char, int> counts_for_p; // char_p -> count of k' that produce it
            for (int k_prime : possible_k_prime_indices) {
                char char_p = s[(p + k_prime) % n];
                counts_for_p[char_p]++;
            }

            double current_p_win_prob = 0.0;
            for (auto const& [char_p_val, count] : counts_for_p) {
                if (count == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            // The probability of winning for this p is (number of unique (char0, char_p) pairs) / (number of possible k' for char0)
            max_win_prob_for_char0 = std::max(max_win_prob_for_char0, current_p_win_prob / possible_k_prime_indices.size());
        }
        total_win_prob += max_win_prob_for_char0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

