        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Minimum moves required is max(abs_n, abs_m)
        // If k is less than this, it's impossible.
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the number of moves that are "excess" beyond reaching (abs_n, abs_m)
        // using a path that maximizes diagonal moves initially.
        // This path involves abs_m diagonal moves and (abs_n - abs_m) straight moves.
        // Total moves for this path: abs_m + (abs_n - abs_m) = abs_n.
        long long remaining_moves = k - abs_n;

        long long diagonal_moves;

        // Case 1: abs_n and abs_m have the same parity.
        // This means (abs_n - abs_m) is even.
        // The point (abs_n, abs_m) has the same parity as (0,0) if (abs_n + abs_m) is even.
        // Or, equivalently, abs_n and abs_m have the same parity.
        if ((abs_n % 2) == (abs_m % 2)) {
            // If remaining_moves is even, we can use all k moves.
            // Each pair of excess moves can be (1,0) -> (0,0) or (1,1) -> (0,0) etc.
            // A pair of moves like (1,0) then (-1,0) uses 2 straight moves.
            // A pair of moves like (1,1) then (-1,-1) uses 2 diagonal moves.
            // To maximize diagonal moves, we want to use diagonal moves for these pairs.
            // So, if remaining_moves is even, we can make all k moves contribute to the final position.
            // The maximum number of diagonal moves is k.
            diagonal_moves = k;
        } else { // Case 2: abs_n and abs_m have different parity.
            // This means (abs_n - abs_m) is odd.
            // The point (abs_n, abs_m) has different parity from (0,0) if (abs_n + abs_m) is odd.
            // If remaining_moves is even, we cannot reach (abs_n, abs_m) in k moves.
            // Because each move changes the parity of (x+y) by 1.
            // So, after k moves, the parity of (x+y) will be k % 2.
            // We need (abs_n + abs_m) % 2 == k % 2.
            // If (abs_n % 2) != (abs_m % 2), then (abs_n + abs_m) % 2 == 1.
            // If k is even, then k % 2 == 0. So (abs_n + abs_m) % 2 != k % 2. Impossible.
            // However, the problem states we can visit any point any number of times.
            // This means we can make "wasted" moves.
            // If (abs_n % 2) != (abs_m % 2), then (abs_n + abs_m) is odd.
            // If k is even, we need to make an odd number of effective moves.
            // This means we must make at least one move that effectively "undoes" a previous move's parity.
            // For example, if we are at (X,Y) and need to reach (N,M) where (N+M) is odd,
            // and we have an even number of moves left.
            // We can make a move (X,Y) -> (X+1, Y) and then (X+1, Y) -> (X, Y).
            // This uses 2 moves, but changes the parity of (X+Y) twice, so it's back to original.
            // To change the parity of (X+Y) by 1, we need an odd number of moves.
            // If k is even, and (abs_n + abs_m) is odd, it's impossible to reach (abs_n, abs_m) in k moves.
            // Wait, this is incorrect. The parity of (x+y) changes by 0 or 2 for diagonal moves, and by 1 for straight moves.
            // No, this is also incorrect.
            // A move (dx, dy) changes x to x+dx, y to y+dy.
            // (x+dx) + (y+dy) = (x+y) + (dx+dy).
            // The parity of (x+y) changes by the parity of (dx+dy).
            // For diagonal moves: dx, dy are both non-zero. (dx+dy) can be 0, 2, -2. So (dx+dy) is even.
            // For straight moves: one of dx, dy is zero, the other is non-zero. (dx+dy) can be 1, -1. So (dx+dy) is odd.
            // This means diagonal moves preserve the parity of (x+y).
            // Straight moves flip the parity of (x+y).
            // Let S be the number of straight moves and D be the number of diagonal moves.
            // Total moves k = S + D.
            // The final parity of (n+m) must be (0+0) + S * (parity_change_from_straight_move) + D * (parity_change_from_diagonal_move)
            // (n+m) % 2 = S % 2.
            // So, S must have the same parity as (n+m).
            // We know k = S + D.
            // If (abs_n % 2) != (abs_m % 2), then (abs_n + abs_m) is odd. So S must be odd.
            // If k is even, and S must be odd, then D must be odd.
            // If k is odd, and S must be odd, then D must be even.

            // If (abs_n % 2) != (abs_m % 2), then (abs_n + abs_m) is odd.
            // We need S to be odd.
            // If k is even: S must be odd. This means D must be odd.
            // If k is odd: S must be odd. This means D must be even.

            // The minimum number of straight moves to reach (abs_n, abs_m) is (abs_n - abs_m).
            // If (abs_n - abs_m) is odd, then we need an odd number of straight moves.
            // If k is even, and we need an odd number of straight moves, we must use at least one "wasted" straight move.
            // For example, (0,0) -> (1,0) -> (0,0). This uses 2 straight moves, but effectively 0.
            // This changes the parity of S by 2.
            // So, if (abs_n - abs_m) is odd, and k is even, we cannot reach it.
            // This is because (abs_n - abs_m) is the minimum number of straight moves.
            // Any additional moves must be in pairs (e.g., (1,0) then (-1,0)).
            // Each such pair adds 2 to S or 2 to D.
            // So, the parity of S will always be the same as (abs_n - abs_m).
            // If (abs_n - abs_m) is odd, then S must be odd.
            // If k is even, and S is odd, then D must be odd.
            // This is possible.

            // Let's re-evaluate the parity condition.
            // The point (x,y) has parity (x+y)%2.
            // A diagonal move (dx,dy) where dx,dy != 0: (dx+dy) is even. Parity of (x+y) is preserved.
            // A straight move (dx,dy) where one of dx,dy is 0: (dx+dy) is odd. Parity of (x+y) is flipped.
            // Let S be the number of straight moves.
            // After k moves, the parity of (final_x + final_y) will be (initial_x + initial_y + S) % 2.
            // Since initial_x = initial_y = 0, we have (abs_n + abs_m) % 2 = S % 2.
            // We also know k = S + D.

            // If (abs_n % 2) != (abs_m % 2), then (abs_n + abs_m) is odd.
            // So, S must be odd.
            // If k is even, and S must be odd, then D must be odd.
            // If k is odd, and S must be odd, then D must be even.

            // The minimum number of moves to reach (abs_n, abs_m) is abs_n.
            // This path uses abs_m diagonal moves and (abs_n - abs_m) straight moves.
            // The number of straight moves is (abs_n - abs_m).
            // If (abs_n - abs_m) is odd, then S is odd. This matches the requirement.
            // If k is even, and S is odd, then D must be odd.
            // If k is odd, and S is odd, then D must be even.

            // The problem is that if k is even, and (abs_n + abs_m) is odd, it's impossible.
            // Example: (1,0) in 2 moves. (1+0) is odd. k=2 is even.
            // (0,0) -> (1,0) (1 straight move)
            // Now at (1,0), 1 move left. Need to end at (1,0).
            // Can go (1,0) -> (0,0) (1 straight move). Total 2 straight moves. Final (0,0).
            // Can go (1,0) -> (2,0) (1 straight move). Total 2 straight moves. Final (2,0).
            // Can go (1,0) -> (1,1) (1 diagonal move). Total 1 straight, 1 diagonal. Final (1,1).
            // In all cases, (final_x + final_y) is even.
            // So if (abs_n + abs_m) is odd, and k is even, it's impossible.
            if (k % 2 == 0) { // k is even
                std::cout << -1 << "\n";
                continue;
            }
            // If k is odd, and (abs_n + abs_m) is odd, it's possible.
            // We have remaining_moves = k - abs_n.
            // Since (abs_n % 2) != (abs_m % 2), abs_n is different parity from abs_m.
            // So abs_n and abs_n-1 have different parity.
            // If k is odd, and abs_n is even, then remaining_moves is odd.
            // If k is odd, and abs_n is odd, then remaining_moves is even.
            // We need to make one "wasted" move to adjust parity.
            // For example, (0,0) -> (1,0) -> (0,0) -> (1,0)
            // This uses 3 moves to reach (1,0).
            // The first abs_n moves get us to (abs_n, abs_m).
            // We have remaining_moves = k - abs_n.
            // If remaining_moves is even, we can use pairs of diagonal moves (e.g., (1,1) then (-1,-1)).
            // This adds 2 to D, and 0 to S.
            // If remaining_moves is odd, we need to use one straight move to adjust parity.
            // For example, (1,0) then (-1,0). This uses 2 straight moves.
            // We have k moves. We need to reach (abs_n, abs_m).
            // The maximum number of diagonal moves is k-1.
            // This is because we need at least one straight move to flip the parity of (x+y).
            // If (abs_n + abs_m) is odd, we need an odd number of straight moves.
            // If k is odd, we can achieve this by making k-1 diagonal moves and 1 straight move.
            // This gives k-1 diagonal moves.
            diagonal_moves = k - 1;
        }

        std::cout << diagonal_moves << "\n";
    }
    return 0;
}

