int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // Value if initial bit is 0
    int current_val_1 = 1023; // Value if initial bit is 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1 |= x;
        } else { // '^'
            current_val_0 ^= x;
            current_val_1 ^= x;
        }
    }

    int final_and_mask = 1023; // Represents the 'AND' constant
    int final_or_mask = 0;     // Represents the 'OR' constant
    int final_xor_mask = 0;    // Represents the 'XOR' constant

    for (int b = 0; b < 10; ++b) {
        int bit_0_result = (current_val_0 >> b) & 1;
        int bit_1_result = (current_val_1 >> b) & 1;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // Bit always becomes 0.
            // To achieve this: AND with 0 at this bit position.
            final_and_mask &= ~(1 << b);
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // Bit always becomes 1.
            // To achieve this: OR with 1 at this bit position.
            final_or_mask |= (1 << b);
        } else if (bit_0_result == 1 && bit_1_result == 0) {
            // Bit flips (0->1, 1->0).
            // To achieve this: XOR with 1 at this bit position.
            final_xor_mask |= (1 << b);
        }
        // If (bit_0_result == 0 && bit_1_result == 1), bit remains unchanged.
        // This is the default state for AND (1), OR (0), XOR (0) at this bit.
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) {
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> diff_L(n + 1, 0);
    int current_s = 0;
    int current_b = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_L[i + 1] = current_s - current_b;
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // for k from 0 to n
    std::vector<int> diff_R(n + 1, 0);
    current_s = 0;
    current_b = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_R[2 * n - i] = current_s - current_b;
    }

    // Store indices for diff_L values
    // map: diff_value -> minimum k (number of jars eaten from left)
    std::map<int, int> left_diff_to_k;
    for (int k = 0; k <= n; ++k) {
        if (left_diff_to_k.find(diff_L[k]) == left_diff_to_k.end()) {
            left_diff_to_k[diff_L[k]] = k;
        }
    }

    int min_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible number of jars eaten from the right (k_R)
    // For each k_R, we have diff_R[k_R]
    // We need (initial_diff - diff_L[k_L] - diff_R[k_R]) == 0
    // which means diff_L[k_L] == initial_diff - diff_R[k_R]
    for (int k_R = 0; k_R <= n; ++k_R) {
        int target_diff_L = initial_diff - diff_R[k_R];
        if (left_diff_to_k.count(target_diff_L)) {
            int k_L = left_diff_to_k[target_diff_L];
            min_eaten = std::min(min_eaten, k_L + k_R);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n); // length of consecutive zeros to the left, including current
    std::vector<int> right_zero_run(n); // length of consecutive zeros to the right, including current
    std::vector<int> left_one_run(n); // length of consecutive ones to the left, including current
    std::vector<int> right_one_run(n); // length of consecutive ones to the right, including current

    // Calculate left runs
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    left_one_run[0] = (a[0] == 1 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    right_one_run[n - 1] = (a[n - 1] == 1 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0 && a[i - 1] == 1 && a[i + 1] == 1) { // Pattern 1 0 1
            // This 0 will turn into 1.
            // The number of steps depends on the minimum of the surrounding 1-runs.
            // The 1-run to the left is `left_one_run[i-1]`.
            // The 1-run to the right is `right_one_run[i+1]`.
            // The 0 at `i` will become 1 after `min(left_one_run[i-1], right_one_run[i+1])` steps.
            int steps = std::min(left_one_run[i - 1], right_one_run[i + 1]);
            max_steps = std::max(max_steps, steps);
            final_a[i] = 1; // It will eventually become 1
        } else if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) { // Pattern 0 1 0
            // This 1 will turn into 0.
            // The number of steps depends on the minimum of the surrounding 0-runs.
            // The 0-run to the left is `left_zero_run[i-1]`.
            // The 0-run to the right is `right_zero_run[i+1]`.
            // The 1 at `i` will become 0 after `min(left_zero_run[i-1], right_zero_run[i+1])` steps.
            int steps = std::min(left_zero_run[i - 1], right_zero_run[i + 1]);
            max_steps = std::max(max_steps, steps);
            final_a[i] = 0; // It will eventually become 0
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L is roughly N
    // 2^18 = 262144, 2^19 = 524288
    // Since N <= 2e5, max value of f(t) can be around 2e5.
    // If f(t) = 2e5, then length L must be around log2(2e5) approx 17.6.
    // So, max L for which f(t) can be equal to L is small.
    // Let's pick a safe small_len_limit, say 20.
    // If L > 20, then 2^L is much larger than L.
    // For example, if L=20, 2^20 = 1048576.
    // If L=18, 2^18 = 262144.
    // If L=17, 2^17 = 131072.
    // The maximum possible value for f(s_l...s_r) is N (2e5).
    // So, if r-l+1 > 18, then f(s_l...s_r) would be at least 2^(r-l) if s_l='1'.
    // If s_l='1' and r-l+1 = 19, then f(s_l...s_r) >= 2^18 = 262144 > N.
    // So, we only need to check substrings of length up to 18 (or 19 to be safe).
    // Let's use a limit of 20 for small_len_limit.
    const int SMALL_LEN_LIMIT = 20; 

    for (int i = 0; i < n; ++i) {
        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // If len exceeds SMALL_LEN_LIMIT, the value current_val can become very large.
            // If s[i] is '1', current_val will be at least 2^(len-1).
            // If len > SMALL_LEN_LIMIT, then 2^(len-1) is much larger than n.
            // For example, if SMALL_LEN_LIMIT = 20, and len = 21, then current_val >= 2^20 > 2e5.
            // So, current_val can't be equal to len.
            // If s[i] is '0', then current_val will be smaller, but we handle this case separately.
            if (len > SMALL_LEN_LIMIT && s[i] == '1') {
                // Optimization: if current_val already exceeds n + SMALL_LEN_LIMIT,
                // it's unlikely to ever equal len, especially if len is much smaller.
                // The maximum possible value for len is n.
                // If current_val > n, it can't be equal to len.
                // We can break early if current_val is already too large.
                // A safe upper bound for current_val to check against is n + SMALL_LEN_LIMIT.
                // If current_val exceeds this, it's definitely too large.
                if (current_val > n + SMALL_LEN_LIMIT) { // n is max possible len
                    break; 
                }
            }

            current_val = (current_val << 1) | (s[j] - '0');

            // Check if current_val is too large to be equal to len.
            // If current_val > n, it cannot be equal to len, because len <= n.
            // This check is important for '1' starting substrings.
            if (current_val > n) {
                // If s[i] was '1', we can break.
                // If s[i] was '0', current_val might still be small, but we need to consider leading zeros.
                // The logic for leading zeros is handled by the '0' case below.
                // For '1' starting substrings, if current_val > n, it will only grow larger, so break.
                if (s[i] == '1') {
                    break;
                }
            }

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    // Handle substrings starting with '0'
    // For each '0' at index i, we need to find how many '0's precede it.
    // Let's say s[i] = '0'.
    // Substring s[i...i] has len 1, val 0. Not good.
    // Substring s[i...j] where s[i]='0', s[i+1]='0', ..., s[k-1]='0', s[k]='1'.
    // The value f(s[i...j]) is f(s[k...j]).
    // The length is j-i+1.
    // We need j-i+1 = f(s[k...j]).
    // This means f(s[k...j]) - (j-k+1) = k-i.
    // Let L_prime = j-k+1 be the length of the '1'-starting part.
    // Let val_prime = f(s[k...j]) be its value.
    // We need val_prime - L_prime = k-i.
    // k-i is the number of leading zeros.
    // The maximum number of leading zeros is n.
    // The maximum value of val_prime - L_prime is roughly n.
    // So, we can iterate through all possible starting positions k for a '1'.
    // For each k, iterate j from k up to min(n-1, k + SMALL_LEN_LIMIT - 1).
    // Calculate val_prime = f(s[k...j]) and L_prime = j-k+1.
    // If val_prime - L_prime >= 0 and val_prime - L_prime <= n,
    // then we can find a starting index i = k - (val_prime - L_prime).
    // If i >= 0 and s[i...k-1] are all '0's, then this is a good substring.

    // Precompute counts of consecutive leading zeros for each position.
    // `zeros_before[k]` stores the count of '0's immediately preceding index k.
    // e.g., for "000101", zeros_before[0]=0, zeros_before[1]=1, zeros_before[2]=2, zeros_before[3]=3, zeros_before[4]=0, zeros_before[5]=1.
    std::vector<int> zeros_before(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            zeros_before[i + 1] = zeros_before[i] + 1;
        } else {
            zeros_before[i + 1] = 0;
        }
    }

    for (int k = 0; k < n; ++k) {
        if (s[k] == '1') {
            long long val_prime = 0;
            for (int j = k; j < n; ++j) {
                int L_prime = j - k + 1;

                // If L_prime exceeds SMALL_LEN_LIMIT, val_prime will grow very fast.
                // If val_prime - L_prime exceeds n, it's impossible to find a valid i.
                // The maximum possible value for val_prime - L_prime is n.
                // If L_prime > SMALL_LEN_LIMIT, then val_prime is at least 2^(L_prime-1).
                // 2^(L_prime-1) - L_prime will quickly exceed n.
                // For example, if L_prime = 19, 2^18 - 19 = 262144 - 19 > 2e5.
                // So, we only need to check L_prime up to SMALL_LEN_LIMIT.
                if (L_prime > SMALL_LEN_LIMIT) {
                    break; 
                }

                val_prime = (val_prime << 1) | (s[j] - '0');

                // If val_prime itself exceeds n, then val_prime - L_prime will also exceed n (since L_prime is small).
                // So we can break.
                if (val_prime > n + SMALL_LEN_LIMIT) { // n is max possible value for k-i
                    break;
                }

                long long num_leading_zeros_needed = val_prime - L_prime;

                if (num_leading_zeros_needed >= 0) {
                    // Check if there are enough leading zeros before index k.
                    // `zeros_before[k]` stores the count of '0's immediately preceding index k.
                    // This means s[k-1], s[k-2], ..., s[k - zeros_before[k]] are all '0's.
                    // So, we can form a substring starting at `k - num_leading_zeros_needed`
                    // if `num_leading_zeros_needed` <= `zeros_before[k]`.
                    if (num_leading_zeros_needed <= zeros_before[k]) {
                        good_substrings_count++;
                    }
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a_i_max_val to a very large positive number
    // and initial_a_i_min_val to a very large negative number.
    // This represents the bounds on A_i.
    // A_i must be <= initial_a_i_max_val[i]
    // A_i must be >= initial_a_i_min_val[i]
    std::vector<long long> initial_a_i_max_val(n, 2000000000LL); // Max possible A_i is 10^9, but intermediate calculations can be larger
    std::vector<long long> initial_a_i_min_val(n, -2000000000LL); // Min possible A_i is -10^9

    // current_delta[j] stores the sum of 'd' values applied to index j
    // from type 1 operations *before* the current operation being processed.
    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d for l <= j <= r
            // This operation affects future type 2 queries.
            // We update current_delta for the range [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else {
            // Type 2: Max of a[j] in [l, r] is m
            // For each j in [l, r], we know that A_j + current_delta[j] <= m.
            // So, A_j <= m - current_delta[j].
            // We update the upper bound for A_j.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a_i_max_val[j] = std::min(initial_a_i_max_val[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // After processing all operations, we have bounds for each A_j.
    // A_j must be in [initial_a_i_min_val[j], initial_a_i_max_val[j]].
    // To satisfy all conditions, we should pick A_j = initial_a_i_max_val[j].
    // This choice maximizes A_j, which is generally helpful for satisfying max constraints.
    // If initial_a_i_max_val[j] < initial_a_i_min_val[j] for any j, then no solution exists.
    // However, initial_a_i_min_val was initialized to a very small number,
    // and was never updated. So we only need to check if initial_a_i_max_val[j]
    // is within the global |A_i| <= 10^9 constraint.
    // Let's use initial_a_i_max_val as our candidate initial array.
    std::vector<long long> A(n);
    for (int j = 0; j < n; ++j) {
        A[j] = initial_a_i_max_val[j];
        // Check if the chosen A[j] is within the global |A_i| <= 10^9 constraint.
        if (A[j] > 1000000000LL || A[j] < -1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    // Now, we must verify if this candidate array A satisfies all type 2 operations.
    // Simulate all operations with the chosen A.
    std::vector<long long> current_array_values = A; // This will store a_j + sum_of_d_for_j at each step
    current_delta.assign(n, 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d for l <= j <= r
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_array_values[j] += ops[i].val;
                current_delta[j] += ops[i].val; // Keep track of delta for future type 2 checks
            }
        } else {
            // Type 2: Max of a[j] in [l, r] is m
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_array_values[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the array A.
    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << A[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // Calculate the maximum possible number of ones in 'a' after appending parities.
    // Each append operation adds a '0' or '1'.
    // If parity is 0, we add '0', ones_a remains same.
    // If parity is 1, we add '1', ones_a increases by 1.
    // The maximum number of ones we can achieve in 'a' is if we always append '1's.
    // This happens if the current parity is 1.
    // The length of 'a' can grow up to |b|.
    // So, we can append |b| - |a| characters.
    // If current ones_a is odd, we can append '1', increasing ones_a by 1.
    // If current ones_a is even, we append '0', ones_a remains same.
    // So, if ones_a is odd, it can become ones_a + 1.
    // If ones_a is even, it remains ones_a.
    // This means the maximum number of ones we can have in 'a' (after potential appends)
    // is ones_a if ones_a is even, or ones_a + 1 if ones_a is odd.
    // This can be simplified to (ones_a + 1) / 2 * 2 if ones_a is odd, or ones_a if ones_a is even.
    // Or simply, if ones_a is odd, we can make it even by adding one '1'.
    // So, the effective maximum ones in 'a' that can be used to form 'b' is:
    // If ones_a is odd, we can make it even by appending a '1'. So, max_ones_a_effective = ones_a + 1.
    // If ones_a is even, we can only append '0's to maintain even parity, or if we append '1's,
    // it means we started with odd parity.
    // The crucial point is that if we have an odd number of ones, we can always append a '1' to make it even.
    // If we have an even number of ones, we append a '0', keeping it even.
    // So, if we start with an odd number of ones, we can effectively have one more '1' available for matching.
    // This means the total number of '1's we can "generate" from `a` is `ones_a` if `ones_a` is even,
    // and `ones_a + 1` if `ones_a` is odd.
    // Let's call this `max_ones_from_a`.

    int max_ones_from_a = ones_a;
    if (ones_a % 2 != 0) { // If initial ones_a is odd
        max_ones_from_a++; // We can append a '1' to make it even
    }

    // Now we compare max_ones_from_a with ones_b.
    // If max_ones_from_a is less than ones_b, it's impossible.
    // Also, the length of 'a' must be at least the length of 'b' after some operations.
    // We can always remove characters from the front of 'a'.
    // We can append characters to 'a' until its length is |b|.
    // The number of characters we can append is |b| - |a|.
    // If |a| > |b|, we don't need to append, we just remove from front.
    // If |a| < |b|, we need to append |b| - |a| characters.
    // The maximum number of ones we can have in 'a' (after appends) is `max_ones_from_a`.
    // This `max_ones_from_a` must be greater than or equal to `ones_b`.
    // Also, `max_ones_from_a` and `ones_b` must have the same parity.
    // This is because appending a parity always results in an even number of ones.
    // If `ones_a` is odd, we append '1', `ones_a` becomes `ones_a + 1` (even).
    // If `ones_a` is even, we append '0', `ones_a` remains `ones_a` (even).
    // So, any string `a'` formed by appending parities to `a` will have an even number of ones,
    // *if* `a` itself had an even number of ones, or if `a` had an odd number of ones and we appended one '1'.
    // The only way to get an odd number of ones in `a'` is if `a` had an odd number of ones, and we didn't append anything.
    // But we can always append.
    // The logic is:
    // 1. We need `ones_b` ones.
    // 2. We have `ones_a` ones initially.
    // 3. If `ones_a` is odd, we can append a '1' to make it `ones_a + 1` (even).
    // 4. If `ones_a` is even, we append a '0' to keep it `ones_a` (even).
    // So, the effective number of ones we can achieve in `a` (which will be used to match `b`) is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This value must be >= `ones_b`.

    if (max_ones_from_a >= ones_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The previous element in the non-decreasing array
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long lower_bound_b = prev_b;

        // Case 1: current_a >= lower_bound_b
        // We need to find b_i such that b_i >= lower_bound_b.
        // The smallest possible b_i is current_a.
        // If current_a >= lower_bound_b, we can potentially set b_i = current_a.
        // This requires 0 operations on a_i.
        // If current_a < lower_bound_b, we must increment a_i.
        // The smallest b_i we can achieve is current_a + k_i.
        // We need current_a + k_i >= lower_bound_b.
        // So k_i >= lower_bound_b - current_a.
        // If current_a + x < lower_bound_b, then it's impossible to make b_i >= lower_bound_b
        // using at most x operations.

        // If a[i] is already >= prev_b, we can potentially keep a[i] as b[i].
        // This requires 0 operations on a[i].
        // We can also increment a[i] up to a[i] + x.
        // If a[i] + x < prev_b, this means we cannot make a[i] >= prev_b by incrementing.
        // This case is impossible if a[i] >= prev_b.
        // So if a[i] >= prev_b, we can always set b[i] = a[i] and prev_b remains a[i].
        // The only constraint is that if a[i] + x < m and a[i] < prev_b, this path is not taken.

        // Let's consider the value `b_i` we want to achieve.
        // `b_i` must be `(a_i + k_i) % m` where `0 <= k_i <= x`.
        // Also, `b_i >= prev_b`.

        // Option 1: Don't increment a_i "across the m boundary".
        // We want `a_i + k_i >= prev_b`.
        // If `a_i >= prev_b`, we can choose `k_i = 0`, so `b_i = a_i`. This is valid.
        // If `a_i < prev_b`:
        // We need `a_i + k_i >= prev_b`.
        // The minimum `k_i` is `prev_b - a_i`.
        // If `prev_b - a_i <= x`, then we can achieve `b_i = prev_b` by incrementing `a_i` by `prev_b - a_i`.
        // In this case, we set `prev_b = prev_b`.
        // If `prev_b - a_i > x`, then we cannot achieve `b_i = prev_b` by incrementing `a_i` without crossing `m`.
        // So this option fails.

        // Option 2: Increment a_i "across the m boundary".
        // This means `a_i + k_i` becomes `(a_i + k_i) % m`.
        // The value `a_i + k_i` effectively becomes `a_i + k_i - m` if `a_i + k_i >= m`.
        // The smallest value `b_i` can take is `0` (by incrementing `a_i` by `m - a_i` if `a_i != 0`).
        // If we increment `a_i` by `k_i`, the new value is `(a_i + k_i) % m`.
        // We need `(a_i + k_i) % m >= prev_b`.
        // And `k_i <= x`.

        // Let's simplify. We need to find `b_i` such that:
        // 1. `b_i >= prev_b`
        // 2. `b_i = (a_i + k_i) % m` for some `0 <= k_i <= x`.

        // Consider the range of values `a_i` can become:
        // `[a_i, (a_i + x) % m]` if `a_i + x < m` (no wrap-around)
        // `[a_i, m-1] U [0, (a_i + x) % m]` if `a_i + x >= m` (wrap-around)

        // If `a_i >= prev_b`:
        // We can choose `b_i = a_i` (0 operations). This satisfies `b_i >= prev_b`.
        // We can also choose `b_i = prev_b` if `prev_b` is reachable from `a_i` with `k_i <= x`.
        // If `a_i >= prev_b`, we can always set `b_i = a_i`. This requires 0 operations.
        // The only time we might need to increment `a_i` is if `a_i` is too large,
        // but we want to keep `b_i` as small as possible to allow more room for `b_{i+1}`.
        // So if `a_i >= prev_b`, we check if `a_i + x >= m` and `(a_i + x) % m < prev_b`.
        // This means we can increment `a_i` to `(a_i + x) % m`, but this value is too small.
        // In this case, we must keep `b_i = a_i`.
        // Otherwise, if `a_i + x < m` or `(a_i + x) % m >= prev_b`, we can potentially set `b_i = prev_b`.
        // This is only possible if `prev_b` is reachable from `a_i` with `k_i <= x`.
        // If `a_i >= prev_b`, then `prev_b` is reachable from `a_i` if `prev_b >= a_i` (which is false)
        // or if `prev_b` is reachable by wrapping around.
        // The values reachable from `a_i` are `(a_i + k) % m` for `0 <= k <= x`.
        // If `a_i >= prev_b`:
        // We can choose `b_i = a_i`. This is valid.
        // We can also choose `b_i = prev_b` if `prev_b` is reachable from `a_i` by incrementing.
        // This means `(a_i + k) % m = prev_b` for some `k <= x`.
        // If `a_i <= prev_b`, then `k = prev_b - a_i`. If `k <= x`, we can set `b_i = prev_b`.
        // If `a_i > prev_b`, then `k = m - a_i + prev_b`. If `k <= x`, we can set `b_i = prev_b`.
        // We want to keep `b_i` as small as possible, so if `prev_b` is reachable, we prefer `prev_b`.
        // So if `a_i >= prev_b`:
        //   If `a_i + x < m`:
        //     `b_i` can be `a_i` or anything up to `a_i + x`.
        //     Since `a_i >= prev_b`, we can set `b_i = a_i`.
        //     We don't need to check `prev_b` here.
        //   If `a_i + x >= m`: (wrap-around possible)
        //     The values reachable are `[a_i, m-1]` and `[0, (a_i + x) % m]`.
        //     If `(a_i + x) % m < prev_b`, it means even with max increments, we can't reach `prev_b` by wrapping around.
        //     So we must use `a_i` (or something larger than `a_i` but less than `m`).
        //     In this case, we set `prev_b = a_i`.
        //     Otherwise, if `(a_i + x) % m >= prev_b`, it means we can reach `prev_b` by wrapping around.
        //     So we can set `prev_b = prev_b`.
        // This logic is getting complicated. Let's simplify.

        // We need to find `b_i` such that `b_i >= prev_b` and `b_i` is reachable from `a_i` with at most `x` operations.
        // A value `val` is reachable from `a_i` with at most `x` operations if:
        // 1. `val >= a_i` and `val - a_i <= x` (no wrap-around)
        // 2. `val < a_i` and `m - a_i + val <= x` (wrap-around)

        // If `a_i >= prev_b`:
        // We can potentially set `b_i = a_i`. This requires 0 operations.
        // This is always a valid choice for `b_i` in terms of `b_i >= prev_b`.
        // However, we want to keep `b_i` as small as possible.
        // Can we set `b_i = prev_b`?
        // This is possible if `prev_b` is reachable from `a_i` with `k_i <= x`.
        // If `prev_b >= a_i` (which is not the case here, `a_i >= prev_b`), `k_i = prev_b - a_i`.
        // If `prev_b < a_i`, `k_i = m - a_i + prev_b`.
        // If `m - a_i + prev_b <= x`, then `prev_b` is reachable by wrapping around.
        // In this case, we can set `b_i = prev_b`.
        // Otherwise, `prev_b` is not reachable by wrapping around.
        // So we must set `b_i = a_i`.
        // So, if `a_i >= prev_b`:
        //   If `m - a_i + prev_b <= x`: (can reach `prev_b` by wrapping)
        //     `prev_b` remains `prev_b`.
        //   Else: (cannot reach `prev_b` by wrapping)
        //     `prev_b` becomes `a_i`.
        // This covers the case `a_i >= prev_b`.

        // If `a_i < prev_b`:
        // We must increment `a_i`.
        // Can we reach `prev_b` without wrapping around?
        // This means `prev_b - a_i <= x`.
        // If `prev_b - a_i <= x`:
        //   We can set `b_i = prev_b`. `prev_b` remains `prev_b`.
        // Else (`prev_b - a_i > x`):
        //   We cannot reach `prev_b` without wrapping around.
        //   Can we reach `prev_b` by wrapping around?
        //   This would mean `m - a_i + prev_b <= x`.
        //   But `prev_b - a_i > x` implies `prev_b > a_i + x`.
        //   And `m - a_i + prev_b` is even larger.
        //   So if `prev_b - a_i > x`, it's impossible to reach `prev_b` at all.
        //   Thus, this `x` is not enough. Return `false`.

        // Combining these:
        if (current_a >= lower_bound_b) {
            // Option 1: Set b_i = current_a. This is valid.
            // Option 2: Set b_i = lower_bound_b. This is valid if lower_bound_b is reachable from current_a.
            // lower_bound_b is reachable from current_a if `m - current_a + lower_bound_b <= x`.
            // We want to keep b_i as small as possible, so if Option 2 is possible, we take it.
            if (m - current_a + lower_bound_b <= x) {
                // We can make b_i = lower_bound_b by wrapping around.
                // prev_b remains lower_bound_b.
            } else {
                // We cannot make b_i = lower_bound_b by wrapping around.
                // So we must make b_i = current_a (or something larger, but current_a is smallest valid).
                prev_b = current_a;
            }
        } else { // current_a < lower_bound_b
            // We must increment current_a.
            // We need to reach at least lower_bound_b.
            // The number of increments needed to reach lower_bound_b without wrapping is `lower_bound_b - current_a`.
            if (lower_bound_b - current_a <= x) {
                // We can make b_i = lower_bound_b without wrapping.
                // prev_b remains lower_bound_b.
            } else {
                // We cannot reach lower_bound_b without wrapping.
                // And we cannot reach lower_bound_b by wrapping either, because `current_a + x` would be less than `lower_bound_b`.
                // (i.e., `current_a + x < lower_bound_b` implies `current_a + x` is not `m` or more, so no wrap-around to `0` or small values).
                // If `current_a + x < lower_bound_b`, then `(current_a + k) % m` for `k <= x` will always be `< lower_bound_b`.
                // So it's impossible.
                return false;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations needed is m-1 (e.g., 0 -> m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_list;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_list.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_list.empty()) {
        Child current_child = children_list.front();
        children_list.pop_front();
        cured_children_indices.push_back(current_child.original_idx);

        long long current_v_cry = current_child.v;
        long long total_d_cry_effect = 0;

        // Apply current_v_cry and total_d_cry_effect to remaining children
        // and handle chain reactions

        // Use a temporary list to store children that need to be removed
        // and to collect their d_cry values.
        std::list<std::list<Child>::iterator> to_remove_iterators;

        for (auto it = children_list.begin(); it != children_list.end(); ++it) {
            // Apply v_cry effect
            if (current_v_cry > 0) {
                it->p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry effect
            it->p -= total_d_cry_effect;

            if (it->p < 0) {
                to_remove_iterators.push_back(it);
            }
        }

        // Process children who need to be removed due to p < 0
        // This loop might need to run multiple times if new d_cries cause more children to leave.
        // However, the problem statement implies that all d_cries from a single "wave"
        // are applied to *all* subsequent children.
        // A simpler approach is to collect all d_cries from children leaving in this wave
        // and apply them to the remaining children.
        // The problem states "All these events occur immediately one after the other in some order.
        // Some cries may lead to other cries, causing a chain reaction."
        // This suggests an iterative process for d_cries.

        // Let's re-evaluate the chain reaction.
        // When child i goes, v_i affects children j, j+1, ...
        // Then, if child k's p < 0, they cry d_k. This d_k affects children k+1, k+2, ...
        // If child m's p < 0 due to d_k, they cry d_m. This d_m affects children m+1, m+2, ...
        // This means d_cries are applied sequentially based on their position in the line.

        // Reset current_v_cry for the next pass, as it's only for the first child's cry.
        // The d_cry chain reaction needs to be handled carefully.

        // The most straightforward way to handle the chain reaction is to iterate through the list
        // and apply effects. If a child leaves, add its d_cry to a running total that affects
        // subsequent children.

        long long current_d_cry_sum = 0; // Sum of d_cries from children who left in this step

        // Iterate through the list, applying effects and checking for removals
        // This loop needs to be robust against iterator invalidation if we remove elements directly.
        // Using a list allows efficient removal.

        auto it = children_list.begin();
        while (it != children_list.end()) {
            // Apply the accumulated d_cry from previous children who left in this wave
            it->p -= current_d_cry_sum;

            if (it->p < 0) {
                current_d_cry_sum += it->d; // Add this child's d_cry to the sum for subsequent children
                it = children_list.erase(it); // Remove child and advance iterator
            } else {
                ++it; // Move to the next child
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition elements such that a_0 and a_1 are in different subsequences.
    // This implies a_0 is in subseq 1, a_1 is in subseq 2.
    // To minimize max_f, we want to put a_0 and a_1 in different subsequences.
    // To minimize min_f, we want to put a_0 and a_1 in different subsequences.
    //
    // Consider a partition where elements[0] is in subseq 1, and elements[1] is in subseq 2.
    // All other elements (elements[2] to elements[n-1]) can be put into subseq 2.
    //
    // Values of f:
    // 1. (elements[0] + elements[k]) + h for k >= 1
    // 2. (elements[j] + elements[k]) for j, k >= 1, j != k
    //
    // min_f:
    //   - If n=2: only (elements[0] + elements[1]) + h. min_f = max_f = (elements[0] + elements[1]) + h. Goodness = 0.
    //   - If n > 2:
    //     - (elements[0] + elements[1]) + h (different subsequences)
    //     - (elements[1] + elements[2]) (same subsequence, if elements[2] is in subseq 2)
    //     min_f = min((elements[0].value + elements[1].value + h), (elements[1].value + elements[2].value))
    //
    // max_f:
    //   - (elements[0] + elements[n-1]) + h (different subsequences)
    //   - (elements[n-2] + elements[n-1]) (same subsequence)
    //   max_f = max((elements[0].value + elements[n-1].value + h), (elements[n-2].value + elements[n-1].value))
    //
    // Goodness = max_f - min_f

    long long goodness2;
    std::vector<int> partition2(n);

    // Assign elements[0] to subseq 1, elements[1] to subseq 2.
    // For elements[2] to elements[n-1], assign them to subseq 2.
    // This makes subseq 1 = {elements[0]}, subseq 2 = {elements[1], elements[2], ..., elements[n-1]}

    long long current_min_f;
    long long current_max_f;

    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
        current_max_f = elements[0].value + elements[1].value + h;
    } else {
        current_min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        current_max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    }
    goodness2 = current_max_f - current_min_f;

    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut
    // Try all possible cut positions
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts
    // This means we have 3 pieces.
    // The problem statement implies that if k=1 doesn't work,
    // we should check k=2.
    // The only way to get a new palindrome with 2 cuts (3 pieces)
    // that is not achievable with 1 cut is if the string is of the form
    // A B A (where A is a palindrome) and we can rearrange to A B A.
    // Or more generally, if we can swap outer parts.
    //
    // Consider the structure of the original palindrome s.
    // If s consists of only one distinct character (e.g., "aaaaa"),
    // then any rearrangement of its substrings will result in the same string,
    // which is also a palindrome. In this case, it's impossible to get a new string.
    //
    // If s has at least two distinct characters, and it's a palindrome,
    // then we can always achieve a new palindrome with 2 cuts.
    // Example: "nolon" -> "no|l|on" -> "on|l|no"
    // Example: "abacaba" -> "aba|c|aba" -> "aba|c|aba" (no change)
    // But if we cut "abacaba" as "a|bacab|a", we can't rearrange to a new palindrome.
    //
    // Let's re-evaluate the k=2 case.
    // If the string is not all same characters, and it's a palindrome,
    // can we always make a new palindrome with 2 cuts?
    //
    // Consider the string s. If all characters are the same, e.g., "qqqq",
    // then any permutation of its substrings will result in "qqqq".
    // In this case, it's impossible.
