// Using long long for y to prevent overflow
// Using int for x and array indices as n <= 2e5
// a_i can be up to 10^9, so sums can exceed 32-bit int.

struct Result {
    long long y_val;
    int final_x;
    bool terminates;
};

// Memoization table for (x, parity)
// parity 0: just finished step 3, about to start step 2
// parity 1: just finished step 2, about to start step 3
std::vector<std::vector<Result>> memo;
std::vector<std::vector<bool>> visited;
std::vector<int> a_values;
int N;

Result solve(int current_x, int parity) {
    if (current_x <= 0 || current_x > N) {
        return {0, current_x, true}; // Base case: terminated
    }

    if (visited[current_x][parity]) {
        // Cycle detected, or already computed
        if (memo[current_x][parity].terminates) {
            return memo[current_x][parity]; // Already computed and terminates
        } else {
            return {0, 0, false}; // Cycle detected, does not terminate
        }
    }

    visited[current_x][parity] = true;
    memo[current_x][parity].terminates = false; // Mark as potentially non-terminating (in a cycle)

    long long val = a_values[current_x];
    Result next_res;

    if (parity == 0) { // About to perform step 2
        int next_x = current_x + val;
        next_res = solve(next_x, 1); // Next state: (next_x, parity 1)
        if (!next_res.terminates) {
            return {0, 0, false}; // Propagate non-termination
        }
        memo[current_x][parity] = {val + next_res.y_val, next_res.final_x, true};
    } else { // parity == 1, About to perform step 3
        int next_x = current_x - val;
        next_res = solve(next_x, 0); // Next state: (next_x, parity 0)
        if (!next_res.terminates) {
            return {0, 0, false}; // Propagate non-termination
        }
        memo[current_x][parity] = {val + next_res.y_val, next_res.final_x, true};
    }

    return memo[current_x][parity];
}

