void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed pile_index
        int haybales_in_pile = a[i];
        int cost_per_haybale = pile_index; // Cost to move to pile 0 (1-indexed pile 1)

        if (haybales_in_pile == 0) {
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining_days and cost_per_haybale
        long long max_movable_from_this_pile = remaining_days / cost_per_haybale;

        long long haybales_to_move = std::min((long long)haybales_in_pile, max_movable_from_this_pile);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

