int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] is the largest element (n),
        // then a[i][j] = min(n, p[j]) = p[j] for all j != i.
        // So max_val_in_row would be max(p[j] for j != i), which is n-1.
        // In this case, p[i] should be n.
        // For any other p[i] < n, max_val_in_row will be p[i] itself.
        // This is because there must be some p[k] > p[i] (since p[i] < n).
        // For such k, a[i][k] = min(p[i], p[k]) = p[i].
        // And for any p[j] < p[i], a[i][j] = min(p[i], p[j]) = p[j] < p[i].
        // So the maximum value in row i (excluding a[i][i]) will be p[i].
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

