    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders, 'mid' mathematicians, and 'mid' other students.
            // Available coders for the 'mid' required slots: c
            // Available mathematicians for the 'mid' required slots: m
            // Available flexible students for the 'mid' other slots: (c - mid) + (m - mid) + x
            // This simplifies to c + m + x - 2 * mid.
            // We need 'mid' flexible students, so:
            // mid <= c + m + x - 2 * mid
            // 3 * mid <= c + m + x
            // mid <= (c + m + x) / 3
            // This condition is already covered by the 'high' initialization.

            // The critical part is that we must have enough coders and mathematicians
            // to satisfy the "at least one" requirement for each of the 'mid' teams.
            // So, c >= mid and m >= mid.
            // These are also covered by the 'high' initialization.

            // The remaining students after assigning one coder and one mathematician to each of the 'mid' teams are:
            // c_rem = c - mid
            // m_rem = m - mid
            // x_rem = x
            // Total remaining students: c_rem + m_rem + x_rem = (c - mid) + (m - mid) + x = c + m + x - 2 * mid
            // These remaining students must fill the 'mid' third slots in the teams.
            // So, we need to check if (c + m + x - 2 * mid) >= mid.
            if (c >= mid && m >= mid && (c + m + x - 2 * mid) >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

