        long long current_staircase_cost = 1; // Cost for k=1 (n=1) staircase
        while (x >= current_staircase_cost) {
            x -= current_staircase_cost;
            count++;
            current_staircase_cost = current_staircase_cost * 4 + 1;
        }
        std::cout << count << "\n";
    }
    return 0;
}

