        // The area of the triangle from the apex to the i-th cut
        // should be i times the area of one piece.
        // Total area of carrot = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area from apex to i-th cut = i * (h / (2n)).
        // Let x_i be the distance of the i-th cut from the apex.
        // Area from apex to x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
