int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a = (d + sqrt(d^2 - 4d)) / 2
            // For b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa. Since a and b are symmetric, the order doesn't matter.
            // We need d^2 - 4d >= 0 for real solutions.
            // d(d-4) >= 0. Since d >= 0, this means d-4 >= 0, so d >= 4.
            // If d = 0, d^2 - 4d = 0, a = 0, b = 0. This is handled by the d == 0 case.
            // If d >= 4, then d^2 - 4d >= 0.

            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

