#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // starting from a_1 = 0, a_2 = 1, ...
    // For each a[i], it must be at least i to maintain a_i >= i.
    // If a[i] < i, then we cannot make a strictly increasing prefix of length i+1.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // ending with a_n = 0, a_{n-1} = 1, ...
    // For each a[i], it must be at least (n-1-i) to maintain a_i >= (n-1-i).
    // If a[i] < (n-1-i), then we cannot make a strictly decreasing suffix of length (n-i).
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of the potential increasing prefix and decreasing suffix
    // is greater than or equal to n, it means there's an overlap or they meet.
    // This implies there's at least one 'k' where a peak can be formed.
    // For example, if left_len = 3 and right_len = 2 for n=3,
    // it means a[0]>=0, a[1]>=1, a[2]>=2 (left_len=3)
    // and a[2]>=0, a[1]>=1 (right_len=2)
    // The condition left_len + right_len > n is equivalent to left_len >= n - right_len + 1.
    // This means the index `left_len - 1` (0-indexed) is less than or equal to
    // the index `n - right_len` (0-indexed).
    // In other words, the potential peak index from the left (left_len-1)
    // is not to the right of the potential peak index from the right (n-right_len).
    // If left_len + right_len > n, there is at least one index `k` (1-indexed)
    // such that `a_k` can be the peak.
    // The indices that can be a peak are `i` such that `a[i] >= i` and `a[i] >= n-1-i`.
    // The range of such `i` is `[0, left_len-1]` from the left and `[n-right_len, n-1]` from the right.
    // If these ranges overlap or touch, i.e., `left_len-1 >= n-right_len`,
    // which simplifies to `left_len + right_len >= n+1`, then a peak can be found.
    // The problem statement says "any strictly increasing or strictly decreasing array is sharpened".
    // This means k=n (strictly increasing) or k=1 (strictly decreasing) are allowed.
    // If left_len == n, it means a[i] >= i for all i. We can make it 0,1,2,...,n-1. This is sharpened.
    // If right_len == n, it means a[i] >= n-1-i for all i. We can make it n-1,n-2,...,0. This is sharpened.
    // Both these cases are covered by left_len + right_len > n.
    // For example, if n=3, left_len=3, right_len=3. 3+3 > 3. Yes.
    // If n=3, left_len=2, right_len=2. 2+2 > 3. Yes. (e.g., a=[0,1,0])
    // If n=4, left_len=2, right_len=2. 2+2 > 4 is false. 2+2=4. No. (e.g., a=[0,1,1,0])
    // The condition is `left_len + right_len > n`.
    // This is because if `left_len + right_len == n`, it means the "potential peak" indices
    // are `left_len-1` and `n-right_len`. If `left_len + right_len == n`, then `left_len-1 = n-right_len-1`.
    // This means the two ranges meet at `left_len-1` and `n-right_len` are adjacent, not overlapping.
    // For example, if n=4, left_len=2, right_len=2.
    // Left part can be `a[0]>=0, a[1]>=1`. Max peak index is 1.
    // Right part can be `a[2]>=1, a[3]>=0`. Min peak index is 2.
    // We need `a_k` to be part of both. So `k` must be in `[0, left_len-1]` AND `[n-right_len, n-1]`.
    // This means `left_len-1 >= n-right_len`.
    // `left_len + right_len >= n+1`.
    // So, `left_len + right_len > n` is the correct condition.

    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

