    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on value
    // If values are equal, original_index can be used for stable sort, but not critical here.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value should be paired with the i-th largest B value.
        // The original_index of b_elements[i] tells us where this B value was originally.
        // This is the position in the output array result_a where a_elements[i].value should go.
        result_a[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

