int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it will interact with all 'b's to its right.
            // Each 'b' to its right will cause one 'ab' -> 'bba' operation.
            // The 'a' itself will move past all these 'b's.
            // The number of steps for this 'a' is equal to the current b_count.
            total_steps = (total_steps + b_count) % MOD;

            // After this 'a' moves past all 'b's, it effectively becomes 'b's.
            // Specifically, for each 'b' it moved past, it generated a new 'b'.
            // So, the number of 'b's to its right effectively doubles for future 'a's.
            // The 'a' itself is consumed in this process (it's now to the right of all 'b's).
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

