// Function to convert a number to its parity pattern string
// The pattern will always have 18 characters, padded with '0's from the left
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding with '0's from the left for the number
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the right to make it 18 characters long
            // This corresponds to padding with '0's from the left for the pattern
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is a definite constraint.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it matches the rule based on our candidate w.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch found:
            // If s[i] is '1' but our w implies s[i] should be '0', then no such w exists.
            // (Because we initialized w[j] to '1' unless forced to '0',
            // if s[i] is '1' and we can't make it '1', it's impossible.)
            // If s[i] is '0' but our w implies s[i] should be '1', then our w is wrong.
            // (This case should not happen if our logic for setting w[j] to '0' is correct,
            // as s[i]=='0' implies w[i-x] and w[i+x] are '0', which would make s_i_should_be_1 false.)
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

