#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (k)
    // k items from left means n-k items from right
    for (int k = 0; k <= n; ++k) {
        long long current_energy = 0;

        // Energy for items taken from left
        // Sum of w[0]...w[k-1]
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from right
        // Sum of w[k]...w[n-1] (which are n-k items)
        current_energy += (prefix_sum[n] - prefix_sum[k]) * r;

        // Add penalty for consecutive actions
        int left_count = k;
        int right_count = n - k;

        if (left_count > right_count) {
            // More items taken from left.
            // The last item taken must have been from the left.
            // The number of "extra" left items is (left_count - right_count - 1).
            // Each of these extra items incurs a Ql penalty.
            // This happens if left_count >= right_count + 1.
            // If left_count == right_count + 1, no penalty.
            // If left_count == right_count + 2, one penalty.
            // So, (left_count - right_count - 1) penalties.
            current_energy += std::max(0, left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right.
            // The last item taken must have been from the right.
            // The number of "extra" right items is (right_count - left_count - 1).
            // Each of these extra items incurs a Qr penalty.
            // This happens if right_count >= left_count + 1.
            // If right_count == left_count + 1, no penalty.
            // If right_count == left_count + 2, one penalty.
            // So, (right_count - left_count - 1) penalties.
            current_energy += std::max(0, right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

