#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long get_power(long long n, long long r) {
    if (r == 0) return 0; // Should not happen with q >= 2
    long long count = 0;
    while (n > 0 && n % r == 0) {
        count++;
        n /= r;
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p such that x is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.

        // Find prime factors of q
        std::vector<long long> q_prime_factors;
        long long temp_q = q;
        for (long long i = 2; i * i <= temp_q; ++i) {
            if (temp_q % i == 0) {
                q_prime_factors.push_back(i);
                while (temp_q % i == 0) {
                    temp_q /= i;
                }
            }
        }
        if (temp_q > 1) {
            q_prime_factors.push_back(temp_q);
        }

        long long max_x = 1;

        for (long long r : q_prime_factors) {
            // For each prime factor r of q, we want to find the largest divisor of p
            // that is not divisible by q, by reducing the power of r in p.

            // Calculate the power of r in p
            long long p_val = p;
            long long p_r_power = 0;
            while (p_val > 0 && p_val % r == 0) {
                p_r_power++;
                p_val /= r;
            }

            // Calculate the power of r in q
            long long q_val = q;
            long long q_r_power = 0;
            while (q_val > 0 && q_val % r == 0) {
                q_r_power++;
                q_val /= r;
            }

            // We need to reduce the power of r in p by at least (q_r_power - 1)
            // to make x not divisible by q (specifically, not divisible by r^(q_r_power)).
            // The largest x will be p / r^(q_r_power - 1 + 1) = p / r^(q_r_power)
            // No, this is wrong. We need to make sure x is not divisible by q.
            // If x is divisible by q, then for every prime factor r of q,
            // the power of r in x must be >= the power of r in q.
            // To make x not divisible by q, we need to find *some* prime factor r of q
            // such that the power of r in x is < the power of r in q.
            // To maximize x, we should pick the r that requires the smallest reduction.

            // For a specific prime factor r of q, we want to find the largest divisor of p
            // that has a power of r less than q_r_power.
            // This means we must divide p by r at least (p_r_power - (q_r_power - 1)) times.
            // Which simplifies to dividing p by r^(p_r_power - q_r_power + 1).
            // Let's call this candidate x_r = p / r^(p_r_power - q_r_power + 1).
            // This x_r is guaranteed to have power of r equal to q_r_power - 1,
            // thus x_r is not divisible by q (because it's not divisible by r^(q_r_power)).

            long long current_x_candidate = p;
            for (int i = 0; i < p_r_power - q_r_power + 1; ++i) {
                current_x_candidate /= r;
            }
            max_x = std::max(max_x, current_x_candidate);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int x = 0; x <= 9; ++x) {
        std::string colors(n, ' ');
        char last1 = '0' - 1; // Sentinel for the last digit in S1
        char last2 = '0' - 1; // Sentinel for the last digit in S2
        bool possible_x = true;

        // First pass: assign digits < x to color 1, digits > x to color 2
        // Digits == x are temporarily unassigned (marked with '0')
        for (int i = 0; i < n; ++i) {
            if (s[i] < (char)('0' + x)) {
                colors[i] = '1';
                if (s[i] < last1) { // S1 must be non-decreasing
                    possible_x = false;
                    break;
                }
                last1 = s[i];
            } else if (s[i] > (char)('0' + x)) {
                colors[i] = '2';
                if (s[i] < last2) { // S2 must be non-decreasing
                    possible_x = false;
                    break;
                }
                last2 = s[i];
            } else { // s[i] == x
                colors[i] = '0'; // Mark as unassigned for now
            }
        }

        if (!possible_x) {
            continue;
        }

        // Second pass: assign digits == x
        // Digits == x that appear before any digit > x must be color 1
        // Digits == x that appear after any digit > x must be color 2
        // This is equivalent to finding the first occurrence of a digit > x.
        // All 'x's before that index go to color 1, all 'x's after go to color 2.
        // If no digit > x, all 'x's go to color 1.

        // Find the first index `k` such that s[k] > x.
        // All s[i] == x for i < k must be color 1.
        // All s[i] == x for i >= k must be color 2.
        int k = n;
        for (int i = 0; i < n; ++i) {
            if (s[i] > (char)('0' + x)) {
                k = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            if (colors[i] == '0') { // This digit is 'x'
                if (i < k) {
                    colors[i] = '1';
                    if (s[i] < last1) { // Should not happen if last1 is correctly updated
                        possible_x = false;
                        break;
                    }
                    last1 = s[i];
                } else {
                    colors[i] = '2';
                    if (s[i] < last2) { // Should not happen if last2 is correctly updated
                        possible_x = false;
                        break;
                    }
                    last2 = s[i];
                }
            }
        }

        if (!possible_x) {
            continue;
        }

        // Final check: last digit of S1 <= first digit of S2
        // This is implicitly handled by the construction.
        // All digits assigned '1' are <= x. All digits assigned '2' are >= x.
        // So, last1 <= x and first2 >= x. Thus last1 <= first2.
        // The only edge case is if S1 or S2 is empty.
        // If S1 is empty, last1 remains '0'-1. If S2 is empty, first2 is not defined.
        // But the condition is "last digit of S1 must be less than or equal to the first digit of S2".
        // If S1 is empty, there is no last digit. If S2 is empty, there is no first digit.
        // The overall sequence is non-decreasing if S1 and S2 are individually non-decreasing.
        // The construction ensures that all '1's are <= x and all '2's are >= x.
        // So, if S1 is non-empty and S2 is non-empty, last1 will be x and first2 will be x, or last1 < x and first2 >= x, or last1 <= x and first2 > x.
        // In all cases, last1 <= first2.
        // The only way this could fail is if last1 > first2, which is impossible by construction.

        std::cout << colors << "\n";
        return;
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

