    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.
    sum_r_term = (sum_r_term * b) / 2;
    sum_r_term %= MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is (b * sum_{k=1 to a} k) + (sum_{k=1 to a} 1)
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a

    long long sum_k_val = (a * (a + 1)) / 2;
    sum_k_val %= MOD;

    long long sum_k_term = (b % MOD * sum_k_val) % MOD;
    sum_k_term = (sum_k_term + a % MOD) % MOD;

    // Total sum = (sum_k_term) * (sum_r_term)
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            adj[s[i] - 'a'].insert(s[i+1]);
            adj[s[i+1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i] && adj[i].size() <= 1) { // Start of a path or isolated char in s
            char current_char = 'a' + i;

            // Traverse forward
            while (true) {
                if (visited[current_char - 'a']) {
                    // This means we found a cycle or a character already part of another path.
                    // Since we only start traversal from nodes with degree <= 1,
                    // this implies a cycle if degree is 2, or a conflict if degree is 1.
                    // For a valid path, we should not encounter an already visited node unless it's the start of the path.
                    // But we are building a path, so if we hit a visited node, it means it's already part of a path.
                    // This can only happen if the graph contains a cycle, which is invalid for a linear keyboard.
                    // Or if a character with degree 2 was already visited, meaning it was part of a path started from another end.
                    // This check is implicitly handled by the degree check and the fact that we only start from degree <= 1.
                    // If a character has degree 2 and is visited, it means it's part of a path.
                    // If we reach it again, it means there's a cycle.
                    // Example: a-b-c-a. If we start at 'a', go to 'b', then 'c', then 'a' again.
                    // This is caught by adj[i].size() > 2 check if 'a' has 3 neighbors.
                    // If 'a' has 2 neighbors (b,c), and b has 2 (a,d), c has 2 (a,e), then a-b-d and a-c-e are two paths.
                    // If a-b-c-a, then 'a' has neighbors 'b' and 'c'. 'b' has 'a' and 'c'. 'c' has 'a' and 'b'.
                    // All have degree 2. If we start from 'a', add 'a', then 'b', then 'c'.
                    // From 'c', next is 'a'. If 'a' is visited, it's a cycle.
                    // This is the critical check for cycles.
                    bool is_cycle = false;
                    if (adj[current_char - 'a'].size() == 2) { // If degree 2, it must be a cycle
                        is_cycle = true;
                    }
                    if (is_cycle) {
                        std::cout << "NO\n";
                        return;
                    }
                    break; // End of path
                }
                visited[current_char - 'a'] = true;
                layout += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                if (next_char == 0) { // No unvisited neighbors
                    break;
                }
                current_char = next_char;
            }
        }
    }

    // Check for cycles among characters with degree 2 that were not visited
    // This happens if the graph contains a cycle where all nodes have degree 2.
    // E.g., a-b-c-a. All nodes have degree 2. Our loop above only starts from degree <= 1.
    // So, if such a cycle exists, it won't be processed.
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in 's' or not part of any required adjacency
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

