#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long X, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The smallest possible value for b_i, given b_{i-1}
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a_i + X < m. The possible values for b_i are [a_i, a_i + X].
        // We need b_i >= prev_b.
        // If a_i + X < prev_b, it's impossible to satisfy b_i >= prev_b.
        // Otherwise, we can choose b_i = max(a_i, prev_b).
        if (current_a + X < m) {
            if (current_a + X < prev_b) {
                return false; // Cannot make b_i >= prev_b
            }
            // We can choose b_i = max(a_i, prev_b).
            // The smallest possible value for b_i is max(a_i, prev_b).
            // This value is valid because max(a_i, prev_b) <= a_i + X.
            // If prev_b <= a_i, then a_i is chosen. a_i <= a_i + X.
            // If prev_b > a_i, then prev_b is chosen. prev_b <= a_i + X.
            prev_b = std::max(current_a, prev_b);
        }
        // Case 2: a_i + X >= m. The possible values for b_i are [a_i, m-1] U [0, (a_i + X) % m].
        // This means b_i can be any value in [0, m-1] except for values in ((a_i + X) % m, a_i).
        // Let's call the upper bound (a_i + X) % m as `upper_bound`.
        // The forbidden range is (upper_bound, a_i).
        else { // current_a + X >= m
            long long upper_bound = (current_a + X) % m;

            // We need to find b_i such that b_i >= prev_b and b_i is allowed.
            // If prev_b <= upper_bound:
            //   We can choose b_i = prev_b. This is allowed because prev_b is not in (upper_bound, a_i)
            //   (since prev_b <= upper_bound).
            //   So, the smallest possible b_i is prev_b.
            // If prev_b > upper_bound:
            //   This means prev_b is in the range (upper_bound, m-1].
            //   If prev_b is also in the forbidden range (upper_bound, a_i),
            //   then we must choose b_i >= a_i.
            //   If prev_b >= a_i, then we can choose b_i = prev_b. This is allowed.
            //   If prev_b < a_i, then prev_b is in (upper_bound, a_i). This is the forbidden range.
            //   In this case, we must choose b_i >= a_i. The smallest such b_i is a_i.
            //   This is allowed because a_i is not in the forbidden range (upper_bound, a_i).
            //   So, if prev_b > upper_bound and prev_b < a_i, we must set prev_b = a_i.

            // Simplified logic:
            // If prev_b is in the "forbidden" range (upper_bound, a_i),
            // then we must pick a value >= a_i. The smallest such value is a_i.
            // Otherwise, we can pick prev_b.

            // The forbidden range is (upper_bound, a_i).
            // If prev_b is in this forbidden range, i.e., upper_bound < prev_b < a_i,
            // then we cannot pick prev_b. We must pick a value >= a_i.
            // The smallest valid value for b_i would then be a_i.
            if (prev_b > upper_bound && prev_b < current_a) {
                prev_b = current_a;
            }
            // Otherwise, prev_b is a valid choice (either prev_b <= upper_bound, or prev_b >= a_i).
            // In this case, we keep prev_b as is.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);

    // Calculate left_zero_run: length of consecutive zeros to the left, including current
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
        } else {
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run: length of consecutive zeros to the right, including current
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
        } else {
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            // Find the nearest 0 to the left and right
            int l = i - left_zero_run[i]; // Index of the 0 that starts the run of 0s ending at i-1, or -1 if no 0s
            int r = i + right_zero_run[i]; // Index of the 0 that starts the run of 0s starting at i+1, or n if no 0s

            // If a[i] is 1, it can only change if it's part of a 010 pattern.
            // This means it must be surrounded by 0s.
            // The distance to the nearest 1 on the left is `i - (l+1)`.
            // The distance to the nearest 1 on the right is `(r-1) - i`.
            // If l < 0, it means all elements to the left are 1s (or it's the first element).
            // If r >= n, it means all elements to the right are 1s (or it's the last element).

            // The actual distance to the nearest 1 on the left is `i - (l_idx + 1)` where `l_idx` is the index of the 1.
            // The actual distance to the nearest 1 on the right is `(r_idx - 1) - i` where `r_idx` is the index of the 1.

            // For a[i] to change from 1 to 0, it must be 1 and surrounded by 0s.
            // The number of steps for a 1 at index `i` to become 0 is `min(i - l_idx, r_idx - i)`.
            // Here, `l_idx` is the index of the nearest 1 to the left of `i`, and `r_idx` is the nearest 1 to the right.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0 in the next step.
            // This is equivalent to `a[i-1] == 0` and `a[i+1] == 0`.
            // The `left_zero_run[i-1]` gives the length of zeros ending at `i-1`.
            // The `right_zero_run[i+1]` gives the length of zeros starting at `i+1`.

            // The number of steps for a 1 at index `i` to become 0 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // This means `left_zero_run[i-1] >= 1` and `right_zero_run[i+1] >= 1`.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.

            // The actual logic for a 1 at index `i` to become 0:
            // It needs to be surrounded by 0s.
            // The number of steps for `a[i]` to become 0 is `min(k_left, k_right)` where
            // `k_left` is the number of steps for the 1 to be "eaten" from the left.
            // `k_right` is the number of steps for the 1 to be "eaten" from the right.
            // `k_left` is `i - (index of nearest 1 to its left)`.
            // `k_right` is `(index of nearest 1 to its right) - i`.
            // If there's no 1 to the left, `k_left` is effectively infinity.
            // If there's no 1 to the right, `k_right` is effectively infinity.

            // Let's find the actual nearest 1s.
            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            int k_val = 0;
            if (left_one_idx == -1 && right_one_idx == n) {
                // All 1s, or a single 1. This 1 will never change.
                // This case is only possible if n=1 and a[0]=1, or n=2 and a=[1,1].
                // But we handle n<=2 separately.
                // For n > 2, if all are 1s, it's stable. If a single 1, it's stable.
                // This means a[i] is 1, and all other elements are 0.
                // E.g., 00100. This is stable.
                // So k_val = 0.
            } else if (left_one_idx == -1) { // No 1 to the left, only 0s.
                // Sequence starts with 0s, then 1s, then 0s, then 1s...
                // Example: 0011100. For the first 1, left_one_idx = -1.
                // The 1 at `i` is `a[i]`.
                // The number of steps for `a[i]` to become 0 is `right_one_idx - i`.
                k_val = right_one_idx - i;
            } else if (right_one_idx == n) { // No 1 to the right, only 0s.
                // Example: 0011100. For the last 1, right_one_idx = n.
                // The number of steps for `a[i]` to become 0 is `i - left_one_idx`.
                k_val = i - left_one_idx;
            } else { // 1s on both sides.
                // Example: 01010. For the middle 1, left_one_idx=1, right_one_idx=3.
                // k_val = min(i - left_one_idx, right_one_idx - i).
                k_val = std::min(i - left_one_idx, right_one_idx - i);
            }
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            // A 0 at index `i` becomes 1 if it's part of a 101 pattern.
            // This means `a[i-1] == 1` and `a[i+1] == 1`.
            // The number of steps for `a[i]` to become 1 is `min(i - left_one_idx, right_one_idx - i)`.
            // Here, `left_one_idx` is the index of the nearest 1 to the left of `i`.
            // `right_one_idx` is the index of the nearest 1 to the right of `i`.
            // If `a[i]` is 0, and `a[i-1]` is 1, and `a[i+1]` is 1, then `a[i]` becomes 1 in the next step.
            // This is equivalent to `left_zero_run[i-1] == 0` and `right_zero_run[i+1] == 0`.
            // The number of steps for `a[i]` to become 1 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.

            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            if (left_one_idx != -1 && right_one_idx != n) {
                int k_val = std::min(i - left_one_idx, right_one_idx - i);
                if (k_val <= max_k) {
                    b[i] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: one where all bits are 0, and one where all bits are 1.
    // We only care about bits 0-9, as constants are up to 1023.
    // So, initial_val_0 = 0 (all bits 0)
    // And initial_val_1 = 1023 (all bits 1 for 0-9)
    int val0 = 0;
    int val1 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

    // Now, val0 is the result if input was 0.
    // And val1 is the result if input was 1023.

    // We need to find A, B, C such that for any input bit 'b':
    // (b & A) | B ^ C = final_bit_value
    //
    // Let's analyze for each bit position 'j' (0 to 9):
    // Let b_j be the j-th bit of the input.
    // Let final_0_j be the j-th bit of val0.
    // Let final_1_j be the j-th bit of val1.
    //
    // If b_j = 0, then (0 & A_j) | B_j ^ C_j = final_0_j  =>  0 | B_j ^ C_j = final_0_j  =>  B_j ^ C_j = final_0_j
    // If b_j = 1, then (1 & A_j) | B_j ^ C_j = final_1_j  =>  A_j | B_j ^ C_j = final_1_j
    //
    // Substituting B_j ^ C_j = final_0_j into the second equation:
    // A_j | final_0_j = final_1_j
    //
    // From A_j | final_0_j = final_1_j:
    // If final_0_j = 0: A_j | 0 = final_1_j  =>  A_j = final_1_j
    // If final_0_j = 1: A_j | 1 = final_1_j. This implies final_1_j must be 1.
    //                    If final_1_j is 0, it's impossible. (But this won't happen because final_0_j is derived from 0 and final_1_j from 1023, so final_0_j <= final_1_j for AND/OR/XOR operations if we consider the bits independently. More precisely, if an input bit is 0, it can only become 1 if an OR operation sets it. If an input bit is 1, it can only become 0 if an AND operation clears it. So, if 0 becomes 1, then 1 must also become 1. If 0 becomes 0, then 1 can become 0 or 1. So final_0_j <= final_1_j is not strictly true for XOR, but A_j | final_0_j = final_1_j is the correct derivation.)
    //                    If final_1_j = 1, then A_j can be 0 or 1. We choose A_j = 0 to minimize operations.
    //
    // So, A_j can be determined:
    // If final_0_j = 0 and final_1_j = 0: A_j = 0
    // If final_0_j = 0 and final_1_j = 1: A_j = 1
    // If final_0_j = 1 and final_1_j = 0: This case is impossible for A_j | final_0_j = final_1_j.
    //                                      (1 | A_j = 0 is impossible).
    //                                      This means our assumption that the final transformation can be represented as (b & A) | B ^ C is incorrect for this specific bit pattern.
    //                                      Let's re-evaluate.
    //
    // The general form of a bit transformation is:
    // f(b) = (b & K_and) | K_or ^ K_xor
    //
    // For each bit j:
    // Let b_j be the input bit.
    // Let f_j(0) be the output bit if input bit was 0.
    // Let f_j(1) be the output bit if input bit was 1.
    //
    // We have 4 possible (f_j(0), f_j(1)) pairs:
    // 1. (0, 0): Output is always 0, regardless of input.
    //    This can be achieved by: `& 0` (K_and=0, K_or=0, K_xor=0)
    //    Or: `| 0 ^ 0` (K_and=1, K_or=0, K_xor=0)
    //    Or: `& 0 | 0 ^ 0`
    //    Simplest: `& 0`
    // 2. (0, 1): Output is same as input.
    //    This can be achieved by: `& 1` (K_and=1, K_or=0, K_xor=0)
    //    Or: `| 0`
    //    Simplest: `& 1`
    // 3. (1, 0): Output is NOT of input.
    //    This can be achieved by: `^ 1` (K_and=1, K_or=0, K_xor=1)
    //    Simplest: `^ 1`
    // 4. (1, 1): Output is always 1, regardless of input.
    //    This can be achieved by: `| 1` (K_and=1, K_or=1, K_xor=0)
    //    Simplest: `| 1`

    // We can combine these into three operations: one AND, one OR, one XOR.
    // Let the final operations be `& A`, `| B`, `^ C`.
    // The final value for an input `x` is `((x & A) | B) ^ C`.

    // Let's determine A, B, C bit by bit.
    // For each bit j (0 to 9):
    // Let x_j be the j-th bit of input x.
    // Let A_j, B_j, C_j be the j-th bits of A, B, C.
    // The j-th bit of the result is `((x_j & A_j) | B_j) ^ C_j`.

    // Case 1: Input bit x_j = 0
    // Result bit: `((0 & A_j) | B_j) ^ C_j = (0 | B_j) ^ C_j = B_j ^ C_j`.
    // This must be equal to the j-th bit of `val0`. So, `B_j ^ C_j = (val0 >> j) & 1`.

    // Case 2: Input bit x_j = 1
    // Result bit: `((1 & A_j) | B_j) ^ C_j = (A_j | B_j) ^ C_j`.
    // This must be equal to the j-th bit of `val1`. So, `(A_j | B_j) ^ C_j = (val1 >> j) & 1`.

    // We need to find A_j, B_j, C_j for each j.
    // Let `v0_j = (val0 >> j) & 1` and `v1_j = (val1 >> j) & 1`.
    // We have:
    // 1) `B_j ^ C_j = v0_j`
    // 2) `(A_j | B_j) ^ C_j = v1_j`

    // From (1), `C_j = B_j ^ v0_j`. Substitute into (2):
    // `(A_j | B_j) ^ (B_j ^ v0_j) = v1_j`

    // Let's try to find A, B, C that work.
    // A common strategy for this type of problem is to use a fixed set of operations.
    // For example, `& A`, `| B`, `^ C`.
    //
    // Let's define the target values for each bit:
    // `target_0_j = (val0 >> j) & 1`
    // `target_1_j = (val1 >> j) & 1`
    //
    // We want to find A_j, B_j, C_j such that:
    // `((0 & A_j) | B_j) ^ C_j = target_0_j`  => `B_j ^ C_j = target_0_j`
    // `((1 & A_j) | B_j) ^ C_j = target_1_j`  => `(A_j | B_j) ^ C_j = target_1_j`
    //
    // Let's try to construct A, B, C.
    //
    // Consider the effect of `^ C`: it flips bits where C_j=1.
    // Let `val0_prime = val0 ^ C` and `val1_prime = val1 ^ C`.
    // Then we need `(0 & A) | B = val0_prime` and `(1 & A) | B = val1_prime`.
    // This simplifies to `B = val0_prime` and `A | B = val1_prime`.
    // So, `B = val0 ^ C`.
    // And `A | (val0 ^ C) = val1 ^ C`.
    //
    // This means for each bit j:
    // `B_j = (val0 >> j) & 1 ^ C_j`
    // `A_j | B_j = (val1 >> j) & 1 ^ C_j`
    //
    // Substitute B_j into the second equation:
    // `A_j | ((val0 >> j) & 1 ^ C_j) = (val1 >> j) & 1 ^ C_j`
    //
    // Let `v0_j = (val0 >> j) & 1` and `v1_j = (val1 >> j) & 1`.
    // `A_j | (v0_j ^ C_j) = v1_j ^ C_j`
    //
    // We need to choose C_j.
    //
    // Case 1: `v0_j = 0, v1_j = 0` (input 0 -> 0, input 1 -> 0)
    //   `A_j | (0 ^ C_j) = 0 ^ C_j`
    //   `A_j | C_j = C_j`. This implies `A_j` must be 0.
    //   If `A_j = 0`, then `B_j = 0 ^ C_j = C_j`.
    //   So, `A_j=0, B_j=C_j`.
    //   The operation is `((x_j & 0) | C_j) ^ C_j = (0 | C_j) ^ C_j = C_j ^ C_j = 0`.
    //   This works for any C_j. We can choose C_j = 0.
    //   So for (0,0): A_j=0, B_j=0, C_j=0.
    //
    // Case 2: `v0_j = 0, v1_j = 1` (input 0 -> 0, input 1 -> 1)
    //   `A_j | (0 ^ C_j) = 1 ^ C_j`
    //   `A_j | C_j = 1 ^ C_j`.
    //   If `C_j = 0`: `A_j | 0 = 1 ^ 0` => `A_j = 1`.
    //     Then `B_j = 0 ^ 0 = 0`.
    //     So for (0,1): A_j=1, B_j=0, C_j=0.
    //     Operation: `((x_j & 1) | 0) ^ 0 = x_j`. Correct.
    //   If `C_j = 1`: `A_j | 1 = 1 ^ 1` => `A_j | 1 = 0`. This is impossible.
    //   So for (0,1): A_j=1, B_j=0, C_j=0.
    //
    // Case 3: `v0_j = 1, v1_j = 0` (input 0 -> 1, input 1 -> 0)
    //   `A_j | (1 ^ C_j) = 0 ^ C_j`
    //   `A_j | (1 ^ C_j) = C_j`.
    //   If `C_j = 0`: `A_j | (1 ^ 0) = 0` => `A_j | 1 = 0`. Impossible.
    //   If `C_j = 1`: `A_j | (1 ^ 1) = 1` => `A_j | 0 = 1` => `A_j = 1`.
    //     Then `B_j = 1 ^ 1 = 0`.
    //     So for (1,0): A_j=1, B_j=0, C_j=1.
    //     Operation: `((x_j & 1) | 0) ^ 1 = x_j ^ 1`. Correct.
    //
    // Case 4: `v0_j = 1, v1_j = 1` (input 0 -> 1, input 1 -> 1)
    //   `A_j | (1 ^ C_j) = 1 ^ C_j`
    //   `A_j | (1 ^ C_j) = 1 ^ C_j`. This implies `A_j` must be 0.
    //   If `A_j = 0`, then `B_j = 1 ^ C_j`.
    //   So, `A_j=0, B_j=1^C_j`.
    //   The operation is `((x_j & 0) | (1 ^ C_j)) ^ C_j = (0 | (1 ^ C_j)) ^ C_j = (1 ^ C_j) ^ C_j = 1`.
    //   This works for any C_j. We can choose C_j = 0.
    //   So for (1,1): A_j=0, B_j=1, C_j=0.
    //
    // Summary for each bit j:
    // (v0_j, v1_j) | A_j | B_j | C_j | Operation
    // -------------|-----|-----|-----|--------------------
    // (0, 0)       | 0   | 0   | 0   | ((x_j & 0) | 0) ^ 0 = 0
    // (0, 1)       | 1   | 0   | 0   | ((x_j & 1) | 0) ^ 0 = x_j
    // (1, 0)       | 1   | 0   | 1   | ((x_j & 1) | 0) ^ 1 = x_j ^ 1
    // (1, 1)       | 0   | 1   | 0   | ((x_j & 0) | 1) ^ 0 = 1

    // Let's construct the final A, B, C values.
    int final_A = 0; // for &
    int final_B = 0; // for |
    int final_C = 0; // for ^

    for (int j = 0; j < 10; ++j) {
        int v0_j = (val0 >> j) & 1;
        int v1_j = (val1 >> j) & 1;

        if (v0_j == 0 && v1_j == 0) {
            // A_j=0, B_j=0, C_j=0
        } else if (v0_j == 0 && v1_j == 1) {
            // A_j=1, B_j=0, C_j=0
            final_A |= (1 << j);
        } else if (v0_j == 1 && v1_j == 0) {
            // A_j=1, B_j=0, C_j=1
            final_A |= (1 << j);
            final_C |= (1 << j);
        } else { // v0_j == 1 && v1_j == 1
            // A_j=0, B_j=1, C_j=0
            final_B |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation.
                           // If A is 1023, it means all bits are 1, so x & 1023 is just x (for 0-1023).
                           // So we can omit & 1023.
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If B is not all 0s, we need an OR operation.
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If C is not all 0s, we need an XOR operation.
        result_ops.push_back({'^', final_C});
    }

    // The problem asks for at most 5 lines. Our construction gives at most 3.
    // The order of operations matters: `& A`, then `| B`, then `^ C`.
    // This order is fixed by the derivation.

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and y can accumulate many such values.
// x can also go out of bounds quickly.

// Memoization table for results of (x, parity)
// dp[x][0] stores {final_y, final_x} if starting at x with parity 0 (add a_x)
// dp[x][1] stores {final_y, final_x} if starting at x with parity 1 (subtract a_x)
// The values stored are relative changes from the state (x, parity)
// dp[x][parity].first = change in y
// dp[x][parity].second = change in x
// A special value (e.g., -1 for change in y) can indicate non-termination.
std::vector<std::vector<std::pair<long long, long long>>> dp;
std::vector<std::vector<bool>> visited; // To detect cycles (non-termination)

// The actual array 'a' (0-indexed)
std::vector<long long> a_arr;
int N;

// Recursive function to calculate the outcome from a given state (current_x, current_parity)
// current_x is 1-indexed
// current_parity: 0 for adding a_x, 1 for subtracting a_x
std::pair<long long, long long> solve(long long current_x, int current_parity) {
    // Check termination conditions
    if (current_x <= 0 || current_x > N) {
        return {0, current_x}; // Base case: terminated, no further y change, x is the final x
    }

    // Check if already computed
    if (dp[current_x][current_parity].first != -2) { // -2 indicates not computed
        return dp[current_x][current_parity];
    }

    // Detect cycles (non-termination)
    if (visited[current_x][current_parity]) {
        return {-1, -1}; // Indicate non-termination
    }

    visited[current_x][current_parity] = true;

    long long val = a_arr[current_x - 1]; // Get a_x (0-indexed array)
    long long next_x;
    long long y_change_from_step = val;

    if (current_parity == 0) { // Step 2: x = x + val, y = y + val
        next_x = current_x + val;
        // Next step will be step 3 (parity 1)
        std::pair<long long, long long> res = solve(next_x, 1);

        visited[current_x][current_parity] = false; // Backtrack visited state

        if (res.first == -1) { // If next state leads to non-termination
            return dp[current_x][current_parity] = {-1, -1};
        } else {
            return dp[current_x][current_parity] = {y_change_from_step + res.first, res.second};
        }
    } else { // current_parity == 1 (Step 3: x = x - val, y = y + val)
        next_x = current_x - val;
        // Next step will be step 2 (parity 0)
        std::pair<long long, long long> res = solve(next_x, 0);

        visited[current_x][current_parity] = false; // Backtrack visited state

        if (res.first == -1) { // If next state leads to non-termination
            return dp[current_x][current_parity] = {-1, -1};
        } else {
            return dp[current_x][current_parity] = {y_change_from_step + res.first, res.second};
        }
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_arr.resize(N);
    // a_1 is set for each query, a_2 to a_N are given
    for (int i = 1; i < N; ++i) {
        std::cin >> a_arr[i];
    }

    // Initialize DP table. Size N+1 for 1-indexed x, and 2 for parity.
    // Use -2 as a sentinel value for uncomputed states.
    dp.resize(N + 1, std::vector<std::pair<long long, long long>>(2, {-2, -2}));
    visited.resize(N + 1, std::vector<bool>(2, false));

    for (int i = 1; i < N; ++i) {
        a_arr[0] = i; // Set a_1 for the current query

        // Reset DP table and visited states for each new a_1.
        // Only states reachable from (1,0) with current a_1 need to be cleared.
        // However, clearing the whole table is simpler and N is small enough.
        // A more optimized approach would be to only clear relevant entries,
        // but this requires tracking which entries were modified.
        // For N=2e5, clearing N*2 entries is 4e5 operations, which is fine.
        for(int j=1; j<=N; ++j) {
            dp[j][0] = {-2, -2};
            dp[j][1] = {-2, -2};
            visited[j][0] = false;
            visited[j][1] = false;
        }

        // Initial state: x=1, y=0. First operation is step 2 (add a_x).
        // So we call solve(1, 0)
        std::pair<long long, long long> result = solve(1, 0);

        if (result.first == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << i + result.first << "\n"; // Initial y is 0, first a_x is a_1=i
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long current_delta_sum = 0;
            for (int j = 0; j < i; ++j) {
                if (ops[j].type == 1) {
                    if (ops[j].l <= ops[i].r && ops[j].r >= ops[i].l) { // Check for overlap
                        current_delta_sum += ops[j].val;
                    }
                }
            }
            // For each element a[k] in range [ops[i].l, ops[i].r],
            // its initial value initial_a[k] must be <= current_max_val - current_delta_sum.
            // We want to maximize initial_a[k] to satisfy this constraint.
            // So, initial_a[k] = min(initial_a[k], current_max_val - current_delta_sum).
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                initial_a[k] = std::min(initial_a[k], current_max_val - current_delta_sum);
            }
        }
    }

    // If initial_a[k] is still max_long_long, it means it was not constrained by any type 2 operation.
    // We can set it to 0, as per problem statement (absolute value <= 10^9).
    // Setting it to 0 is a valid choice that satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_hall = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from current child in office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated cries from children who left the hall
            children[j].p -= total_d_cry_from_hall;

            // Check if child j now cries and leaves
            if (children[j].p < 0) {
                total_d_cry_from_hall += children[j].d;
                children[j].in_line = false;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If a has an odd number of ones, we can append a '1'.
    // If a has an even number of ones, we can append a '0'.
    // This means we can always increase the number of ones by 1 if it's odd,
    // or keep it the same if it's even (by appending '0').
    // Effectively, if ones_a is odd, we can make it ones_a + 1.
    // If ones_a is even, we can make it ones_a.
    // So, the maximum number of ones we can achieve in a string of length L
    // that is derived from 'a' by appending parities is:
    // ones_a + (L - |a|) if ones_a is odd,
    // ones_a + (L - |a|) if ones_a is even and we append '1's (which is not always possible)
    //
    // A simpler way to think about it:
    // We can always append a character. If we append '0', the number of ones doesn't change.
    // If we append '1', the number of ones increases by 1.
    // The parity operation allows us to append either '0' or '1' based on current parity.
    // If current parity is 0 (even ones), we append '0'. ones_count remains same.
    // If current parity is 1 (odd ones), we append '1'. ones_count increases by 1.
    //
    // So, if we start with `ones_a` ones:
    // If `ones_a` is even, we can only append '0'. The number of ones remains `ones_a`.
    // If `ones_a` is odd, we can append '1'. The number of ones becomes `ones_a + 1`.
    //
    // This means the maximum number of ones we can achieve in a string of length `L`
    // that is derived from `a` by appending parities is:
    // `ones_a` if `ones_a` is even.
    // `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a + (ones_a % 2)`.
    //
    // Let `max_ones_possible_in_a_prefix` be the maximum number of ones we can have
    // in a string derived from `a` that has length at least `|b|`.
    // We can always extend `a` to be at least length `|b|`.
    // The number of ones in `a` can be `ones_a` or `ones_a + 1` (if `ones_a` is odd).
    //
    // Let `effective_ones_a` be the number of ones in `a` after potentially one parity append
    // that maximizes the number of ones.
    // If `ones_a` is odd, we can append '1', making `ones_a + 1` ones.
    // If `ones_a` is even, we can append '0', keeping `ones_a` ones.
    // So, `effective_ones_a = ones_a + (ones_a % 2)`.
    // This is the maximum number of ones we can have in a string of length `|a|` or `|a|+1`
    // that is a prefix of the final string we are considering.
    //
    // The length of `a` can be increased to `|b|` or more.
    // The number of ones in `a` can be at most `ones_a + (ones_a % 2)`.
    // If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Also, the length of `a` must be at least `|b|` after some operations.
    // If `|a| < |b|`, we must append `|b| - |a|` characters.
    // The number of ones in `a` can be at most `ones_a + (ones_a % 2)`.
    //
    // The crucial observation is that we can always make the string `a` as long as we want.
    // If `a` has `k` ones, and we append `parity(a)`:
    // If `k` is even, `parity(a)` is '0'. `a` becomes `a + '0'`. Number of ones is still `k`.
    // If `k` is odd, `parity(a)` is '1'. `a` becomes `a + '1'`. Number of ones is `k+1`.
    //
    // This means if `ones_a` is even, we can only ever have an even number of ones.
    // If `ones_a` is odd, we can make it `ones_a + 1` (even), and then it will stay even.
    // So, if `ones_a` is odd, we can effectively have `ones_a + 1` ones.
    // If `ones_a` is even, we can only have `ones_a` ones.
    //
    // Let `max_ones_reachable_from_a` be the maximum number of ones we can achieve
    // in a string derived from `a` by appending parities.
    // `max_ones_reachable_from_a = ones_a + (ones_a % 2)`.
    //
    // If `max_ones_reachable_from_a < ones_b`, then it's impossible.
    // Also, the length of `a` must be at least `|b|`.
    // If `|a| < |b|`, we need to append `|b| - |a|` characters.
    // The number of ones in `a` will be `ones_a` plus the number of '1's appended.
    // The maximum number of '1's we can append is `(ones_a % 2)` if we append one character.
    //
    // Let's re-evaluate.
    // We can always make `a` long enough to contain `b` as a suffix.
    // The question is about the number of ones.
    // Let `current_ones` be the number of ones in `a`.
    // If `current_ones` is even, we append '0'. `current_ones` remains even.
    // If `current_ones` is odd, we append '1'. `current_ones` becomes even.
    //
    // This means that after at most one append operation, the number of ones in `a` will become even.
    // And once it's even, it will always remain even, because appending '0' keeps it even.
    //
    // So, the number of ones in any string `a'` derived from `a` by appending parities
    // will be `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    // Let `final_ones_a = ones_a + (ones_a % 2)`. This is the maximum number of ones
    // we can achieve in `a` while keeping its length at least `|a|`.
    //
    // If `final_ones_a < ones_b`, it's impossible.
    // Also, the length of `a` must be at least `|b|`.
    // If `|a| < |b|`, we need to append `|b| - |a|` characters.
    // The number of ones in `a` will be `ones_a` plus the number of '1's appended.
    // The maximum number of '1's we can append is `(ones_a % 2)` if we append one character.
    //
    // The logic is:
    // 1. Calculate `ones_a` and `ones_b`.
    // 2. Calculate `max_ones_a_can_have = ones_a + (ones_a % 2)`.
    //    This is the maximum number of ones `a` can have after potentially one parity append.
    //    After this, any further appends will be '0's, keeping the number of ones constant.
    // 3. If `max_ones_a_can_have < ones_b`, then it's impossible. Print "NO".
    // 4. Otherwise, it is possible. Print "YES".
    //
    // Example 1: a="01011", b="0110"
    // ones_a = 3 (odd)
    // ones_b = 2
    // max_ones_a_can_have = 3 + (3 % 2) = 3 + 1 = 4.
    // Since 4 >= 2, it's possible. Output: YES.
    //
    // Example 2: a="0011", b="1110"
    // ones_a = 2 (even)
    // ones_b = 3
    // max_ones_a_can_have = 2 + (2 % 2) = 2 + 0 = 2.
    // Since 2 < 3, it's impossible. Output: NO.
    //
    // This logic seems correct and covers all cases. The length constraint is implicitly handled
    // because we can always extend `a` to be at least `|b|` long by appending '0's (after `max_ones_a_can_have` is reached).

    int max_ones_a_can_have = ones_a + (ones_a % 2);

    if (max_ones_a_can_have >= ones_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);

    // Case 2: Partition such that a_1 is in one subsequence, and all others are in another.
    // Or more generally, a_1, ..., a_{k-1} in one, a_k, ..., a_n in another.
    // The optimal strategy for this case is to put a_1 in one group and all other elements in another group.
    // This ensures that a_1 + a_2 + h is the minimum possible value involving h.
    // And a_1 + a_2 is not possible.
    //
    // Let's consider the partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    //
    // Possible f values:
    // 1. elements[i].value + elements[j].value (both in group 2, i,j >= 1)
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-1].value + elements[n-2].value
    // 2. elements[0].value + elements[j].value + h (elements[0] in group 1, elements[j] in group 2, j >= 1)
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f for this partition:
    // min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //
    // Overall max_f for this partition:
    // max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness2 = max_f - min_f

    long long min_f2_same_group = elements[1].value + elements[2].value;
    long long min_f2_diff_group = elements[0].value + elements[1].value + h;
    long long min_f2 = std::min(min_f2_same_group, min_f2_diff_group);

    long long max_f2_same_group = elements[n - 1].value + elements[n - 2].value;
    long long max_f2_diff_group = elements[0].value + elements[n - 1].value + h;
    long long max_f2 = std::max(max_f2_same_group, max_f2_diff_group);

    long long goodness2 = max_f2 - min_f2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        std::vector<int> result(n);
        for (int i = 0; i < n; ++i) {
            result[elements[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> result(n);
        result[elements[0].original_index] = 1; // Smallest element in group 1
        for (int i = 1; i < n; ++i) {
            result[elements[i].original_index] = 2; // Others in group 2
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

