int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // min_r[i] stores the minimum r (0-indexed) such that the substring s[i..r]
    // contains a pattern s_x = s_{x+k} = s_{x+2k}.
    // If no such r exists for a given i, min_r[i] can be n.
    // We are looking for the smallest r such that l <= x < x+2k <= r.
    // The smallest possible r for a pattern starting at x with step k is x+2k.
    // So, for a given l, we need to find the smallest r such that there exists
    // x, k with l <= x and x+2k <= r and s_x = s_{x+k} = s_{x+2k}.
    // This means we need to find the minimum x+2k over all x >= l that form a pattern.
    // Let's define min_pattern_end[i] as the minimum index j such that s[i..j]
    // contains a pattern s_x = s_{x+k} = s_{x+2k} where x >= i.
    // More precisely, min_pattern_end[i] is the minimum value of (x+2k)
    // for any pattern s_x = s_{x+k} = s_{x+2k} such that x >= i.
    // If no such pattern exists for x >= i, min_pattern_end[i] can be n.

    std::vector<int> min_pattern_end(n + 1, n); // min_pattern_end[i] stores min (x+2k) for x >= i

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible step sizes k
        // The maximum possible k is such that x + 2k < n.
        // So 2k < n - x, k < (n - x) / 2.
        // k must be at least 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s_x = s_{x+k} = s_{x+2k}
                // The end index of this pattern is x + 2k.
                // This pattern affects all min_pattern_end[i] for i <= x.
                // We want to update min_pattern_end[x] with this value.
                // Since we iterate x from 0 to n-1, and k from 1 upwards,
                // the first pattern found for a given x will have the smallest x+2k.
                // However, we need the minimum x+2k for any x' >= i.
                // So, we can iterate x from n-1 down to 0.
                // For a fixed x, the smallest x+2k is for k=1.
                // So, if s[x] == s[x+1] == s[x+2], then x+2 is the smallest end for x.
                // If s[x] == s[x+2] == s[x+4], then x+4 is the smallest end for x.
                // The minimum of these is what we need for min_pattern_end[x].
                // The maximum k is 6 because if k >= 7, then x+2k >= x+14.
                // If n is 300,000, and x is 0, then k can be up to 149,999.
                // But the problem constraints on k are not explicit, only 1 <= k <= n.
                // However, if k is large, x+2k will be large.
                // The crucial observation is that if a pattern exists, we only care about the smallest x+2k.
                // If k is large, say k=7, then x+2k = x+14.
                // If there is a pattern with k=1,2,3,4,5,6, it will have a smaller x+2k.
                // The maximum possible value for x+2k is n-1.
                // If k is large, x+2k will be large.
                // The smallest possible x+2k is x+2.
                // If we have s[x] = s[x+k] = s[x+2k], then the minimum r for this pattern is x+2k.
                // We are interested in the minimum x+2k over all possible k.
                // For a fixed x, the smallest x+2k is when k is smallest, i.e., k=1.
                // So, if s[x] == s[x+1] == s[x+2], then x+2 is a candidate for min_pattern_end[x].
                // If s[x] == s[x+2] == s[x+4], then x+4 is a candidate for min_pattern_end[x].
                // If s[x] == s[x+3] == s[x+6], then x+6 is a candidate for min_pattern_end[x].
                // The maximum k we need to check is small.
                // If k is large, say k=7, then x+2k = x+14.
                // If there is a pattern s[x] = s[x+k'] = s[x+2k'] for k' < k, then x+2k' < x+2k.
                // The maximum value of x+2k is n-1.
                // The minimum value of x+2k is x+2.
                // The maximum value of k we need to check is 6.
                // Why 6? Consider the indices $x, x+k, x+2k$.
                // If $k \ge 7$, then $x+2k \ge x+14$.
                // Any pattern $s_x = s_{x+k} = s_{x+2k}$ with $k \ge 7$ would imply that
                // $s_x$ is equal to $s_{x+k}$ and $s_{x+2k}$.
                // If there is a pattern $s_x = s_{x+k'} = s_{x+2k'}$ with $k' < 7$,
                // then $x+2k'$ would be smaller than $x+2k$.
                // The smallest $x+2k$ is $x+2$ (for $k=1$).
                // The largest $x+2k$ we care about is $x+13$ (for $k=6$).
                // If $x+2k \ge x+14$, then any $l, r$ pair that includes this pattern
                // would also include any pattern with $k' < 7$ that starts at $x$ or later.
                // This is because $x+2k' < x+14$.
                // So, we only need to check $k$ from 1 to 6.
                // This is a common optimization for problems involving arithmetic progressions in strings.
                // The maximum value of $x+2k$ we need to consider for a pattern is $x+13$.
                // If $x+2k \ge x+14$, then $x+2k$ is "far enough" that any $l,r$ pair
                // that includes this pattern would also include a pattern with $k' \le 6$
                // if such a pattern exists starting at $x$ or later.
                // This is because the "bad" region for $l$ is $[x, \text{min_pattern_end}[x]-1]$.
                // If min_pattern_end[x] is $x+14$ or more, then the length of the bad region is at least 14.
                // Any pattern with $k' \le 6$ would have $x+2k' \le x+13$.
                // So, if there is a pattern with $k \ge 7$, its end $x+2k$ is at least $x+14$.
                // If there is also a pattern with $k' \le 6$, its end $x+2k'$ is at most $x+13$.
                // The minimum of these two would be $x+2k'$.
                // So we only need to consider $k \in [1, 6]$.
                if (k > 6) break; // Optimization: only check k up to 6

                min_pattern_end[x] = std::min(min_pattern_end[x], x + 2 * k);
            }
        }
    }

    // Now, propagate the minimums backwards.
    // min_pattern_end[i] should be the minimum (x+2k) for any x >= i.
    // So, min_pattern_end[i] = min(min_pattern_end[i], min_pattern_end[i+1]).
    for (int i = n - 1; i >= 0; --i) {
        min_pattern_end[i] = std::min(min_pattern_end[i], min_pattern_end[i + 1]);
    }

    // Now, for each starting position l (0-indexed),
    // the pairs (l, r) that are "bad" are those where r < min_pattern_end[l].
    // The number of such r's for a given l is (min_pattern_end[l] - 1) - l + 1 = min_pattern_end[l] - l.
    // These are the pairs (l, r) where l <= r < min_pattern_end[l].
    // The number of such r's is min_pattern_end[l] - l.
    // If min_pattern_end[l] == n, it means no pattern starts at or after l.
    // In this case, all r from l to n-1 are bad. The count is n - l.
    // This is consistent with min_pattern_end[l] - l.
    for (int l = 0; l < n; ++l) {
        bad_pairs += (min_pattern_end[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

