#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> result_a(n);
        std::vector<int> result_b(n);

        for (int i = 0; i < n; ++i) {
            result_a[a[i].original_index] = a[i].value;
            result_b[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << result_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << result_b[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use as many 5s as possible
        ans += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            ans += 1; // 1 press of +/-1
        } else if (diff == 2) {
            ans += 1; // 1 press of +/-2
        } else if (diff == 3) {
            ans += 2; // Can be +/-1, +/-2 or +/-1, +/-1, +/-1. Optimal is +/-1, +/-2.
                      // Or +/-5, then +/-2. E.g., if diff was 3, we could do +5, then -2.
                      // This is equivalent to (diff + 2) / 5.
                      // For diff=3, (3+2)/5 = 1. But we need 2 presses.
                      // The greedy approach for 1,2,3,4 is:
                      // 1 -> 1 press (+/-1)
                      // 2 -> 1 press (+/-2)
                      // 3 -> 2 presses (+/-1, +/-2)
                      // 4 -> 2 presses (+/-2, +/-2)
                      // This is equivalent to ceil(diff / 2.0) for diff=1,2,3,4
                      // Or (diff + 1) / 2 for integer division.
                      // Let's re-evaluate the remaining diff.
                      // If diff is 1, 2, 3, 4.
                      // 1: 1 press (+1)
                      // 2: 1 press (+2)
                      // 3: 2 presses (+1, +2)
                      // 4: 2 presses (+2, +2)
                      // This is (diff + 1) / 2 for diff = 1, 2, 3, 4.
                      // (1+1)/2 = 1
                      // (2+1)/2 = 1
                      // (3+1)/2 = 2
                      // (4+1)/2 = 2
                      // This is correct.
            ans += (diff + 1) / 2;
        } else if (diff == 4) {
            ans += 2; // Can be +/-2, +/-2
            ans += (diff + 1) / 2;
        }

        std::cout << ans << std::endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reversed permutation always has the same fingerprint.
    // We need to ensure it's a different permutation.
    // A permutation p is different from its reverse p_rev if p is not a palindrome.
    // The problem guarantees a solution exists.
    // For n >= 2, if p is a palindrome, then p_i = p_{n-i+1}.
    // For example, if n=2, p=[1,2], p_rev=[2,1]. These are different.
    // If n=3, p=[1,2,3], p_rev=[3,2,1]. These are different.
    // If n=4, p=[1,2,3,4], p_rev=[4,3,2,1]. These are different.
    // It's impossible for a permutation of distinct numbers from 1 to n to be a palindrome
    // unless n=1 (which is not allowed, n>=2) or it's a very specific case.
    // For example, if p_1 = p_n, but p_1 and p_n must be distinct if n > 1.
    // Wait, p_i = p_{n-i+1} means p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements in a permutation are distinct, this can only happen if n=1.
    // For n >= 2, p_1 must be different from p_n.
    // Thus, p cannot be equal to its reverse p_rev.
    // So, reversing the permutation always yields a different permutation with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

