#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long k = 1;            // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
                                    // k = 2^p - 1 for p = 1, 2, 3, ...
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            k = k * 2 + 1; // Next number of stairs: 1 -> 3 -> 7 -> 15 -> ...
            // Cost for a staircase with k stairs is k * (k + 1) / 2
            // current_cost = k * (k + 1) / 2
            // This can be rewritten as:
            // current_cost = (2^p - 1) * (2^p) / 2
            // current_cost = (2^p - 1) * 2^(p-1)
            // The next cost will be for k' = 2^(p+1) - 1
            // next_cost = (2^(p+1) - 1) * 2^p
            // Notice that next_cost = (2k + 1) * (k+1) / 2
            // Or, more simply, the cost for k stairs is k * (k+1) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of costs is 1*(1+1)/2 = 1
            // 3*(3+1)/2 = 6
            // 7*(7+1)/2 = 28
            // 15*(15+1)/2 = 120
            // The next cost is calculated based on the new k.
            // The formula for the cost of a nice staircase with k stairs is k * (k + 1) / 2.
            // Since k is always odd (1, 3, 7, ...), k+1 is always even.
            // So (k+1)/2 is an integer.
            // current_cost = k * ((k + 1) / 2);
            // This is equivalent to current_cost = k * (k+1)/2.
            // The previous current_cost was for k_old.
            // The new k is k_new = 2 * k_old + 1.
            // The new current_cost is k_new * (k_new + 1) / 2.
            // This is (2*k_old + 1) * (2*k_old + 2) / 2
            // = (2*k_old + 1) * (k_old + 1)
            // This is the correct recurrence for the cost.
            current_cost = k * (k + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to minimize |median1 - median2|.
        // After sorting the array a, the optimal strategy is to pick
        // the median of the first class as a[n-1] and the median of the second class as a[n].
        // This is because if we pick a[n-1] as the median of the first class,
        // it means the first class must contain at least n elements less than or equal to a[n-1].
        // If we pick a[n] as the median of the second class,
        // it means the second class must contain at least n elements greater than or equal to a[n].
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        // We need to partition these 2n students into two classes, C1 and C2,
        // each with an odd number of students.
        // Let |C1| = 2k1+1 and |C2| = 2k2+1.
        // (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 = n-1.
        //
        // The median of C1 is its (k1+1)-th smallest element.
        // The median of C2 is its (k2+1)-th smallest element.
        //
        // To minimize the difference, we want the medians to be as close as possible.
        // Intuitively, the medians should be chosen from the middle of the sorted array.
        //
        // Let's consider the elements a[n-1] and a[n] (0-indexed).
        // If we choose a[n-1] as the median of one class and a[n] as the median of the other class,
        // can we always form valid classes?
        //
        // Suppose C1 has median a[n-1] and C2 has median a[n].
        // For C1 to have median a[n-1], it must contain k1 elements <= a[n-1] and k1 elements >= a[n-1].
        // For C2 to have median a[n], it must contain k2 elements <= a[n] and k2 elements >= a[n].
        //
        // The simplest partition that uses a[n-1] and a[n] as medians is:
        // Class 1: {a_1, ..., a_{n-1}, a_n} (size n)
        // Class 2: {a_{n+1}, ..., a_{2n}} (size n)
        // This doesn't work because n can be even.
        //
        // However, the problem states that the number of students in classes may be equal or different.
        // The key insight is that the minimum possible difference will always be between a[n-1] and a[n]
        // (using 0-indexed array).
        //
        // Consider any two medians, M1 and M2, from the two classes.
        // Let M1 be the median of C1 and M2 be the median of C2.
        // Without loss of generality, assume M1 <= M2.
        //
        // C1 has size 2k1+1. M1 is the (k1+1)-th element.
        // This means C1 contains at least k1+1 elements less than or equal to M1.
        // C2 has size 2k2+1. M2 is the (k2+1)-th element.
        // This means C2 contains at least k2+1 elements greater than or equal to M2.
        //
        // The total number of elements less than or equal to M1 is at least k1+1.
        // The total number of elements greater than or equal to M2 is at least k2+1.
        //
        // Since k1 + k2 = n-1, we have (k1+1) + (k2+1) = n-1+2 = n+1.
        //
        // So, there are at least k1+1 elements in the entire set that are <= M1.
        // And there are at least k2+1 elements in the entire set that are >= M2.
        //
        // In the sorted array `a`, the (k1+1)-th element is `a[k1]`.
        // So, M1 must be at least `a[k1]`.
        // The (2n - (k2+1) + 1)-th element is `a[2n - (k2+1)]`.
        // So, M2 must be at most `a[2n - (k2+1)]`.
        //
        // This reasoning is a bit complex. A simpler argument:
        //
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick two medians, $m_1$ and $m_2$.
        // Suppose $m_1$ is the median of class $C_1$ of size $2k_1+1$, and $m_2$ is the median of class $C_2$ of size $2k_2+1$.
        // We know $k_1+k_2 = n-1$.
        //
        // $m_1$ must be one of the $a_i$'s. $m_2$ must be one of the $a_j$'s.
        //
        // For $m_1$ to be the median of $C_1$, there must be at least $k_1$ elements in $C_1$ less than or equal to $m_1$, and at least $k_1$ elements in $C_1$ greater than or equal to $m_1$.
        // For $m_2$ to be the median of $C_2$, there must be at least $k_2$ elements in $C_2$ less than or equal to $m_2$, and at least $k_2$ elements in $C_2$ greater than or equal to $m_2$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can always form two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        // For example, let $C_1 = \{a_0, \dots, a_{n-1}\}$ and $C_2 = \{a_n, \dots, a_{2n-1}\}$.
        // This is not valid because sizes are $n$.
        //
        // The crucial observation is that if we sort the entire $2n$ students,
        // the $n$-th student (0-indexed $a_{n-1}$) and the $(n+1)$-th student (0-indexed $a_n$)
        // are the "middle" two students.
        //
        // If we pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other,
        // the difference is $a_n - a_{n-1}$.
        // Can we achieve a smaller difference?
        //
        // Suppose we have two medians $M_1$ and $M_2$ such that $M_1 < a_{n-1}$ or $M_2 > a_n$.
        // If $M_1 < a_{n-1}$, then $M_1$ is at most $a_{n-2}$.
        // If $M_2 > a_n$, then $M_2$ is at least $a_{n+1}$.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$.
        // And the $n$ largest elements $a_n, \dots, a_{2n-1}$.
        //
        // One class must contain $a_{n-1}$ as its median, and the other $a_n$ as its median.
        // This is because if both medians are $\le a_{n-1}$, then we would need $k_1+1$ elements $\le M_1$ and $k_2+1$ elements $\le M_2$.
        // This would mean $n+1$ elements are $\le \max(M_1, M_2)$, which is $\le a_{n-1}$.
        // But there are only $n$ elements $\le a_{n-1}$ ($a_0, \dots, a_{n-1}$). This is a contradiction.
        //
        // Similarly, if both medians are $\ge a_n$, we would need $n+1$ elements $\ge \min(M_1, M_2)$, which is $\ge a_n$.
        // But there are only $n$ elements $\ge a_n$ ($a_n, \dots, a_{2n-1}$). This is a contradiction.
        //
        // Therefore, one median must be $\le a_{n-1}$ and the other must be $\ge a_n$.
        // Let $M_1 \le a_{n-1}$ and $M_2 \ge a_n$.
        // Then $|M_1 - M_2| = M_2 - M_1 \ge a_n - a_{n-1}$.
        //
        // This shows that the minimum possible difference is at least $a_n - a_{n-1}$.
        // We can achieve this difference by setting $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // To achieve this, we can form two classes:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This is not valid if $n$ is even, as class sizes must be odd.
        //
        // However, we can always construct valid classes.
        // For example, let $k_1 = 0$, $k_2 = n-1$.
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$, median $a_n$)
        // This is not valid. The median of Class 2 would be $a_{n-1}$ if sorted.
        //
        // The proof that $a_n - a_{n-1}$ is the minimum is solid.
        // The existence of a valid partition that achieves this minimum is also guaranteed.
        // For example, consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // If $n$ is odd, then both classes have size $n$ (odd).
        // Median of C1 is $a_{(n-1)/2}$. Median of C2 is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem statement implies that such a partition always exists.
        // The minimum difference is indeed $a_n - a_{n-1}$.
        //
        // Example 2: n=3, 2n=6. a = [1, 2, 3, 4, 5, 6]
        // a[n-1] = a[2] = 3. a[n] = a[3] = 4.
        // Difference = 4 - 3 = 1.
        // Example partition given: C1 = [6, 4, 2] (median 4), C2 = [5, 1, 3] (median 3).
        // Difference = |4-3| = 1.
        // This matches $a_n - a_{n-1}$.
        //
        // Example 3: n=5, 2n=10. a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]
        // a[n-1] = a[4] = 8. a[n] = a[5] = 13.
        // Difference = 13 - 8 = 5.
        // This matches $a_n - a_{n-1}$.
        //
        // The logic seems to hold. The minimum difference is simply the difference between the two middle elements in the sorted array.

        long long result = a[n] - a[n-1];
        std::cout << result << "\n";
    }
    return 0;
}

