    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences using numbers from 1 to k+1.
    // The pattern is 1, k+1, 2, k, 3, k-1, ...
    // This generates differences: k, k-1, k-2, ..., 1.
    // We use k+1 numbers to generate k differences.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left (small)
            std::cout << left << " ";
            left++;
        } else { // Odd index, take from right (large)
            std::cout << right << " ";
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // To avoid introducing new distinct differences, we append them in increasing order.
    // The last number printed was either left-1 or right+1.
    // If it was left-1, then left is the next available number.
    // If it was right+1, then right is the next available number.
    // In both cases, the next available number is left (which is now k+1 if k+1 is odd, or k/2+1 if k+1 is even).
    // The numbers used are 1, ..., k+1. So the next number to print is k+2.
    // The last number printed was either left-1 or right+1.
    // If k+1 is odd, the last number printed was left-1 = (k+1)/2. The next number to print is (k+1)/2 + 1.
    // If k+1 is even, the last number printed was right+1 = k/2 + 1. The next number to print is k/2 + 2.
    // This is not quite right. The numbers used are 1, ..., k+1.
    // The smallest unused number is k+2.
    // The last number printed was either `left-1` or `right+1`.
    // `left` is now `(k+1)/2 + 1` if `k+1` is odd, or `k/2 + 1` if `k+1` is even.
    // `right` is now `k/2 + 1` if `k+1` is odd, or `k/2 + 1` if `k+1` is even.
    // The numbers used are 1, 2, ..., k+1.
    // The next number to print is k+2.
    // The difference `|p_{k+1} - p_{k+2}|` should not introduce a new distinct difference.
    // By printing `k+2, k+3, ..., n` in increasing order, the differences will be `1`.
    // Since `k >= 1`, `1` is already one of the `k` distinct differences generated.
    // So, this strategy works.

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

