long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m > n) {
        return 0;
    }

    long long k_max = n / m;

    // Calculate the sum of last digits for one full cycle (10 iterations)
    std::vector<int> cycle_last_digits;
    for (int i = 1; i <= 10; ++i) {
        cycle_last_digits.push_back(static_cast<int>((static_cast<long long>(i) * m) % 10));
    }

    long long sum_one_cycle = 0;
    for (int digit : cycle_last_digits) {
        sum_one_cycle += digit;
    }

    // Number of full cycles of 10 iterations
    long long num_full_cycles = k_max / 10;
    long long total_sum = num_full_cycles * sum_one_cycle;

    // Remaining iterations
    long long remaining_iterations = k_max % 10;
    for (int i = 0; i < remaining_iterations; ++i) {
        total_sum += cycle_last_digits[i];
    }

    return total_sum;
}

