void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'p' such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // We iterate from right to left to find the first violation.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Now, find the rightmost index 'q' such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // We iterate from p-1 down to 1 to find the first violation.
    // Note: if p is 0, this loop won't run, which is correct.
    int q = p; // q starts at p, meaning the segment a[q...p-1] is empty if p is 0 or 1.
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // After this loop, a[q...p-1] is non-increasing.
    // If q is 0, then a[0...p-1] is non-increasing.

    // The prefix to remove is a[0...q-1]. Its length is q.
    std::cout << q << std::endl;
}

