#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its length is 1.
        // min_idx and max_idx are both pos[1].
        // The length of the segment is max_idx - min_idx + 1 = pos[1] - pos[1] + 1 = 1.
        // This is equal to m. So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include m.
        // The segment must contain all numbers from 1 to m.
        // We maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // To include 'm', we update current_min_idx and current_max_idx
        // to cover the position of 'm' as well.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if there exists a subsegment [l, r]
        // such that p[l...r] is a permutation of 1...m.
        // This implies two conditions:
        // 1. The subsegment must contain all numbers from 1 to m.
        //    The smallest contiguous segment that contains all numbers from 1 to m
        //    is defined by [current_min_idx, current_max_idx].
        // 2. The length of this subsegment must be exactly 'm'.
        //    The length of the segment [current_min_idx, current_max_idx] is
        //    (current_max_idx - current_min_idx + 1).
        //    If this length equals 'm', then all numbers from 1 to m are present,
        //    and no other numbers are present (because it's a permutation of 1...m).
        //    Thus, 'm' is beautiful.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

