struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    // Create the result array A'
    std::vector<long long> a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th element of sorted A (smallest) should be paired with
        // the element of B that was originally at b_elements[i].original_index
        // This means a_prime[b_elements[i].original_index] = a_elements[i].value
        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible value for b_i if it were part of an increasing prefix
    // b_i must be at least i (0-indexed) to maintain b_0 < b_1 < ... < b_i
    // So, b_i <= a_i and b_i >= i. Thus, a_i >= i must hold.
    // We can set b_i = i if a_i >= i.
    // If a_i < i, then it's impossible to make b_i = i, or b_i > i.
    // In fact, b_i must be at least b_{i-1} + 1.
    // The minimum possible value for b_i is i (if b_0=0, b_1=1, etc.).
    // So, if a_i < i, we cannot make b_i >= i.
    // This means we cannot form a strictly increasing prefix of length i+1.
    // The maximum length of a strictly increasing prefix starting from 0 is limited by this.

    // `left_possible[i]` stores whether it's possible to have `b_0 < b_1 < ... < b_i`
    // where `b_j` is chosen such that `b_j <= a_j` and `b_j >= j`.
    // Specifically, `b_j` can be `j`.
    std::vector<bool> left_possible(n);
    left_possible[0] = (a[0] >= 0); // b_0 can be 0 if a_0 >= 0
    for (int i = 1; i < n; ++i) {
        left_possible[i] = (left_possible[i-1] && (a[i] >= i));
    }

    // Calculate the maximum possible value for b_i if it were part of a decreasing suffix
    // b_i must be at least n-1-i (0-indexed) to maintain b_i > b_{i+1} > ... > b_{n-1}
    // So, b_i <= a_i and b_i >= n-1-i. Thus, a_i >= n-1-i must hold.
    // We can set b_i = n-1-i if a_i >= n-1-i.
    // If a_i < n-1-i, then it's impossible to make b_i >= n-1-i.
    // This means we cannot form a strictly decreasing suffix of length n-i.
    // The maximum length of a strictly decreasing suffix ending at 0 is limited by this.

    // `right_possible[i]` stores whether it's possible to have `b_i > b_{i+1} > ... > b_{n-1}`
    // where `b_j` is chosen such that `b_j <= a_j` and `b_j >= n-1-j`.
    // Specifically, `b_j` can be `n-1-j`.
    std::vector<bool> right_possible(n);
    right_possible[n-1] = (a[n-1] >= 0); // b_{n-1} can be 0 if a_{n-1} >= 0
    for (int i = n - 2; i >= 0; --i) {
        right_possible[i] = (right_possible[i+1] && (a[i] >= (n - 1 - i)));
    }

    // Check if there exists a peak `k` (0-indexed) such that:
    // 1. `b_0 < b_1 < ... < b_k` is possible (using values 0, 1, ..., k)
    // 2. `b_k > b_{k+1} > ... > b_{n-1}` is possible (using values k, k-1, ..., 0 relative to the peak)
    // The condition for `b_k` is that it must be at least `k` (for the left side)
    // AND at least `n-1-k` (for the right side).
    // So, `a_k` must be at least `max(k, n-1-k)`.
    // However, the problem statement implies that `b_k` is the peak, so `b_k` must be strictly greater than `b_{k-1}` and `b_{k+1}`.
    // The minimum value `b_k` can take is `k` (from left side) and `n-1-k` (from right side).
    // If we set `b_j = j` for `j <= k` and `b_j = n-1-j` for `j >= k`,
    // then `b_k` would be `k` and `n-1-k`.
    // This means `b_k` must be at least `k` and `b_k` must be at least `n-1-k`.
    // The actual value of `b_k` must be `max(k, n-1-k)`.
    // So, we need `a_k >= max(k, n-1-k)`.
    // This is implicitly handled by `left_possible[k]` requiring `a_k >= k` and `right_possible[k]` requiring `a_k >= n-1-k`.
    // If both `left_possible[k]` and `right_possible[k]` are true, it means we can construct
    // `b_0=0, b_1=1, ..., b_k=k` and `b_k=n-1-k, b_{k+1}=n-2-k, ..., b_{n-1}=0`.
    // The values for `b_k` are `k` and `n-1-k`.
    // We need to ensure that `b_k` can be chosen such that it's `k` (for left) and `n-1-k` (for right).
    // The actual value of `b_k` can be `max(k, n-1-k)`.
    // If `a_k >= max(k, n-1-k)`, then we can set `b_k = max(k, n-1-k)`.
    // And for `j < k`, `b_j = j`. For `j > k`, `b_j = n-1-j`.
    // This construction satisfies `b_0 < ... < b_k` and `b_k > ... > b_{n-1}`.
    // The conditions `a_j >= j` for `j <= k` and `a_j >= n-1-j` for `j >= k` are exactly what `left_possible` and `right_possible` check.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (left_possible[k] && right_possible[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

