#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation
// This version checks if elements are distinct and within [1, length]
// and if the maximum element is equal to length.
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix_val = 0;
    bool prefix_distinct = true;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (val < 1 || val > l1 || seen_prefix[val]) {
            prefix_distinct = false;
        }
        seen_prefix[val] = true;
        if (val > max_prefix_val) {
            max_prefix_val = val;
        }
        if (prefix_distinct && max_prefix_val == l1) {
            is_prefix_perm[l1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool suffix_distinct = true;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (val < 1 || val > l2 || seen_suffix[val]) {
            suffix_distinct = false;
        }
        seen_suffix[val] = true;
        if (val > max_suffix_val) {
            max_suffix_val = val;
        }
        if (suffix_distinct && max_suffix_val == l2) {
            is_suffix_perm[l2] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
