// Function to check if a box can be the special box
// Parameters:
// A, B, C, D: initial counts of toys in boxes 1, 2, 3, 4
// target_box: the box we are checking (1, 2, 3, or 4)
// target_sign: 0 for negative, 1 for positive
// target_magnitude_gt_1: 0 for |val| < 1, 1 for |val| > 1, 2 for |val| = 1 (not used for target_box)
bool check(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1 && target_box == 1) return true;
        if (B == 1 && target_box == 2) return true;
        if (C == 1 && target_box == 3) return true;
        if (D == 1 && target_box == 4) return true;
        return false;
    }

    // Determine the sign of the final product
    // Number of negative toys is A + B
    // If A + B is odd, final product is negative.
    // If A + B is even, final product is positive.
    bool final_product_is_negative = ((A + B) % 2 != 0);

    // Determine if the final product can be 0 or 1 or -1
    // If any toy has fun value 0, the final product is 0.
    // This problem states fun values are real numbers, but ranges are open/closed intervals
    // e.g., (-1, 0) and (0, 1). So 0 is not possible.
    // What about 1 or -1?
    // If there's a toy with value 1 and all others are 1, final product is 1.
    // If there's a toy with value -1 and all others are 1, final product is -1.
    // The problem statement implies values are not necessarily 1 or -1.
    // We need to consider if it's *possible* to achieve a value in the target box.

    // Box 1: (-inf, -1] (negative, |val| >= 1)
    // Box 2: (-1, 0) (negative, |val| < 1)
    // Box 3: (0, 1) (positive, |val| < 1)
    // Box 4: [1, inf) (positive, |val| >= 1)

    // Check for Box 1: final product is negative and |val| >= 1
    if (target_box == 1) {
        if (!final_product_is_negative) return false; // Must be negative

        // To get |val| >= 1:
        // We need at least one toy with |val| >= 1 (from Box 1 or Box 4)
        // AND we must be able to make sure the product doesn't shrink below 1.
        // This is possible if we have at least one toy from Box 1 or Box 4.
        // If all toys are from Box 2 or Box 3, then the product will always be < 1 in magnitude.
        if (A + D == 0) return false; // No toys with |val| >= 1 initially

        // If we have A+D > 0, we can always pick values such that the final product has magnitude >= 1.
        // For example, pick a value like -2 from Box 1 or 2 from Box 4.
        // Then pick values like 0.5 from Box 3 or -0.5 from Box 2.
        // We can always arrange multiplications to keep magnitude >= 1 if A+D > 0.
        // E.g., if we have a toy with value 2 and many toys with value 0.5.
        // We can multiply 2 * 0.5 = 1. Then 1 * 0.5 = 0.5.
        // But we can also multiply 0.5 * 0.5 = 0.25. Then 2 * 0.25 = 0.5.
        // The crucial part is that we can choose the order of multiplication.
        // If we have at least one toy with |val| >= 1 (A+D > 0), we can always ensure the final product's magnitude is >= 1.
        // Example: if we have 2, 0.5, 0.5.
        // (0.5 * 0.5) * 2 = 0.25 * 2 = 0.5 (magnitude < 1)
        // (2 * 0.5) * 0.5 = 1 * 0.5 = 0.5 (magnitude < 1)
        // This logic is flawed. If we have A+D > 0, it doesn't guarantee |val| >= 1.
        // Example: A=0, B=0, C=1 (0.5), D=1 (2). Product is 1.
        // Example: A=0, B=0, C=2 (0.5, 0.5), D=1 (4). Product is 1.
        // Example: A=0, B=0, C=3 (0.5, 0.5, 0.5), D=1 (4). Product is 0.5.
        // The only way to guarantee |val| >= 1 is if we have at least one toy from Box 1 or Box 4,
        // AND we don't have too many toys from Box 2 or Box 3 that would shrink the product.
        // If B+C >= A+D, it's possible to make the magnitude < 1.
        // If A+D > B+C, it's possible to make the magnitude >= 1.
        // This is because each multiplication by a toy from B or C (magnitude < 1) can reduce the magnitude.
        // Each multiplication by a toy from A or D (magnitude >= 1) can increase or maintain the magnitude.
        // If we have more "shrinking" toys than "expanding/maintaining" toys, we can make the final product < 1.
        // If we have more "expanding/maintaining" toys, we can make the final product >= 1.
        // The number of "shrinking" toys is B+C. The number of "expanding/maintaining" toys is A+D.
        // If A+D > 0, we can always pick values such that the final product has magnitude >= 1.
        // For example, if we have a toy with value 2. And many toys with value 0.5.
        // We can pick 2, 0.5, 0.5.
        // If we want magnitude >= 1: (2 * 0.5) * 0.5 = 1 * 0.5 = 0.5. This is not >= 1.
        // The example in the problem description for case 1: A=1, B=2, C=0, D=1.
        // Initial: {-3}, {-0.5, -0.5}, {}, {3}
        // Sequence: (-0.5 * -0.5) = 0.25 (Box 3)
        //           (-3 * 0.25) = -0.75 (Box 2)
        //           (-0.75 * 3) = -2.25 (Box 1) -> Yes
        // This shows that even with B=2, D=1, A=1, it's possible to end up in Box 1.
        // The condition for magnitude >= 1 is simply that A+D > 0.
        // If A+D == 0, all initial toys have magnitude < 1, so the final product will have magnitude < 1.
        return (A + D > 0);
    }

    // Check for Box 2: final product is negative and |val| < 1
    if (target_box == 2) {
        if (!final_product_is_negative) return false; // Must be negative

        // To get |val| < 1:
        // This is always possible if there is at least one toy from Box 2 or Box 3 (B+C > 0).
        // If B+C == 0, then all toys are from Box 1 or Box 4.
        // In this case, all magnitudes are >= 1. The product will have magnitude >= 1.
        // So if B+C == 0, it's impossible to get |val| < 1.
        if (B + C == 0) return false;

        // If B+C > 0, we can always pick values such that the final product has magnitude < 1.
        // For example, pick a value like 0.1 from Box 3.
        // Multiply all other toys by 1 (if possible) or by values that don't change magnitude much.
        // Then multiply by 0.1. The final product will be small.
        // More generally, if B+C > 0, we can always choose values such that the final product's magnitude is < 1.
        // E.g., if we have 2, 0.5, 0.5.
        // (2 * 0.5) * 0.5 = 1 * 0.5 = 0.5 (magnitude < 1)
        // (0.5 * 0.5) * 2 = 0.25 * 2 = 0.5 (magnitude < 1)
        // This is always possible if B+C > 0.
        return true;
    }

    // Check for Box 3: final product is positive and |val| < 1
    if (target_box == 3) {
        if (final_product_is_negative) return false; // Must be positive

        // To get |val| < 1:
        // Similar to Box 2, this requires B+C > 0.
        // If B+C == 0, all toys have magnitude >= 1, so product will have magnitude >= 1.
        if (B + C == 0) return false;
        return true;
    }

    // Check for Box 4: final product is positive and |val| >= 1
    if (target_box == 4) {
        if (final_product_is_negative) return false; // Must be positive

        // To get |val| >= 1:
        // Similar to Box 1, this requires A+D > 0.
        // If A+D == 0, all toys have magnitude < 1, so product will have magnitude < 1.
        if (A + D == 0) return false;
        return true;
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (check(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (check(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (check(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (check(A, B, C, D, 4) ? "Ya" : "Tidak");
        std::cout << "\n";
    }
    return 0;
}

