#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take N/2
                // Option 2: Take 1

                // If N is a power of 2, taking N/2 might be bad if it leaves a small N for opponent.
                // Example: N=4.
                // Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // Chanek takes N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Chanek prefers 3. So take N/2.

                // Example: N=6.
                // Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 1+2+1=4. Opponent: 1+1=2.
                // Chanek takes N/2=3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
                // Both give 4.

                // The strategy is: if N is even, and N is not 2, take N/2.
                // If N is 2, taking 1 is better for Chanek (1 coin, leaves 1 for opponent, Chanek gets 1).
                // If N is 2, taking N/2=1 is also 1 coin.
                // So if N=2, it doesn't matter.
                // The only case where taking 1 is better than N/2 is when N/2 leaves the opponent with a very good move.
                // This happens when N/2 is 1 (i.e., N=2).
                // For N > 2 and even:
                // If Chanek takes N/2, N becomes N/2.
                // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1, N becomes N-2 (even).
                // The opponent will try to maximize their coins.
                // If N is a power of 2 (e.g., 4, 8, 16, ...), taking N/2 is always optimal for the current player.
                // If N is even but not a power of 2 (e.g., 6, 10, 12, ...), taking N/2 is also optimal.
                // The only exception is N=2.

                // Let's check if N is a power of 2.
                // A number is a power of 2 if (n & (n - 1)) == 0.
                if ((n & (n - 1)) == 0 && n != 2) { // N is a power of 2 and N > 2
                    // In this case, taking N/2 is optimal.
                    // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // This seems to prolong the game and give opponent more chances.
                    // Taking N/2 is generally better for the current player if N is a power of 2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else if (n == 2) {
                    chanek_coins += 1;
                    n -= 1;
                }
                else { // N is even, not a power of 2, and N > 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0 && n != 2) { // N is a power of 2 and N > 2
                    n /= 2;
                } else if (n == 2) {
                    n -= 1;
                }
                else { // N is even, not a power of 2, and N > 2
                    n /= 2;
                }
            }
        }
        turn = 1 - turn; // Switch turn
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

