#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append two elements: X and S + X
        // Let S_new = current_sum + X + (S + X) = current_sum + 2X + S
        // Let X_new = current_xor_sum ^ X ^ (S + X) = current_xor_sum ^ S
        // We want S_new = 2 * X_new
        // current_sum + 2*current_xor_sum = 2 * (current_xor_sum ^ current_sum)
        // This is not correct. The logic is:
        // We want to append two numbers, say P and Q.
        // New sum: current_sum + P + Q
        // New XOR sum: current_xor_sum ^ P ^ Q
        // We want: current_sum + P + Q = 2 * (current_xor_sum ^ P ^ Q)
        //
        // A known trick for this type of problem is to append X and S+X.
        // Let P = current_xor_sum.
        // Let Q = current_sum + current_xor_sum.
        //
        // New sum: S' = current_sum + P + Q
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * current_sum + 2 * current_xor_sum
        //
        // New XOR sum: X' = current_xor_sum ^ P ^ Q
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum
        //
        // Check condition: S' = 2 * X'
        // 2 * current_sum + 2 * current_xor_sum = 2 * (current_sum + current_xor_sum)
        // This is always true.
        //
        // So, we can append current_xor_sum and (current_sum + current_xor_sum).
        // These are two elements.

        long long p = current_xor_sum;
        long long q = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << p << " " << q << std::endl;
    }
}

