// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The problem states "i-th from the right digit", so we build from right to left
    // and then pad. The string is built in reverse order of digits.
    // Example: 241 -> '1' (odd), '4' (even), '2' (even) -> "100"
    // If we want to compare from left to right, we need to reverse this.
    // But the problem says "i-th from the right digit", so the string "100"
    // represents 241's parity pattern from right to left.
    // The pattern 's' is also given from left to right, but it's compared
    // "i-th from the right digit of the pattern".
    // This means we should normalize both to a fixed length and then compare.
    // Let's make the pattern string always 18 characters long.
    // The digits are processed from right to left.
    // So, for 241, it's 1 (odd), 4 (even), 2 (even).
    // The string should be "000000000000000100" (18 chars)
    // The current `pattern_str` is "100" (reversed digits).
    // We need to pad it to 18 characters with '0's at the end (which correspond to leading zeros of the number).
    // So, if `pattern_str` is "100", we need "100000000000000000".
    // This is equivalent to reversing `pattern_str` and then padding with '0's at the beginning.
    // Or, more simply, just pad `pattern_str` with '0's at the end until it's 18 chars.
    // The comparison logic will then need to handle this.

    // Let's re-evaluate the pattern generation.
    // "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // This means we should generate a string where index 0 is the rightmost digit's parity, index 1 is the second rightmost, etc.
    // Example: 92 -> '0' (for 2), '1' (for 9) -> "01"
    // Example: 2212 -> '0' (for 2), '1' (for 1), '0' (for 2), '0' (for 2) -> "0100"
    // Example: 50 -> '0' (for 0), '1' (for 5) -> "01"
    // Example: 414 -> '0' (for 4), '1' (for 1), '0' (for 4) -> "010"
    // All these examples match "010".
    // So, the generated string should be padded with '0's at the end to a fixed length (e.g., 18).
    // "01" becomes "010000000000000000"
    // "0100" becomes "010000000000000000"
    // "010" becomes "010000000000000000"

    // The current `pattern_str` is built correctly for this interpretation.
    // For 92: n=92 -> '0', pattern_str="0"; n=9 -> '1', pattern_str="01"; n=0.
    // For 2212: n=2212 -> '0', pattern_str="0"; n=221 -> '1', pattern_str="01"; n=22 -> '0', pattern_str="010"; n=2 -> '0', pattern_str="0100"; n=0.
    // This is exactly what we need.

    // Now, pad this string with '0's at the end to a fixed length (e.g., 18).
    // The maximum number of digits for 10^18-1 is 18.
    // So, a length of 18 is sufficient.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's at the end to match the fixed length
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

