        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::map<char, bool> in_password;

    for (char c : s) {
        in_password[c] = true;
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    for (auto const& [key, val] : adj) {
        if (val.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;

    for (char c_val = 'a'; c_val <= 'z'; ++c_val) {
        if (in_password[c_val] && adj[c_val].size() <= 1 && visited.find(c_val) == visited.end()) {
            // This character is either an endpoint of a path or an isolated character in the password.
            // Start building the path from here.
            char current = c_val;
            char prev = 0; // Sentinel for the previous character

            while (current != 0 && visited.find(current) == visited.end()) {
                layout += current;
                visited.insert(current);

                char next_char = 0;
                for (char neighbor : adj[current]) {
                    if (neighbor != prev) {
                        next_char = neighbor;
                        break;
                    }
                }
                prev = current;
                current = next_char;
            }
        }
    }

    // Check if all characters from the password have been included in the layout.
    // This implicitly checks if there are any cycles or internal nodes with degree > 2.
    for (char c : s) {
        if (visited.find(c) == visited.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in the password
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part
    long long sum_r_part;
    if (b == 1) { // If b=1, then r must be 0, but r!=0 is required. So no nice integers.
        sum_r_part = 0;
    } else {
        sum_r_part = (b - 1);
        sum_r_part = (sum_r_part * b) / 2;
        sum_r_part %= MOD; // sum_r_part can be large, but it's not multiplied by MOD yet.
                           // The division by 2 is exact.
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_k_part
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_part;
    long long sum_k_val = (a * (a + 1)) / 2; // sum_{k=1 to a} k
    sum_k_val %= MOD;

    sum_k_part = (b % MOD * sum_k_val) % MOD; // b * sum_{k=1 to a} k
    sum_k_part = (sum_k_part + a) % MOD;      // + a

    // Total sum = (sum_r_part * sum_k_part) % MOD
    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

