        }
        // Case 3: f_b(x_b) = x_b (identity)
        // This means f0=0, f1=1.
        // To achieve this, we need to ensure the bit is not changed by AND/OR/XOR.
        //   `& 1` keeps it `x_b`. So `final_and_const` should have 1 at bit `b`. (default)
        //   `| 0` keeps it `x_b`. So `final_or_const` should have 0 at bit `b`. (default)
        //   `^ 0` keeps it `x_b`. So `final_xor_const` should have 0 at bit `b`. (default)
        // No change needed for `final_and_const`, `final_or_const`, `final_xor_const` for this bit.
        else if (f0 == 0 && f1 == 1) {
            // Do nothing, defaults work: &1 |0 ^0
        }
        // Case 4: f_b(x_b) = 1 - x_b (negation / XOR 1)
        // This means f0=1, f1=0.
        // To achieve this, we need to flip the bit.
        //   `^ 1` flips it. So `final_xor_const` should have 1 at bit `b`.
        else if (f0 == 1 && f1 == 0) {
            final_xor_const |= (1 << b); // Set b-th bit of XOR constant to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters.
    // A common canonical form is AND then OR then XOR.
    // Let's verify if this order works with our derived constants.
    // Initial value `x`.
    // `x_after_and = x & final_and_const`
    // `x_after_or = x_after_and | final_or_const`
    // `x_after_xor = x_after_or ^ final_xor_const`

    // If `final_and_const` is not all 1s (1023), we need an AND operation.
    if (final_and_const != 1023) {
        result_ops.push_back({'&', final_and_const});
    }
    // If `final_or_const` is not all 0s (0), we need an OR operation.
    if (final_or_const != 0) {
        result_ops.push_back({'|', final_or_const});
    }
    // If `final_xor_const` is not all 0s (0), we need an XOR operation.
    if (final_xor_const != 0) {
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain balance.
    // key: balance, value: number of jars removed
    std::map<int, int> left_balance_to_removed_count;
    left_balance_to_removed_count[0] = 0; // 0 jars removed, balance 0

    int current_balance_left = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n - 1 - i] == 1) { // Jars from n down to 1
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        // Store the minimum number of jars removed (i+1) to get current_balance_left
        // If a balance is seen multiple times, we want the one with fewer jars removed.
        // Since we iterate from 1 jar removed upwards, the first time we see a balance
        // will correspond to the minimum jars removed.
        if (left_balance_to_removed_count.find(current_balance_left) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[current_balance_left] = i + 1;
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible jars removed

    // Case 1: No jars removed from the right side
    // We need the remaining jars to have a balance of 0.
    // This means the jars removed from the left must have a balance equal to initial_balance.
    // So, we look for initial_balance in left_balance_to_removed_count.
    if (left_balance_to_removed_count.count(initial_balance)) {
        min_total_removed = std::min(min_total_removed, left_balance_to_removed_count[initial_balance]);
    }

    // Iterate through removing jars from the right side
    int current_balance_right = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n + i] == 1) { // Jars from n+1 up to 2n
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        // If we remove (i+1) jars from the right, their balance is current_balance_right.
        // The remaining jars (after removing from right) have a balance of initial_balance - current_balance_right.
        // We need to remove some jars from the left such that their balance is initial_balance - current_balance_right.
        // This means the remaining jars (after removing from left and right) have a balance of 0.
        int target_balance_from_left = initial_balance - current_balance_right;

        if (left_balance_to_removed_count.count(target_balance_from_left)) {
            int removed_from_left = left_balance_to_removed_count[target_balance_from_left];
            min_total_removed = std::min(min_total_removed, removed_from_left + (i + 1));
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

