#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: minimum steps for a[i] to become 0 if it's 1,
    // or 0 if it's already 0, considering only left propagation.
    // L[i] = 0 if a[i] == 0
    // L[i] = 1 + L[i-1] if a[i] == 1 and a[i-1] == 0
    // L[i] = 0 if a[i] == 1 and a[i-1] == 1 (this 1 is stable from left)
    // This is not quite right. L[i] should be the distance to the nearest 0 on the left.
    // Or, more precisely, the length of the block of 1s ending at i.
    // Let's redefine L[i] as the length of the block of 1s ending at i.
    // L[i] = 0 if a[i] == 0
    // L[i] = L[i-1] + 1 if a[i] == 1 (and i > 0)
    // L[0] = a[0]

    // Calculate L[i]: length of consecutive 1s ending at i.
    // If a[i] is 0, L[i] is 0.
    L[0] = a[0];
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 1s starting at i.
    // If a[i] is 0, R[i] is 0.
    R[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int dist_to_left_zero = (L[i] == i + 1) ? n + 1 : L[i]; // If all 1s to left, effectively infinite
            int dist_to_right_zero = (R[i] == n - i) ? n + 1 : R[i]; // If all 1s to right, effectively infinite

            int steps_to_become_zero = std::min(dist_to_left_zero, dist_to_right_zero);

            if (steps_to_become_zero == n + 1) { // This means the entire sequence is 1s.
                                                 // In this case, it's stable and all 1s.
                                                 // No change needed, max_steps remains 0.
                                                 // This case is handled by initial check for max_steps.
                // If all 1s, it's stable.
                // If it's 11111, L[i] = i+1, R[i] = n-i.
                // For i=0, L[0]=1, R[0]=n. min(1,n).
                // For i=n-1, L[n-1]=n, R[n-1]=1. min(n,1).
                // For i in between, min(i+1, n-i).
                // The value steps_to_become_zero will be at least 1.
                // If the sequence is all 1s, it's stable, so max_steps should be 0.
                // The logic below for final_a[i] handles this: if steps_to_become_zero is large,
                // it means it's far from a 0, so it will remain 1.
            } else {
                max_steps = std::max(max_steps, (steps_to_become_zero + 1) / 2);
            }
        }
    }

    // Determine the final stable sequence
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int dist_to_left_zero = (L[i] == i + 1) ? n + 1 : L[i];
            int dist_to_right_zero = (R[i] == n - i) ? n + 1 : R[i];

            int steps_to_become_zero = std::min(dist_to_left_zero, dist_to_right_zero);

            if (steps_to_become_zero <= max_steps) {
                final_a[i] = 0;
            } else {
                final_a[i] = 1;
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

