#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = LLONG_MAX;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all in S1).
    // S2 is empty. No pairs (a_i, a_j) with a_i in S1, a_j in S2.
    // All pairs are (a_i, a_j) in S1.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (long long)a[n - 1].value + a[n - 2].value - ((long long)a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    } else { // n=1, no pairs, goodness is 0. But problem states n >= 2.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }


    // Case 2: At least one element in S1 and at least one element in S2.
    // This means there will always be pairs (a_i, a_j) with a_i in S1, a_j in S2.
    // The values for these pairs will be a_i + a_j + h.
    // The minimum such value is a[0].value + a[1].value + h (if a[0] in S1, a[1] in S2 or vice versa).
    // The maximum such value is a[n-1].value + a[n-2].value + h.
    //
    // Consider the partition where a[0] is in S1 and all other elements are in S2.
    // min_f:
    //   - If a[0] is in S1, a[1] is in S2: a[0].value + a[1].value + h
    //   - If a[1] and a[2] are in S2: a[1].value + a[2].value
    //   So, min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f:
    //   - If a[0] is in S1, a[n-1] is in S2: a[0].value + a[n-1].value + h
    //   - If a[n-1] and a[n-2] are in S2: a[n-1].value + a[n-2].value
    //   So, max_f = max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value)
    //
    // This specific partition (a[0] in S1, others in S2) is optimal for many cases.
    // Let's analyze the values:
    // min_f_same = a[1].value + a[2].value (from S2)
    // max_f_same = a[n-1].value + a[n-2].value (from S2)
    // min_f_diff = a[0].value + a[1].value + h
    // max_f_diff = a[0].value + a[n-1].value + h
    //
    // Overall min_f = min(min_f_same, min_f_diff)
    // Overall max_f = max(max_f_same, max_f_diff)
    //
    // Goodness = max(max_f_same, max_f_diff) - min(min_f_same, min_f_diff)
    //
    // Let's calculate this for the partition: a[0] in S1, a[1...n-1] in S2.
    // This partition is valid only if n >= 2.
    if (n >= 2) {
        long long current_min_f_same = LLONG_MAX;
        if (n - 1 >= 2) { // S2 has at least 2 elements
            current_min_f_same = (long long)a[1].value + a[2].value;
        }

        long long current_max_f_same = LLONG_MIN;
        if (n - 1 >= 2) { // S2 has at least 2 elements
            current_max_f_same = (long long)a[n - 1].value + a[n - 2].value;
        }

        long long current_min_f_diff = (long long)a[0].value + a[1].value + h;
        long long current_max_f_diff = (long long)a[0].value + a[n - 1].value + h;

        long long overall_min_f = LLONG_MAX;
        if (current_min_f_same != LLONG_MAX) {
            overall_min_f = std::min(overall_min_f, current_min_f_same);
        }
        overall_min_f = std::min(overall_min_f, current_min_f_diff);

        long long overall_max_f = LLONG_MIN;
        if (current_max_f_same != LLONG_MIN) {
            overall_max_f = std::max(overall_max_f, current_max_f_same);
        }
        overall_max_f = std::max(overall_max_f, current_max_f_diff);

        long long current_goodness = overall_max_f - overall_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Consider the partition where a[0] and a[1] are in S1, and others in S2.
    // This is only relevant if h is very small, such that a[0]+a[1]+h is not the minimum.
    // If h is large, a[0]+a[1]+h will likely be the minimum, and we want to avoid it.
    // The previous case (a[0] in S1, others in S2) already covers the scenario where
    // we want to minimize the number of 'diff' pairs.
    //
    // The key insight is that the minimum possible value of f is either:
    // 1. a[0] + a[1] (if a[0], a[1] are in the same group)
    // 2. a[0] + a[1] + h (if a[0], a[1] are in different groups)
    //
    // The maximum possible value of f is either:
    // 1. a[n-1] + a[n-2] (if a[n-1], a[n-2] are in the same group)
    // 2. a[n-1] + a[n-2] + h (if a[n-1], a[n-2] are in different groups)
    // 3. a[0] + a[n-1] + h (if a[0] in one group, a[n-1] in other)
    //
    // Let's consider the two main strategies:
    // Strategy A: Put all elements into one group (e.g., all 1s).
    //   min_f = a[0].value + a[1].value
    //   max_f = a[n-1].value + a[n-2].value
    //   Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    //   This is already covered by the first block.
    //
    // Strategy B: Put a[0] into group 1, and all other elements into group 2.
    //   min_f_same = a[1].value + a[2].value (if n-1 >= 2)
    //   max_f_same = a[n-1].value + a[n-2].value (if n-1 >= 2)
    //   min_f_diff = a[0].value + a[1].value + h
    //   max_f_diff = a[0].value + a[n-1].value + h
    //   Overall min_f = min(min_f_same, min_f_diff) (if min_f_same exists)
    //   Overall max_f = max(max_f_same, max_f_diff) (if max_f_same exists)
    //   This is already covered by the second block.
    //
    // What if n=2?
    // a = {a0, a1}
    // Case 1: {1, 1}
    //   min_f = a0+a1, max_f = a0+a1. Goodness = 0.
    // Case 2: {1, 2}
    //   min_f = a0+a1+h, max_f = a0+a1+h. Goodness = 0.
    // So for n=2, goodness is always 0.
    // My code:
    // First block (all 1s): min_goodness = (a[1].value + a[0].value) - (a[0].value + a[1].value) = 0.
    // Second block (a[0] in S1, a[1] in S2):
    //   current_min_f_same = LLONG_MAX (S2 has only 1 element)
    //   current_max_f_same = LLONG_MIN (S2 has only 1 element)
    //   current_min_f_diff = a[0].value + a[1].value + h
    //   current_max_f_diff = a[0].value + a[1].value + h
    //   overall_min_f = a[0].value + a[1].value + h
    //   overall_max_f = a[0].value + a[1].value + h
    //   current_goodness = 0.
    // Both cases correctly yield 0 for n=2.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

