        // All `r` from `l` to `r_idx - 1` are bad pairs.
        // The number of such `r` values is `r_idx - l`.
        bad_pairs += (r_idx - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

